export enum AppMode {
  TRANSLATOR = 'translator',
  DOCUMENT_CHAT = 'document',
  BATCH = 'batch'
}

export enum TranslationMode {
  TRANSLATE = 'TRANSLATE',
  TRANSLITERATE = 'TRANSLITERATE'
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  content: string;
  timestamp: number;
}

export interface UploadedFile {
  name: string;
  content: string; // Text content extracted
  type: string;
  size: number;
}

export const SUPPORTED_LANGUAGES = [
  { code: 'auto', name: 'Auto-detect' },
  { code: 'en', name: 'English' },
  { code: 'es', name: 'Spanish' },
  { code: 'fr', name: 'French' },
  { code: 'de', name: 'German' },
  { code: 'hi', name: 'Hindi' },
  { code: 'bn', name: 'Bengali' },
  { code: 'ta', name: 'Tamil' },
  { code: 'ja', name: 'Japanese' },
  { code: 'ko', name: 'Korean' },
  { code: 'zh', name: 'Chinese' },
  { code: 'ru', name: 'Russian' },
  { code: 'ar', name: 'Arabic' },
];

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { TranslationMode } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = 'gemini-2.5-flash-preview-09-2025';

export const translateText = async (
  text: string, 
  sourceLang: string, 
  targetLang: string, 
  mode: TranslationMode
): Promise<string> => {
  if (!text.trim()) return "";

  let prompt = "";

  if (mode === TranslationMode.TRANSLITERATE) {
    prompt = `You are a strict transliteration engine. Convert the following text phonetically from ${sourceLang === 'auto' ? 'detected language' : sourceLang} script to ${targetLang} script. 
    DO NOT translate the meaning. Only convert the sounds/script.
    Input: "${text}"`;
  } else {
    prompt = `You are a high-fidelity neural translation engine. Translate the following text from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}.
    Maintain tone, context, and nuance.
    Input: "${text}"`;
  }

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        temperature: 0.3, // Lower temperature for more accurate translation
      }
    });
    return response.text || "Translation failed.";
  } catch (error) {
    console.error("Gemini Translation Error:", error);
    return "Error: Could not process text. Please check API Key.";
  }
};

export const chatWithDocument = async (
  query: string,
  documentContext: string,
  chatHistory: { role: string; parts: { text: string }[] }[]
): Promise<string> => {

  const systemInstruction = `You are NeuroLingua's "Truth Guard". 
  You have been provided with a specific document context. 

  RULES:
  1. Priority: Answer strictly based on the provided "CONTEXT" below.
  2. If the answer is found in the context, cite it implicitly.
  3. If the answer is NOT in the context, state that clearly, then provide a general knowledge answer but label it as "General Knowledge (Not in Document)".
  4. Be concise and professional.

  CONTEXT:
  ${documentContext.substring(0, 30000)} 
  (Context truncated if too long)`;

  try {
    const chat = ai.chats.create({
      model: MODEL_NAME,
      config: {
        systemInstruction: systemInstruction,
      },
      history: chatHistory
    });

    const response = await chat.sendMessage({ message: query });
    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Error: Unable to connect to Truth Guard intelligence.";
  }
};

export const analyzeDocument = async (documentContent: string, task: 'summary' | 'questions' | 'keywords'): Promise<string> => {
    let prompt = "";
    switch(task) {
        case 'summary':
            prompt = "Provide a concise executive summary of the following document.";
            break;
        case 'questions':
            prompt = "Generate 5 critical questions that this document answers.";
            break;
        case 'keywords':
            prompt = "Extract the top 10 most significant keywords or entities from this document.";
            break;
    }

    try {
        const response = await ai.models.generateContent({
            model: MODEL_NAME,
            contents: `${prompt}\n\nDocument:\n${documentContent.substring(0, 30000)}`
        });
        return response.text || "Analysis failed.";
    } catch (error) {
        return "Error analyzing document.";
    }
}

import React, { useState, useEffect } from 'react';
import { TranslationMode, SUPPORTED_LANGUAGES } from '../types';
import { translateText } from '../services/geminiService';

const Translator: React.FC = () => {
  const [sourceText, setSourceText] = useState('');
  const [targetText, setTargetText] = useState('');
  const [sourceLang, setSourceLang] = useState('auto');
  const [targetLang, setTargetLang] = useState('es');
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TRANSLATE);
  const [isLoading, setIsLoading] = useState(false);

  // Debounce translation trigger
  useEffect(() => {
    const timer = setTimeout(() => {
      if (sourceText.length > 2) {
        handleProcess();
      }
    }, 1000);

    return () => clearTimeout(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [sourceText, sourceLang, targetLang, mode]);

  const handleProcess = async () => {
    if (!sourceText.trim()) return;
    setIsLoading(true);
    const result = await translateText(sourceText, sourceLang, targetLang, mode);
    setTargetText(result);
    setIsLoading(false);
  };

  const handleSwap = () => {
    if (sourceLang === 'auto') return; // Can't swap auto
    const oldSource = sourceLang;
    setSourceLang(targetLang);
    setTargetLang(oldSource);
    setSourceText(targetText);
    setTargetText(sourceText);
  };

  return (
    <div className="space-y-6">
      {/* Control Panel */}
      <div className="bg-gray-50 p-6 rounded-xl border border-gray-200 grid grid-cols-1 md:grid-cols-3 gap-6 shadow-sm">
        <div className="flex flex-col gap-2">
          <label className="text-sm font-semibold text-gray-600">Source Language</label>
          <select 
            value={sourceLang}
            onChange={(e) => setSourceLang(e.target.value)}
            className="p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
          >
            {SUPPORTED_LANGUAGES.map(l => (
              <option key={`src-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>

        <div className="flex flex-col gap-2 justify-center items-center">
            <button 
                onClick={handleSwap}
                className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                title="Swap Languages"
            >
                <i className="fas fa-exchange-alt"></i>
            </button>
        </div>

        <div className="flex flex-col gap-2">
          <label className="text-sm font-semibold text-gray-600">Target Language</label>
          <select 
            value={targetLang}
            onChange={(e) => setTargetLang(e.target.value)}
            className="p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
          >
            {SUPPORTED_LANGUAGES.filter(l => l.code !== 'auto').map(l => (
              <option key={`tgt-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Mode Toggle */}
      <div className="flex justify-center">
        <div className="bg-gray-200 p-1 rounded-full flex gap-1 relative">
             <button
                onClick={() => setMode(TranslationMode.TRANSLATE)}
                className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${mode === TranslationMode.TRANSLATE ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600 hover:text-gray-800'}`}
             >
                <i className="fas fa-language mr-2"></i> Translate
             </button>
             <button
                onClick={() => setMode(TranslationMode.TRANSLITERATE)}
                className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${mode === TranslationMode.TRANSLITERATE ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600 hover:text-gray-800'}`}
             >
                <i className="fas fa-font mr-2"></i> Transliterate
             </button>
        </div>
      </div>

      {/* Text Areas */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="relative">
            <div className="flex justify-between mb-2">
                <span className="text-sm font-semibold text-gray-600">Source</span>
                <span className="text-xs text-gray-400">{sourceText.length} chars</span>
            </div>
            <textarea
                value={sourceText}
                onChange={(e) => setSourceText(e.target.value)}
                placeholder="Type to process..."
                className="w-full h-80 p-5 rounded-2xl border border-gray-300 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none resize-none shadow-inner transition-all text-lg"
            ></textarea>
        </div>

        <div className="relative">
            <div className="flex justify-between mb-2">
                <span className="text-sm font-semibold text-gray-600 flex items-center gap-2">
                    Result 
                    {isLoading && <i className="fas fa-spinner fa-spin text-indigo-500"></i>}
                </span>
                <div className="flex gap-2">
                     <button 
                        onClick={() => navigator.clipboard.writeText(targetText)}
                        className="text-xs text-indigo-600 hover:text-indigo-800 font-medium"
                     >
                        <i className="fas fa-copy mr-1"></i> Copy
                     </button>
                </div>
            </div>
            <textarea
                readOnly
                value={targetText}
                placeholder={isLoading ? "Processing..." : "Result will appear here..."}
                className="w-full h-80 p-5 rounded-2xl border border-gray-300 bg-gray-50 text-gray-700 resize-none shadow-sm focus:outline-none text-lg"
            ></textarea>
        </div>
      </div>

      {/* Footer Info */}
      <div className="text-center text-xs text-gray-400">
         Powered by Gemini Neural Engine • Tier 1 Cloud Inference
      </div>
    </div>
  );
};

export default Translator;

import React, { useState, useRef, useEffect } from 'react';
import { UploadedFile, ChatMessage } from '../types';
import { chatWithDocument, analyzeDocument } from '../services/geminiService';

const DocumentChat: React.FC = () => {
  const [file, setFile] = useState<UploadedFile | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const uploadedFile = event.target.files?.[0];
    if (uploadedFile) {
        setIsProcessing(true);
        // Simple text extraction for demo (In prod, use pdf.js for PDFs)
        const reader = new FileReader();
        reader.onload = async (e) => {
            const text = e.target?.result as string;
            setFile({
                name: uploadedFile.name,
                type: uploadedFile.type,
                size: uploadedFile.size,
                content: text
            });
            // Initial greeting
            setMessages([{
                id: 'init',
                role: 'model',
                content: `I've ingested "${uploadedFile.name}". Truth Guard™ is active. You can now ask questions specifically about this document.`,
                timestamp: Date.now()
            }]);
            setIsProcessing(false);
        };
        reader.readAsText(uploadedFile);
    }
  };

  const handleSendMessage = async () => {
    if (!inputValue.trim() || !file) return;

    const userMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'user',
        content: inputValue,
        timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsProcessing(true);

    // Format history for Gemini
    const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.content }]
    }));

    const responseText = await chatWithDocument(inputValue, file.content, history);

    const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        content: responseText,
        timestamp: Date.now()
    };

    setMessages(prev => [...prev, botMsg]);
    setIsProcessing(false);
  };

  const runQuickAction = async (action: 'summary' | 'questions' | 'keywords') => {
      if (!file) return;
      setIsProcessing(true);
      const res = await analyzeDocument(file.content, action);

      const botMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'model',
        content: `**${action.toUpperCase()}**: \n${res}`,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, botMsg]);
      setIsProcessing(false);
  };

  if (!file) {
      return (
          <div className="flex flex-col items-center justify-center h-[500px] border-2 border-dashed border-indigo-300 rounded-3xl bg-indigo-50/50 hover:bg-indigo-50 transition-all">
              <div className="bg-white p-6 rounded-full shadow-lg mb-4">
                  <i className="fas fa-file-upload text-4xl text-indigo-600"></i>
              </div>
              <h3 className="text-xl font-bold text-gray-700 mb-2">Activate Truth Guard™</h3>
              <p className="text-gray-500 mb-6 text-center max-w-md">Upload a document (TXT for this demo) to ground the AI in your specific data. Prevents hallucinations by strictly adhering to source material.</p>
              <label className="cursor-pointer bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 shadow-lg hover:shadow-xl transition-all">
                  Upload Document
                  <input type="file" className="hidden" accept=".txt,.md,.json,.csv" onChange={handleFileUpload} />
              </label>
              <p className="mt-4 text-xs text-gray-400">Supported: TXT, MD, CSV (PDF support in Pro version)</p>
          </div>
      );
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 h-[600px]">
        {/* Sidebar Actions */}
        <div className="lg:col-span-1 space-y-4">
            <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
                <div className="flex items-center gap-3 mb-2">
                    <div className="bg-green-100 text-green-600 p-2 rounded-lg">
                        <i className="fas fa-file-alt"></i>
                    </div>
                    <div className="overflow-hidden">
                        <h4 className="font-bold text-sm truncate">{file.name}</h4>
                        <p className="text-xs text-gray-400">{(file.size / 1024).toFixed(1)} KB</p>
                    </div>
                </div>
                <button 
                    onClick={() => setFile(null)}
                    className="text-xs text-red-500 hover:text-red-700 w-full text-left mt-2"
                >
                    <i className="fas fa-trash mr-1"></i> Remove File
                </button>
            </div>

            <div className="bg-indigo-900 text-white p-4 rounded-xl shadow-lg">
                <h4 className="font-bold text-sm mb-3 opacity-80 uppercase tracking-wider">Quick Actions</h4>
                <div className="space-y-2">
                    <button onClick={() => runQuickAction('summary')} className="w-full text-left px-3 py-2 bg-white/10 hover:bg-white/20 rounded-lg text-sm transition-colors">
                        <i className="fas fa-list-ul mr-2"></i> Summarize
                    </button>
                    <button onClick={() => runQuickAction('questions')} className="w-full text-left px-3 py-2 bg-white/10 hover:bg-white/20 rounded-lg text-sm transition-colors">
                        <i className="fas fa-question-circle mr-2"></i> Gen. Questions
                    </button>
                    <button onClick={() => runQuickAction('keywords')} className="w-full text-left px-3 py-2 bg-white/10 hover:bg-white/20 rounded-lg text-sm transition-colors">
                        <i className="fas fa-key mr-2"></i> Extract Keywords
                    </button>
                </div>
            </div>
        </div>

        {/* Chat Area */}
        <div className="lg:col-span-3 bg-white rounded-2xl border border-gray-200 shadow-sm flex flex-col overflow-hidden">
            <div className="flex-1 overflow-y-auto p-6 space-y-4 bg-gray-50/50">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[80%] rounded-2xl p-4 shadow-sm ${
                            msg.role === 'user' 
                                ? 'bg-indigo-600 text-white rounded-tr-none' 
                                : 'bg-white border border-gray-200 text-gray-800 rounded-tl-none'
                        }`}>
                            {msg.role === 'model' && (
                                <div className="mb-1 text-xs font-bold text-indigo-500 uppercase flex items-center gap-1">
                                    <i className="fas fa-shield-alt"></i> Truth Guard
                                </div>
                            )}
                            <div className="whitespace-pre-wrap text-sm leading-relaxed">{msg.content}</div>
                        </div>
                    </div>
                ))}
                <div ref={chatEndRef} />
            </div>

            <div className="p-4 bg-white border-t border-gray-100">
                <div className="flex gap-2 relative">
                    <input
                        type="text"
                        value={inputValue}
                        onChange={(e) => setInputValue(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                        disabled={isProcessing}
                        placeholder={isProcessing ? "Thinking..." : "Ask Truth Guard™ about this document..."}
                        className="flex-1 p-3 pl-4 rounded-xl border border-gray-300 focus:outline-none focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 transition-all"
                    />
                    <button 
                        onClick={handleSendMessage}
                        disabled={isProcessing || !inputValue.trim()}
                        className="bg-indigo-600 text-white px-6 rounded-xl hover:bg-indigo-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors"
                    >
                        {isProcessing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-paper-plane"></i>}
                    </button>
                </div>
            </div>
        </div>
    </div>
  );
};

export default DocumentChat;

