// --- Audio Helpers ---

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useState, useEffect, useRef } from 'react';
import { TranslationMode, SUPPORTED_LANGUAGES } from '../types';
import { translateText, speakText } from '../services/geminiService';

// Polyfill type for SpeechRecognition
declare global {
    interface Window {
        webkitSpeechRecognition: any;
        SpeechRecognition: any;
    }
}

const Translator: React.FC = () => {
  const [sourceText, setSourceText] = useState('');
  const [targetText, setTargetText] = useState('');
  const [sourceLang, setSourceLang] = useState('auto');
  const [targetLang, setTargetLang] = useState('es');
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TRANSLATE);
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);

  const recognitionRef = useRef<any>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        recognitionRef.current = new SpeechRecognition();
        recognitionRef.current.continuous = false;
        recognitionRef.current.interimResults = false;

        recognitionRef.current.onresult = (event: any) => {
            const transcript = event.results[0][0].transcript;
            setSourceText(transcript);
            setIsListening(false);
        };

        recognitionRef.current.onerror = (event: any) => {
            console.error(event.error);
            setIsListening(false);
        };

        recognitionRef.current.onend = () => {
            setIsListening(false);
        };
    }
  }, []);

  // Debounce translation trigger
  useEffect(() => {
    const timer = setTimeout(() => {
      if (sourceText.length > 1) { // Process even short texts if spoken
        handleProcess();
      }
    }, 1000);

    return () => clearTimeout(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [sourceText, sourceLang, targetLang, mode]);

  const handleProcess = async () => {
    if (!sourceText.trim()) return;
    setIsLoading(true);
    const result = await translateText(sourceText, sourceLang, targetLang, mode);
    setTargetText(result);
    setIsLoading(false);
  };

  const toggleListening = () => {
    if (isListening) {
        recognitionRef.current?.stop();
        setIsListening(false);
    } else {
        if (recognitionRef.current) {
            // Set language if not auto
            if (sourceLang !== 'auto') {
                recognitionRef.current.lang = sourceLang;
            }
            recognitionRef.current.start();
            setIsListening(true);
        } else {
            alert("Speech recognition not supported in this browser.");
        }
    }
  };

  const handleSpeak = async () => {
      if (!targetText) return;
      setIsPlaying(true);
      await speakText(targetText);
      setIsPlaying(false);
  };

  const handleSwap = () => {
    if (sourceLang === 'auto') return; // Can't swap auto
    const oldSource = sourceLang;
    setSourceLang(targetLang);
    setTargetLang(oldSource);
    setSourceText(targetText);
    setTargetText(sourceText);
  };

  return (
    <div className="space-y-6">
      {/* Control Panel */}
      <div className="bg-gray-50 p-6 rounded-xl border border-gray-200 grid grid-cols-1 md:grid-cols-3 gap-6 shadow-sm">
        <div className="flex flex-col gap-2">
          <label className="text-sm font-semibold text-gray-600">Source Language</label>
          <select 
            value={sourceLang}
            onChange={(e) => setSourceLang(e.target.value)}
            className="p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
          >
            {SUPPORTED_LANGUAGES.map(l => (
              <option key={`src-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>

        <div className="flex flex-col gap-2 justify-center items-center">
            <button 
                onClick={handleSwap}
                className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                title="Swap Languages"
            >
                <i className="fas fa-exchange-alt"></i>
            </button>
        </div>

        <div className="flex flex-col gap-2">
          <label className="text-sm font-semibold text-gray-600">Target Language</label>
          <select 
            value={targetLang}
            onChange={(e) => setTargetLang(e.target.value)}
            className="p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
          >
            {SUPPORTED_LANGUAGES.filter(l => l.code !== 'auto').map(l => (
              <option key={`tgt-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Mode Toggle */}
      <div className="flex justify-center">
        <div className="bg-gray-200 p-1 rounded-full flex gap-1 relative">
             <button
                onClick={() => setMode(TranslationMode.TRANSLATE)}
                className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${mode === TranslationMode.TRANSLATE ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600 hover:text-gray-800'}`}
             >
                <i className="fas fa-language mr-2"></i> Translate
             </button>
             <button
                onClick={() => setMode(TranslationMode.TRANSLITERATE)}
                className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${mode === TranslationMode.TRANSLITERATE ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600 hover:text-gray-800'}`}
             >
                <i className="fas fa-font mr-2"></i> Transliterate
             </button>
        </div>
      </div>

      {/* Text Areas */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="relative group">
            <div className="flex justify-between mb-2">
                <span className="text-sm font-semibold text-gray-600">Source</span>
                <button
                    onClick={toggleListening}
                    className={`text-xs flex items-center gap-1 font-bold transition-colors ${isListening ? 'text-red-600 animate-pulse' : 'text-gray-500 hover:text-indigo-600'}`}
                >
                    <i className={`fas fa-microphone${isListening ? '' : '-slash'}`}></i>
                    {isListening ? ' Listening...' : ' Voice Input'}
                </button>
            </div>
            <textarea
                value={sourceText}
                onChange={(e) => setSourceText(e.target.value)}
                placeholder="Type or click microphone..."
                className="w-full h-80 p-5 rounded-2xl border border-gray-300 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none resize-none shadow-inner transition-all text-lg"
            ></textarea>
        </div>

        <div className="relative group">
            <div className="flex justify-between mb-2">
                <span className="text-sm font-semibold text-gray-600 flex items-center gap-2">
                    Result 
                    {isLoading && <i className="fas fa-spinner fa-spin text-indigo-500"></i>}
                </span>
                <div className="flex gap-3">
                     <button 
                        onClick={handleSpeak}
                        disabled={!targetText || isPlaying}
                        className={`text-xs font-bold transition-colors flex items-center gap-1 ${isPlaying ? 'text-green-600' : 'text-gray-500 hover:text-indigo-600'}`}
                     >
                        <i className={`fas fa-volume-${isPlaying ? 'up' : 'off'}`}></i>
                        {isPlaying ? ' Playing...' : ' Listen'}
                     </button>
                     <button 
                        onClick={() => navigator.clipboard.writeText(targetText)}
                        className="text-xs text-indigo-600 hover:text-indigo-800 font-medium"
                     >
                        <i className="fas fa-copy mr-1"></i> Copy
                     </button>
                </div>
            </div>
            <textarea
                readOnly
                value={targetText}
                placeholder={isLoading ? "Processing..." : "Result will appear here..."}
                className="w-full h-80 p-5 rounded-2xl border border-gray-300 bg-gray-50 text-gray-700 resize-none shadow-sm focus:outline-none text-lg"
            ></textarea>
        </div>
      </div>

      {/* Footer Info */}
      <div className="text-center text-xs text-gray-400">
         Powered by Gemini Neural Engine • Tier 1 Cloud Inference
      </div>
    </div>
  );
};

