): Promise<string> => {
  const promptText = mode === TranslationMode.TRANSLITERATE
    ? `Transliterate the attached document content from ${sourceLang === 'auto' ? 'detected language' : sourceLang} script to ${targetLang} script. Preserve the original layout and structure as much as possible. Return ONLY the transliterated text.`
    : `Translate the attached document content from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}. Preserve the original layout, structure, and formatting as much as possible. Return ONLY the translated text.`;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: [
        { inlineData: { mimeType: file.mimeType, data: file.data } },
        { text: promptText }
      ],
      config: {
        temperature: 0.3,
      }
    });
    return response.text || "Document translation failed.";
  } catch (error) {
    console.error("Gemini Document Translation Error:", error);
    return "Error: Could not process document. Ensure it is a valid PDF or Text file.";
  }
};

// --- Text-to-Speech (TTS) ---

export const speakText = async (text: string): Promise<void> => {
  try {
    const response = await ai.models.generateContent({
      model: TTS_MODEL,
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data returned");

    const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)();

    const audioBuffer = await decodeAudioData(
      decode(base64Audio),
      outputAudioContext,
      24000,
      1,
    );

    const source = outputAudioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(outputAudioContext.destination);
    source.start();

  } catch (error) {
    console.error("TTS Error:", error);
    alert("Could not generate speech. Please check your network connection.");
  }
};

