import { GoogleGenAI, GenerateContentResponse, Modality } from "@google/genai";
import { TranslationMode } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using Gemini 3 Flash for text tasks
const MODEL_NAME = 'gemini-3-flash-preview';
const TTS_MODEL = 'gemini-2.5-flash-preview-tts';

// --- Translation ---

export const translateText = async (
  text: string, 
  sourceLang: string, 
  targetLang: string, 
  mode: TranslationMode
): Promise<string> => {
  if (!text.trim()) return "";

  let prompt = "";

  if (mode === TranslationMode.TRANSLITERATE) {
    prompt = `You are a strict transliteration engine. Convert the following text phonetically from ${sourceLang === 'auto' ? 'detected language' : sourceLang} script to ${targetLang} script. 
    DO NOT translate the meaning. Only convert the sounds/script.
    Input: "${text}"`;
  } else {
    prompt = `You are a high-fidelity neural translation engine. Translate the following text from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}.
    Maintain tone, context, and nuance.
    Input: "${text}"`;
  }

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        temperature: 0.3, 
      }
    });
    return response.text || "Translation failed.";
  } catch (error) {
    console.error("Gemini Translation Error:", error);
    return "Error: Could not process text. Please check connectivity and API Key.";
  }
};

export const translateDocument = async (
  file: { data: string; mimeType: string; isBinary: boolean },
  sourceLang: string,
  targetLang: string,
  mode: TranslationMode
): Promise<string> => {

  let taskDescription = "";

  // Check if it is an image
  if (file.mimeType.startsWith('image/')) {
    taskDescription = `You are a Vision-to-Text Translator. 
    1. Analyze the attached image.
    2. If the image contains legible text, extract it and translate it from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}.
    3. If the image does NOT contain significant text (or is just an object/scene), provide a detailed description of what you see in the image, written in ${targetLang}.`;
  } else {
    // Standard Document logic
    taskDescription = mode === TranslationMode.TRANSLITERATE
    ? `Transliterate the document content from ${sourceLang === 'auto' ? 'detected language' : sourceLang} script to ${targetLang} script.`
    : `Translate the document content from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}.`;
  }

  const instruction = `${taskDescription} Preserve original formatting where possible. Return ONLY the result.`;

  try {
    const parts: any[] = [];

    if (file.isBinary) {
        // For PDF/Images, use inlineData
        parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        parts.push({ text: instruction });
    } else {
        // For Text files, inject directly into prompt
        parts.push({ text: `${instruction}\n\n--- START OF DOCUMENT CONTENT ---\n${file.data}\n--- END OF DOCUMENT CONTENT ---` });
    }

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: [{ role: 'user', parts: parts }],
      config: {
        temperature: 0.3,
      }
    });
    return response.text || "Document translation failed.";
  } catch (error) {
    console.error("Gemini Document Translation Error:", error);
    return "Error: Could not process content. Ensure it is a valid file.";
  }
};

// --- Text-to-Speech (TTS) ---

export const speakText = async (text: string): Promise<void> => {
  try {
    const response = await ai.models.generateContent({
      model: TTS_MODEL,
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data returned");

    const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)();

    const audioBuffer = await decodeAudioData(
      decode(base64Audio),
      outputAudioContext,
      24000,
      1,
    );

    const source = outputAudioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(outputAudioContext.destination);
    source.start();

  } catch (error) {
    console.error("TTS Error:", error);
    alert("Could not generate speech. Please check your network connection.");
  }
};

// --- Intelligent Hybrid Chat (Search + RAG) ---

export const chatHybrid = async (
  query: string,
  chatHistory: { role: string; parts: { text: string }[] }[],
  documentContext?: string,
  links?: string[]
): Promise<{ text: string, sources?: { uri: string; title: string }[] }> => {

  let systemInstruction = "";
  let tools = [];
  const hasLinks = links && links.length > 0;

  if (documentContext) {
    // --- TRUTH GUARD MODE (RAG) ---
    systemInstruction = `You are NeuroLingua's "Truth Guard". 
    A document has been uploaded by the user.

    RULES:
    1. Priority: Answer strictly based on the provided "CONTEXT" below.
    2. If the answer is found in the context, cite it implicitly.
    3. If the answer is NOT in the context, state that clearly, then provide a general knowledge answer but label it as "General Knowledge (Outside Document)".

    DOCUMENT CONTEXT:
    ${documentContext.substring(0, 30000)}... (truncated)`;

    // In RAG mode, normally disable search. 
    // BUT if user explicitly provides links, we enable search to check those links.
    if (hasLinks) {
      tools = [{ googleSearch: {} }];
      systemInstruction += `\n\nNOTE: The user has also provided external links. Use Google Search to verify or retrieve information from these specific links if needed.`;
    } else {
      tools = []; 
    }

  } else {
    // --- GENERAL INTELLIGENCE MODE (Search) ---
    systemInstruction = `You are "NeuroLingua AI", a helpful assistant.
    You have access to Google Search. Use it for current events, facts, and general queries.
    Always provide helpful, concise, and accurate answers.`;

    tools = [{ googleSearch: {} }];
  }

  // Inject Links into the query to ensure the model attends to them
  let finalQuery = query;
  if (hasLinks) {
      finalQuery += `\n\n[USER PROVIDED REFERENCE LINKS]:\n${links?.map(l => `- ${l}`).join('\n')}\nPlease use these links as primary sources if accessible via Search.`;
  }

  try {
    const chat = ai.chats.create({
      model: MODEL_NAME,
      config: { 
        systemInstruction,
        tools: tools
      },
      history: chatHistory
    });

    const response = await chat.sendMessage({ message: finalQuery });

    // Extract Grounding (Web Sources) if available
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources: { uri: string; title: string }[] = [];

    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.web?.uri) {
          sources.push({
            uri: chunk.web.uri,
            title: chunk.web.title || "Web Source"
          });
        }
      });
    }

    return { 
      text: response.text || "I couldn't generate a response.", 
      sources: sources.length > 0 ? sources : undefined 
    };

  } catch (error) {
    console.error("Chat Error:", error);
    return { text: "Error connecting to NeuroLingua Intelligence." };
  }
};

export const chatWithDocument = async (
  query: string,
  documentContent: string,
  chatHistory: { role: string; parts: { text: string }[] }[]
): Promise<string> => {
  const result = await chatHybrid(query, chatHistory, documentContent);
  return result.text;
};

export const analyzeDocument = async (documentContent: string, task: 'summary' | 'questions' | 'keywords'): Promise<string> => {
    let prompt = "";
    switch(task) {
        case 'summary':
            prompt = "Provide a concise executive summary of the following document.";
            break;
        case 'questions':
            prompt = "Generate 5 critical questions that this document answers.";
            break;
        case 'keywords':
            prompt = "Extract the top 10 most significant keywords or entities from this document.";
            break;
    }

    try {
        const response = await ai.models.generateContent({
            model: MODEL_NAME,
            contents: `${prompt}\n\nDocument:\n${documentContent.substring(0, 30000)}`
        });
        return response.text || "Analysis failed.";
    } catch (error) {
        return "Error analyzing document.";
    }
}

// --- Audio Helpers ---

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useState, useEffect, useRef } from 'react';
import { TranslationMode, SUPPORTED_LANGUAGES } from '../types';
import { translateText, translateDocument, speakText } from '../services/geminiService';

// Polyfill type for SpeechRecognition
declare global {
    interface Window {
        webkitSpeechRecognition: any;
        SpeechRecognition: any;
    }
}

interface AttachedFile {
    name: string;
    mimeType: string;
    data: string; // Base64 (for binary) OR Raw Text (for text files)
    isBinary: boolean;
}

const Translator: React.FC = () => {
  const [sourceText, setSourceText] = useState('');
  const [targetText, setTargetText] = useState('');
  const [sourceLang, setSourceLang] = useState('auto');
  const [targetLang, setTargetLang] = useState('es');
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TRANSLATE);
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);

  // Camera State
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const recognitionRef = useRef<any>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = false;

            recognitionRef.current.onresult = (event: any) => {
                const transcript = event.results[0][0].transcript;
                setSourceText(transcript);
                setIsListening(false);
            };

            recognitionRef.current.onerror = (event: any) => {
                console.error("Speech Recognition Error:", event.error);
                if (event.error === 'network') {
                    alert("Speech recognition failed due to network issues.");
                } else if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
                    alert("Microphone access denied. Please check your browser settings.");
                }
                setIsListening(false);
            };

            recognitionRef.current.onend = () => {
                setIsListening(false);
            };
        } catch (e) {
            console.error("Speech Recognition setup failed:", e);
        }
    }
  }, []);

  // Debounce translation trigger for text (not file)
  useEffect(() => {
    const timer = setTimeout(() => {
      if (sourceText.length > 1 && !attachedFile) { // Only auto-process text if no file attached
        handleProcess();
      }
    }, 1000);

    return () => clearTimeout(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [sourceText, sourceLang, targetLang, mode]);

  // Handle Camera Stream
  useEffect(() => {
    let stream: MediaStream | null = null;

    const startCamera = async () => {
        try {
            stream = await navigator.mediaDevices.getUserMedia({ 
                video: { facingMode: 'environment' } // Prefer back camera on mobile
            });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }
        } catch (err) {
            console.error("Error accessing camera:", err);
            alert("Could not access camera. Please check permissions.");
            setIsCameraOpen(false);
        }
    };

    if (isCameraOpen) {
        startCamera();
    }

    return () => {
        if (stream) {
            stream.getTracks().forEach(track => track.stop());
        }
    };
  }, [isCameraOpen]);

  const capturePhoto = () => {
      if (videoRef.current && canvasRef.current) {
          const video = videoRef.current;
          const canvas = canvasRef.current;

          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;

          const ctx = canvas.getContext('2d');
          if (ctx) {
              ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
              // Get Base64 image
              const dataUrl = canvas.toDataURL('image/jpeg');
              // Remove header for API
              const base64Data = dataUrl.split(',')[1];

              setAttachedFile({
                  name: `capture_${Date.now()}.jpg`,
                  mimeType: 'image/jpeg',
                  data: base64Data,
                  isBinary: true
              });

              setIsCameraOpen(false); // Close camera after capture
              setTargetText('');
          }
      }
  };

  const handleProcess = async () => {
    if (!sourceText.trim() && !attachedFile) return;

    setIsLoading(true);
    let result = "";

    if (attachedFile) {
        // Document or Image Translation
        result = await translateDocument(
            { 
                data: attachedFile.data, 
                mimeType: attachedFile.mimeType, 
                isBinary: attachedFile.isBinary 
            },
            sourceLang,
            targetLang,
            mode
        );
    } else {
        // Text Translation
        result = await translateText(sourceText, sourceLang, targetLang, mode);
    }

    setTargetText(result);
    setIsLoading(false);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
      const file = event.target.files?.[0];
      if (file) {
          // Determine if we should treat as binary (PDF/Image) or text
          const isBinary = file.type === 'application/pdf' || file.type.startsWith('image/');

          const reader = new FileReader();

          reader.onload = (e) => {
              let content = e.target?.result as string;

              if (isBinary) {
                  // Strip Data URL prefix
                  content = content.split(',')[1];
              }

              setAttachedFile({
                  name: file.name,
                  mimeType: file.type || 'text/plain',
                  data: content,
                  isBinary: isBinary
              });
              setTargetText(''); // Clear previous result
          };

          if (isBinary) {
              reader.readAsDataURL(file); // Read as base64 for PDF/Images
          } else {
              reader.readAsText(file); // Read as string for Text files
          }
      }
  };

  const handleRemoveFile = () => {
      setAttachedFile(null);
      setTargetText('');
  };

  const handleDownload = () => {
      if (!targetText) return;

      const element = document.createElement("a");
      const file = new Blob([targetText], {type: 'text/plain'});
      element.href = URL.createObjectURL(file);

      // Generate filename based on attached file or default
      let filename = "translation.txt";
      if (attachedFile) {
          const namePart = attachedFile.name.substring(0, attachedFile.name.lastIndexOf('.')) || attachedFile.name;
          filename = `${namePart}_translated.txt`;
      }

      element.download = filename;
      document.body.appendChild(element); // Required for this to work in FireFox
      element.click();
      document.body.removeChild(element);
  };

  const toggleListening = () => {
    if (isListening) {
        recognitionRef.current?.stop();
        setIsListening(false);
    } else {
        if (recognitionRef.current) {
            // Set language if not auto
            if (sourceLang !== 'auto') {
                recognitionRef.current.lang = sourceLang;
            } else {
                recognitionRef.current.lang = 'en-US'; // Default for auto
            }
            try {
                recognitionRef.current.start();
                setIsListening(true);
            } catch (e) {
                console.error("Failed to start recognition:", e);
                setIsListening(false);
            }
        } else {
            alert("Speech recognition not supported in this browser.");
        }
    }
  };

  const handleSpeak = async () => {
      if (!targetText) return;
      setIsPlaying(true);
      await speakText(targetText);
      setIsPlaying(false);
  };

  const handleSwap = () => {
    if (sourceLang === 'auto') return; // Can't swap auto
    const oldSource = sourceLang;
    setSourceLang(targetLang);
    setTargetLang(oldSource);

    if (!attachedFile) {
        setSourceText(targetText);
        setTargetText(sourceText);
    }
  };

  return (
    <div className="space-y-6">
      {/* Control Panel */}
      <div className="bg-gray-50 p-6 rounded-xl border border-gray-200 grid grid-cols-1 md:grid-cols-3 gap-6 shadow-sm">
        <div className="flex flex-col gap-2">
          <label className="text-sm font-semibold text-gray-600">Source Language</label>
          <select 
            value={sourceLang}
            onChange={(e) => setSourceLang(e.target.value)}
            className="p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
          >
            {SUPPORTED_LANGUAGES.map(l => (
              <option key={`src-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>

        <div className="flex flex-col gap-2 justify-center items-center">
            <button 
                onClick={handleSwap}
                className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                title="Swap Languages"
            >
                <i className="fas fa-exchange-alt"></i>
            </button>
        </div>

        <div className="flex flex-col gap-2">
          <label className="text-sm font-semibold text-gray-600">Target Language</label>
          <select 
            value={targetLang}
            onChange={(e) => setTargetLang(e.target.value)}
            className="p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
          >
            {SUPPORTED_LANGUAGES.filter(l => l.code !== 'auto').map(l => (
              <option key={`tgt-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Mode Toggle */}
      <div className="flex justify-center">
        <div className="bg-gray-200 p-1 rounded-full flex gap-1 relative">
             <button
                onClick={() => setMode(TranslationMode.TRANSLATE)}
                className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${mode === TranslationMode.TRANSLATE ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600 hover:text-gray-800'}`}
             >
                <i className="fas fa-language mr-2"></i> Translate
             </button>
             <button
                onClick={() => setMode(TranslationMode.TRANSLITERATE)}
                className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${mode === TranslationMode.TRANSLITERATE ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600 hover:text-gray-800'}`}
             >
                <i className="fas fa-font mr-2"></i> Transliterate
             </button>
        </div>
      </div>

      {/* Text Areas */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative">

        {/* Camera Modal Overlay */}
        {isCameraOpen && (
            <div className="absolute inset-0 z-50 bg-black/90 rounded-2xl flex flex-col items-center justify-center p-4">
                <div className="relative w-full max-w-sm aspect-[3/4] bg-black rounded-lg overflow-hidden border border-gray-600 shadow-2xl">
                    <video 
                        ref={videoRef} 
                        autoPlay 
                        playsInline 
                        className="w-full h-full object-cover"
                    />
                    <canvas ref={canvasRef} className="hidden" />
                </div>
                <div className="flex gap-4 mt-6">
                    <button 
                        onClick={() => setIsCameraOpen(false)}
                        className="px-6 py-3 rounded-full bg-gray-700 text-white font-bold hover:bg-gray-600 transition-colors"
                    >
                        Cancel
                    </button>
                    <button 
                        onClick={capturePhoto}
                        className="px-6 py-3 rounded-full bg-white text-black font-bold hover:bg-gray-200 transition-colors flex items-center gap-2"
                    >
                        <i className="fas fa-camera"></i> Capture
                    </button>
                </div>
            </div>
        )}

        {/* SOURCE AREA */}
        <div className="relative group">
            <div className="flex justify-between mb-2">
                <span className="text-sm font-semibold text-gray-600">Source</span>
                <div className="flex gap-2">
                    {/* Camera Button */}
                     <button
                        onClick={() => setIsCameraOpen(true)}
                        disabled={!!attachedFile}
                        className={`text-xs flex items-center gap-1 font-bold transition-colors ${attachedFile ? 'opacity-30 cursor-not-allowed' : 'text-gray-500 hover:text-indigo-600'}`}
                    >
                        <i className="fas fa-camera"></i> Camera
                    </button>

                    {/* File Upload Button */}
                     <label className={`cursor-pointer text-xs flex items-center gap-1 font-bold transition-colors ${attachedFile ? 'text-indigo-600' : 'text-gray-500 hover:text-indigo-600'}`} title="Attach PDF, Image or Text file">
                        <input type="file" className="hidden" accept=".pdf,.txt,.md,.csv,.json,image/*" onChange={handleFileUpload} />
                        <i className="fas fa-paperclip"></i>
                        {attachedFile ? ' Change File' : ' Attach'}
                    </label>

                    {/* Microphone Button */}
                    <button
                        onClick={toggleListening}
                        disabled={!!attachedFile}
                        className={`text-xs flex items-center gap-1 font-bold transition-colors ${isListening ? 'text-red-600 animate-pulse' : 'text-gray-500 hover:text-indigo-600'} ${attachedFile ? 'opacity-30 cursor-not-allowed' : ''}`}
                    >
                        <i className={`fas fa-microphone${isListening ? '' : '-slash'}`}></i>
                        {isListening ? ' Listening...' : ' Voice'}
                    </button>
                </div>
            </div>

            <div className="relative w-full h-80">
                {attachedFile ? (
                    <div className="absolute inset-0 z-10 bg-indigo-50 border-2 border-indigo-200 border-dashed rounded-2xl flex flex-col items-center justify-center p-6 text-center animate-fade-in">
                        <div className="bg-white p-4 rounded-full shadow-sm mb-3 text-indigo-600 text-2xl">
                             <i className={`fas ${attachedFile.mimeType.startsWith('image/') ? 'fa-image' : (attachedFile.isBinary ? 'fa-file-pdf' : 'fa-file-alt')}`}></i>
                        </div>
                        <h4 className="font-bold text-gray-800 break-all max-w-full mb-1">{attachedFile.name}</h4>
                        <p className="text-xs text-gray-500 mb-4">
                            {attachedFile.mimeType.startsWith('image/') ? 'Image Captured/Uploaded' : 'Document ready'}
                        </p>

                        {/* If it's an image, show a small preview */}
                        {attachedFile.mimeType.startsWith('image/') && (
                             <div className="w-20 h-20 mb-4 rounded-lg overflow-hidden border border-gray-300 shadow-sm">
                                 <img src={`data:${attachedFile.mimeType};base64,${attachedFile.data}`} alt="Preview" className="w-full h-full object-cover" />
                             </div>
                        )}

                        <div className="flex gap-2">
                             <button 
                                onClick={handleProcess}
                                disabled={isLoading}
                                className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-indigo-700 transition-colors shadow-sm"
                             >
                                {isLoading ? <i className="fas fa-spinner fa-spin"></i> : (attachedFile.mimeType.startsWith('image/') ? 'Analyze Image' : 'Translate Doc')}
                             </button>
                             <button 
                                onClick={handleRemoveFile}
                                className="bg-white text-red-500 border border-red-200 px-4 py-2 rounded-lg text-sm font-bold hover:bg-red-50 transition-colors"
                             >
                                Remove
                             </button>
                        </div>
                    </div>
                ) : (
                    <textarea
                        value={sourceText}
                        onChange={(e) => setSourceText(e.target.value)}
                        placeholder="Type text, use voice, attach a file, or use camera..."
                        className="w-full h-full p-5 rounded-2xl border border-gray-300 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none resize-none shadow-inner transition-all text-lg"
                    ></textarea>
                )}
            </div>
        </div>

        {/* TARGET AREA */}
        <div className="relative group">
            <div className="flex justify-between mb-2">
                <span className="text-sm font-semibold text-gray-600 flex items-center gap-2">
                    Result 
                    {isLoading && <i className="fas fa-spinner fa-spin text-indigo-500"></i>}
                </span>
                <div className="flex gap-3">
                     {/* Download Button */}
                     <button
                        onClick={handleDownload}
                        disabled={!targetText}
                        className={`text-xs font-bold transition-colors flex items-center gap-1 ${targetText ? 'text-indigo-600 hover:text-indigo-800' : 'text-gray-300 cursor-not-allowed'}`}
                        title="Download Result as Text File"
                     >
                        <i className="fas fa-download"></i> Download
                     </button>

                     <button 
                        onClick={handleSpeak}
                        disabled={!targetText || isPlaying}
                        className={`text-xs font-bold transition-colors flex items-center gap-1 ${isPlaying ? 'text-green-600' : 'text-gray-500 hover:text-indigo-600'}`}
                     >
                        <i className={`fas fa-volume-${isPlaying ? 'up' : 'off'}`}></i>
                        {isPlaying ? ' Playing...' : ' Listen'}
                     </button>
                     <button 
                        onClick={() => navigator.clipboard.writeText(targetText)}
                        className="text-xs text-indigo-600 hover:text-indigo-800 font-medium"
                     >
                        <i className="fas fa-copy mr-1"></i> Copy
                     </button>
                </div>
            </div>
            <textarea
                readOnly
                value={targetText}
                placeholder={isLoading ? "Processing..." : "Result will appear here..."}
                className="w-full h-80 p-5 rounded-2xl border border-gray-300 bg-gray-50 text-gray-700 resize-none shadow-sm focus:outline-none text-lg"
            ></textarea>
        </div>
      </div>

      {/* Footer Info */}
      <div className="text-center text-xs text-gray-400">
         Powered by Gemini Neural Engine • Tier 1 Cloud Inference
      </div>
    </div>
  );
};

