import { GoogleGenAI, GenerateContentResponse, Modality } from "@google/genai";
import { TranslationMode } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using Gemini 3 Flash for text tasks
const MODEL_NAME = 'gemini-3-flash-preview';
const TTS_MODEL = 'gemini-2.5-flash-preview-tts';

// --- Translation ---

export const translateText = async (
  text: string, 
  sourceLang: string, 
  targetLang: string, 
  mode: TranslationMode
): Promise<string> => {
  if (!text.trim()) return "";

  let prompt = "";

  if (mode === TranslationMode.TRANSLITERATE) {
    prompt = `You are a strict transliteration engine. Convert the following text phonetically from ${sourceLang === 'auto' ? 'detected language' : sourceLang} script to ${targetLang} script. 
    DO NOT translate the meaning. Only convert the sounds/script.
    Input: "${text}"`;
  } else {
    prompt = `You are a high-fidelity neural translation engine. Translate the following text from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}.
    Maintain tone, context, and nuance.
    Input: "${text}"`;
  }

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        temperature: 0.3, 
      }
    });
    return response.text || "Translation failed.";
  } catch (error) {
    console.error("Gemini Translation Error:", error);
    return "Error: Could not process text. Please check connectivity and API Key.";
  }
};

export const translateDocument = async (
  file: { data: string; mimeType: string; isBinary: boolean },
  sourceLang: string,
  targetLang: string,
  mode: TranslationMode
): Promise<string> => {

  let taskDescription = "";

  // Check if it is an image
  if (file.mimeType.startsWith('image/')) {
    taskDescription = `You are a Vision-to-Text Translator. 
    1. Analyze the attached image.
    2. If the image contains legible text, extract it and translate it from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}.
    3. If the image does NOT contain significant text (or is just an object/scene), provide a detailed description of what you see in the image, written in ${targetLang}.`;
  } else {
    // Standard Document logic
    taskDescription = mode === TranslationMode.TRANSLITERATE
    ? `Transliterate the document content from ${sourceLang === 'auto' ? 'detected language' : sourceLang} script to ${targetLang} script.`
    : `Translate the document content from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}.`;
  }

  const instruction = `${taskDescription} Preserve original formatting where possible. Return ONLY the result.`;

  try {
    const parts: any[] = [];

    if (file.isBinary) {
        // For PDF/Images, use inlineData
        parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        parts.push({ text: instruction });
    } else {
        // For Text files, inject directly into prompt
        parts.push({ text: `${instruction}\n\n--- START OF DOCUMENT CONTENT ---\n${file.data}\n--- END OF DOCUMENT CONTENT ---` });
    }

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: [{ role: 'user', parts: parts }],
      config: {
        temperature: 0.3,
      }
    });
    return response.text || "Document translation failed.";
  } catch (error) {
    console.error("Gemini Document Translation Error:", error);
    return "Error: Could not process content. Ensure it is a valid file.";
  }
};

// --- Text-to-Speech (TTS) ---

export const speakText = async (text: string): Promise<void> => {
  try {
    const response = await ai.models.generateContent({
      model: TTS_MODEL,
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data returned");

    const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)();

    const audioBuffer = await decodeAudioData(
      decode(base64Audio),
      outputAudioContext,
      24000,
      1,
    );

    const source = outputAudioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(outputAudioContext.destination);
    source.start();

  } catch (error) {
    console.error("TTS Error:", error);
    alert("Could not generate speech. Please check your network connection.");
  }
};

// --- Intelligent Hybrid Chat (Search + RAG) ---

export const chatHybrid = async (
  query: string,
  chatHistory: { role: string; parts: { text: string }[] }[],
  documentContext?: string,
  links?: string[]
): Promise<{ text: string, sources?: { uri: string; title: string }[] }> => {

  let systemInstruction = "";
  let tools = [];
  const hasLinks = links && links.length > 0;

  if (documentContext) {
    // --- TRUTH GUARD MODE (RAG) ---
    systemInstruction = `You are NeuroLingua's "Truth Guard". 
    A document has been uploaded by the user.

    **ADAPTIVE EXPERT ROLE**:
    Analyze the user's query and the document content to identify the specific field of study. Adopt the persona of a seasoned expert in that domain.

    **CONTEXTUAL LANGUAGE ENHANCEMENT**:
    - **Jewish Context**: If the query relates to Judaism/Hebrew Bible, use **Hebrew** terminology to refine the context.
    - **Hindu Context**: If the query relates to Hinduism/Vedas, use **Sanskrit** terminology.
    - **Christian/Western Context**: If the query relates to Christianity/Theology, use **Latin** or **Greek** terminology.
    - For other fields, use the appropriate technical or cultural nomenclature to ensure the answer is precise and authoritative.

    **RULES**:
    1. Priority: Answer strictly based on the provided "CONTEXT" below, with elaborate analysis.
    2. If the answer is found in the context, cite it implicitly.
    3. If the answer is NOT in the context, state that clearly, then provide a general knowledge answer but label it as "General Knowledge (Outside Document)".

    DOCUMENT CONTEXT:
    ${documentContext.substring(0, 30000)}... (truncated)`;

    // In RAG mode, normally disable search. 
    // BUT if user explicitly provides links, we enable search to check those links.
    if (hasLinks) {
      tools = [{ googleSearch: {} }];
      systemInstruction += `\n\nNOTE: The user has also provided external links. Use Google Search to verify or retrieve detailed information from these specific links if needed.`;
    } else {
      tools = []; 
    }

  } else {
    // --- GENERAL INTELLIGENCE MODE (Search) ---
    systemInstruction = `You are "NeuroLingua AI", an advanced, context-aware intelligence engine.

    **INSTRUCTION: ANALYZE AND ADAPT**
    1. **Identify the Expert Role**: Analyze the user's input to determine the specific domain (e.g., Theology, Law, Physics, History). Adopt the persona of a world-class expert in that field.

    2. **Contextual Terminology & Search Enhancement**:
       - **Jewish Expert**: If the context is Jewish, use **Hebrew** words to find better context and search results.
       - **Hindu Expert**: If the context is Hindu, use **Sanskrit** words.
       - **Christian Expert**: If the context is Christian, use **Latin** words.
       - **General**: For all other fields, use the specific vocabulary that an expert in that field would use.

    You have access to Google Search. Use this improved context to perform searches and answer current events, facts, or general queries.

    Always provide helpful, fully explanatory, concise, complete, and accurate answers.`;

    tools = [{ googleSearch: {} }];
  }

  // Inject Links into the query to ensure the model attends to them
  let finalQuery = query;
  if (hasLinks) {
      finalQuery += `\n\n[USER PROVIDED REFERENCE LINKS]:\n${links?.map(l => `- ${l}`).join('\n')}\nPlease use these links as primary sources if accessible via Search.`;
  }

  try {
    const chat = ai.chats.create({
      model: MODEL_NAME,
      config: { 
        systemInstruction,
        tools: tools
      },
      history: chatHistory
    });

    const response = await chat.sendMessage({ message: finalQuery });

    // Extract Grounding (Web Sources) if available
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources: { uri: string; title: string }[] = [];

    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.web?.uri) {
          sources.push({
            uri: chunk.web.uri,
            title: chunk.web.title || "Web Source"
          });
        }
      });
    }

    return { 
      text: response.text || "I couldn't generate a response.", 
      sources: sources.length > 0 ? sources : undefined 
    };

  } catch (error) {
    console.error("Chat Error:", error);
    return { text: "Error connecting to NeuroLingua Intelligence." };
  }
};

export const chatWithDocument = async (
  query: string,
  documentContent: string,
  chatHistory: { role: string; parts: { text: string }[] }[]
): Promise<string> => {
  const result = await chatHybrid(query, chatHistory, documentContent);
  return result.text;
};

export const analyzeDocument = async (documentContent: string, task: 'summary' | 'questions' | 'keywords'): Promise<string> => {
    let prompt = "";
    switch(task) {
        case 'summary':
            prompt = "Provide a concise executive summary of the following document.";
            break;
        case 'questions':
            prompt = "Generate 5 critical questions that this document answers.";
            break;
        case 'keywords':
            prompt = "Extract the top 10 most significant keywords or entities from this document.";
            break;
    }

    try {
        const response = await ai.models.generateContent({
            model: MODEL_NAME,
            contents: `${prompt}\n\nDocument:\n${documentContent.substring(0, 30000)}`
        });
        return response.text || "Analysis failed.";
    } catch (error) {
        return "Error analyzing document.";
    }
}

// --- Audio Helpers ---

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export enum AppMode {
  TRANSLATOR = 'translator',
  INTELLIGENT_CHAT = 'intelligent_chat',
  BATCH = 'batch'
}

export enum TranslationMode {
  TRANSLATE = 'TRANSLATE',
  TRANSLITERATE = 'TRANSLITERATE'
}

export interface ChatMessage {
  id: string;
