  const [file, setFile] = useState<UploadedFile | null>(null);

  // Link State
  const [links, setLinks] = useState<string[]>([]);
  const [isLinkInputOpen, setIsLinkInputOpen] = useState(false);
  const [linkInput, setLinkInput] = useState('');

  // Voice State
  const [isListening, setIsListening] = useState(false);
  const [playingMsgId, setPlayingMsgId] = useState<string | null>(null);

  const chatEndRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // --- Voice Input Setup ---
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = false;
            recognitionRef.current.lang = 'en-US';

            recognitionRef.current.onresult = (event: any) => {
                const transcript = event.results[0][0].transcript;
                setInputValue(prev => prev + (prev ? ' ' : '') + transcript);
                setIsListening(false);
            };

            recognitionRef.current.onerror = (event: any) => {
                console.error("Speech Error:", event.error);
                setIsListening(false);
            };

            recognitionRef.current.onend = () => {
                setIsListening(false);
            };
        } catch (e) {
            console.error("Speech Setup Failed", e);
        }
    }
  }, []);

  const toggleListening = () => {
      if (isListening) {
          recognitionRef.current?.stop();
          setIsListening(false);
      } else {
          recognitionRef.current?.start();
          setIsListening(true);
      }
  };

  const handleSpeakMessage = async (msgId: string, text: string) => {
      if (playingMsgId) return; // Prevent overlapping
      setPlayingMsgId(msgId);
      await speakText(text);
      setPlayingMsgId(null);
  };

  // --- File Handling ---
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const uploadedFile = event.target.files?.[0];
    if (uploadedFile) {
        const isPdf = uploadedFile.type === 'application/pdf' || uploadedFile.name.toLowerCase().endsWith('.pdf');

        const reader = new FileReader();
        reader.onload = async (e) => {
            let content = e.target?.result as string;

            if (isPdf) {
                 // Strip Data URL prefix for PDF
                 content = content.split(',')[1];
            }

            setFile({
                name: uploadedFile.name,
                type: uploadedFile.type,
                mimeType: isPdf ? 'application/pdf' : (uploadedFile.type || 'text/plain'),
                isBinary: isPdf,
                size: uploadedFile.size,
                content: content
            });
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'model',
                content: `✅ I have ingested **${uploadedFile.name}**. \nTruth Guard™ mode is active. I will answer based on this document.`,
                timestamp: Date.now()
            }]);
        };

        if (isPdf) {
            reader.readAsDataURL(uploadedFile);
        } else {
            reader.readAsText(uploadedFile);
        }
    }
  };

  const handleRemoveFile = () => {
      setFile(null);
      setMessages(prev => [...prev, {
          id: Date.now().toString(),
          role: 'model',
          content: "Document removed. Returning to General Intelligence (Web Search) mode.",
          timestamp: Date.now()
      }]);
  };

  // --- Link Handling ---
  const handleAddLink = () => {
      if (linkInput.trim()) {
          // Basic URL validation
          let url = linkInput.trim();
          if (!url.startsWith('http://') && !url.startsWith('https://')) {
              url = 'https://' + url;
          }
          setLinks(prev => [...prev, url]);
          setLinkInput('');
          setIsLinkInputOpen(false);
      }
  };

  const handleRemoveLink = (indexToRemove: number) => {
      setLinks(prev => prev.filter((_, idx) => idx !== indexToRemove));
  };

  const runQuickAction = async (action: 'summary' | 'questions' | 'keywords') => {
      if (!file) return;
      setIsProcessing(true);
      // For binary files, we need to pass a special prompt to analyzeDocument or handle it there
      // Currently analyzeDocument expects string content. 
      // We will update analyzeDocument signature in service to match.
      const res = await analyzeDocument(file, action);

      const botMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'model',
        content: `**${action.toUpperCase()}**: \n${res}`,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, botMsg]);
      setIsProcessing(false);
  };

  // --- Chat Logic ---
  const handleSendMessage = async () => {
    if (!inputValue.trim()) return;

    const userMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'user',
        content: inputValue,
        timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsProcessing(true);

    // Format history for Gemini
    // We only pass text history here. The binary context is injected in the service based on 'file' prop.
    const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.content }]
    }));

    // Pass links along with query
    const result = await chatHybrid(userMsg.content, history, file || undefined, links);

    const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        content: result.text,
        timestamp: Date.now(),
        sources: result.sources
    };

    setMessages(prev => [...prev, botMsg]);
    setIsProcessing(false);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 h-[600px]">

        {/* Sidebar (Only shows when file attached) */}
        {file && (
            <div className="lg:col-span-1 space-y-4 animate-fade-in">
                <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-200 shadow-sm">
                    <div className="flex items-center gap-3 mb-2">
                        <div className="bg-indigo-600 text-white p-2 rounded-lg">
                            <i className={`fas ${file.isBinary ? 'fa-file-pdf' : 'fa-file-alt'}`}></i>
                        </div>
                        <div className="overflow-hidden">
                            <h4 className="font-bold text-sm truncate text-indigo-900">{file.name}</h4>
                            <p className="text-xs text-indigo-500">Truth Guard™ Active</p>
                        </div>
                    </div>
                    <button 
                        onClick={handleRemoveFile}
                        className="text-xs text-red-500 hover:text-red-700 w-full text-left mt-2 font-medium"
                    >
                        <i className="fas fa-times-circle mr-1"></i> Disconnect File
                    </button>
                </div>

                <div className="bg-white border border-gray-200 p-4 rounded-xl shadow-sm">
                    <h4 className="font-bold text-xs text-gray-400 mb-3 uppercase tracking-wider">Document Actions</h4>
                    <div className="space-y-2">
                        <button onClick={() => runQuickAction('summary')} className="w-full text-left px-3 py-2 hover:bg-gray-100 rounded-lg text-sm text-gray-700 transition-colors">
                            <i className="fas fa-list-ul mr-2 text-indigo-500"></i> Summarize
                        </button>
                        <button onClick={() => runQuickAction('questions')} className="w-full text-left px-3 py-2 hover:bg-gray-100 rounded-lg text-sm text-gray-700 transition-colors">
                            <i className="fas fa-question-circle mr-2 text-indigo-500"></i> Gen. Questions
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Chat Area */}
        <div className={`${file ? 'lg:col-span-3' : 'lg:col-span-4'} flex flex-col bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden transition-all duration-300`}>

            {/* Header */}
            <div className="bg-white border-b border-gray-100 p-4 flex justify-between items-center">
                 <div className="flex items-center gap-3">
                     <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white shadow-lg ${file ? 'bg-indigo-600' : 'bg-gradient-to-br from-cyan-400 to-blue-600'}`}>
                         <i className={`fas ${file ? 'fa-shield-alt' : 'fa-robot'}`}></i>
                     </div>
                     <div>
                         <h3 className="font-bold text-gray-800">{file ? 'Truth Guard™' : 'NeuroLingua AI'}</h3>
                         <p className="text-xs text-gray-500">
                            {file ? 'RAG Mode • Strictly Contextual' : 'General Mode • Web Search Enabled'}
                         </p>
                     </div>
                 </div>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-gray-50/30">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                        <div className={`max-w-[85%] rounded-2xl p-4 shadow-sm relative group ${
                            msg.role === 'user' 
                                ? 'bg-indigo-600 text-white rounded-tr-none' 
                                : 'bg-white border border-gray-200 text-gray-800 rounded-tl-none'
                        }`}>
                            <div className="whitespace-pre-wrap text-sm leading-relaxed">{msg.content}</div>

                            {/* Sources (if any) */}
                            {msg.sources && msg.sources.length > 0 && (
                                <div className="mt-3 pt-3 border-t border-gray-100">
                                    <p className="text-xs font-bold text-gray-400 mb-1">Sources:</p>
                                    <div className="flex flex-wrap gap-2">
                                        {msg.sources.map((src, idx) => (
                                            <a key={idx} href={src.uri} target="_blank" rel="noopener noreferrer" className="text-xs bg-blue-50 text-blue-600 px-2 py-1 rounded hover:bg-blue-100 truncate max-w-[200px] block">
                                                {src.title}
                                            </a>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* Speaker Button */}
                            <button 
                                onClick={() => handleSpeakMessage(msg.id, msg.content)}
                                className={`absolute -bottom-8 ${msg.role === 'user' ? 'right-0' : 'left-0'} text-gray-400 hover:text-indigo-600 text-xs p-1 opacity-0 group-hover:opacity-100 transition-opacity`}
                            >
                                <i className={`fas ${playingMsgId === msg.id ? 'fa-volume-up animate-pulse text-indigo-600' : 'fa-volume-off'}`}></i>
                                {playingMsgId === msg.id ? ' Playing...' : ' Read'}
                            </button>
                        </div>
                    </div>
                ))}
                <div ref={chatEndRef} />
            </div>

            {/* Input Area */}
            <div className="p-4 bg-white border-t border-gray-100 relative">

                {/* Active Links Chips */}
                {links.length > 0 && (
                    <div className="flex flex-wrap gap-2 mb-3 px-1">
                        {links.map((link, idx) => (
                            <div key={idx} className="flex items-center gap-1 bg-blue-50 text-blue-600 text-xs font-medium px-2 py-1 rounded-md border border-blue-100 max-w-[200px]">
                                <i className="fas fa-link text-[10px]"></i>
                                <span className="truncate">{link}</span>
                                <button onClick={() => handleRemoveLink(idx)} className="ml-1 text-blue-400 hover:text-red-500">
                                    <i className="fas fa-times"></i>
                                </button>
                            </div>
                        ))}
                    </div>
                )}

                {/* Link Input Popover */}
                {isLinkInputOpen && (
                    <div className="absolute bottom-20 left-4 z-20 bg-white p-3 rounded-xl shadow-xl border border-gray-200 w-72 animate-fade-in">
                        <h5 className="text-xs font-bold text-gray-600 mb-2">Add Reference Link</h5>
                        <div className="flex gap-2">
                            <input 
                                type="text" 
                                value={linkInput}
                                onChange={(e) => setLinkInput(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && handleAddLink()}
                                placeholder="https://example.com"
                                className="flex-1 text-sm border border-gray-300 rounded-lg px-2 py-1 focus:outline-none focus:border-indigo-500"
                                autoFocus
                            />
                            <button onClick={handleAddLink} className="bg-indigo-600 text-white px-2 rounded-lg text-xs hover:bg-indigo-700">Add</button>
                        </div>
                        <button onClick={() => setIsLinkInputOpen(false)} className="text-xs text-gray-400 mt-2 hover:text-gray-600 underline">Cancel</button>
                    </div>
                )}

                <div className="flex gap-2 relative items-center">

                    {/* Link Button */}
                    <button 
                         onClick={() => setIsLinkInputOpen(!isLinkInputOpen)}
                         className={`p-3 rounded-full transition-colors ${links.length > 0 ? 'text-blue-600 bg-blue-50' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'}`}
                         title="Add Reference URL"
                    >
                         <i className="fas fa-link text-lg"></i>
                    </button>

                    {/* File Upload Button */}
                    <label className={`cursor-pointer p-3 rounded-full transition-colors ${file ? 'text-indigo-600 bg-indigo-50' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'}`} title="Upload Document (PDF/Text) for Truth Guard">
                        <input type="file" className="hidden" accept=".pdf,.txt,.md,.json,.csv" onChange={handleFileUpload} disabled={!!file} />
                        <i className="fas fa-paperclip text-lg"></i>
                    </label>

                    {/* Microphone Button */}
                    <button 
                        onClick={toggleListening}
                        className={`p-3 rounded-full transition-colors ${isListening ? 'bg-red-100 text-red-600 animate-pulse' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'}`}
                        title="Voice Input"
                    >
                        <i className={`fas fa-microphone${isListening ? '' : '-slash'} text-lg`}></i>
                    </button>

                    <input
                        type="text"
                        value={inputValue}
                        onChange={(e) => setInputValue(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                        disabled={isProcessing}
                        placeholder={isListening ? "Listening..." : (file ? "Ask Truth Guard about the file..." : "Ask anything (Web Search enabled)...")}
                        className="flex-1 p-3 pl-4 rounded-xl border border-gray-300 focus:outline-none focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 transition-all"
                    />

                    <button 
                        onClick={handleSendMessage}
                        disabled={isProcessing || !inputValue.trim()}
                        className="bg-indigo-600 text-white w-12 h-12 rounded-xl hover:bg-indigo-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition-all shadow-md flex items-center justify-center"
                    >
                        {isProcessing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-paper-plane"></i>}
                    </button>
                </div>
            </div>
        </div>
    </div>
  );
};

export default IntelligentChat;

import { GoogleGenAI, GenerateContentResponse, Modality } from "@google/genai";
import { TranslationMode } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using Gemini 3 Flash for text tasks
const MODEL_NAME = 'gemini-3-flash-preview';
const TTS_MODEL = 'gemini-2.5-flash-preview-tts';

// --- Translation ---

export const translateText = async (
  text: string, 
  sourceLang: string, 
  targetLang: string, 
  mode: TranslationMode
): Promise<string> => {
  if (!text.trim()) return "";

  let prompt = "";

  if (mode === TranslationMode.TRANSLITERATE) {
    prompt = `You are a strict transliteration engine. Convert the following text phonetically from ${sourceLang === 'auto' ? 'detected language' : sourceLang} script to ${targetLang} script. 
    DO NOT translate the meaning. Only convert the sounds/script.
    Input: "${text}"`;
  } else {
    prompt = `You are a high-fidelity neural translation engine. Translate the following text from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}.
    Maintain tone, context, and nuance.
    Input: "${text}"`;
  }

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        temperature: 0.3, 
      }
    });
    return response.text || "Translation failed.";
  } catch (error) {
    console.error("Gemini Translation Error:", error);
    return "Error: Could not process text. Please check connectivity and API Key.";
  }
};

export const translateDocument = async (
  file: { data: string; mimeType: string; isBinary: boolean },
  sourceLang: string,
  targetLang: string,
  mode: TranslationMode
): Promise<string> => {

  let taskDescription = "";

  // Check if it is an image
  if (file.mimeType.startsWith('image/')) {
    taskDescription = `You are a Vision-to-Text Translator. 
    1. Analyze the attached image.
    2. If the image contains legible text, extract it and translate it from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}.
    3. If the image does NOT contain significant text (or is just an object/scene), provide a detailed description of what you see in the image, written in ${targetLang}.`;
  } else {
    // Standard Document logic
    taskDescription = mode === TranslationMode.TRANSLITERATE
    ? `Transliterate the document content from ${sourceLang === 'auto' ? 'detected language' : sourceLang} script to ${targetLang} script.`
    : `Translate the document content from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}.`;
  }

  const instruction = `${taskDescription} Preserve original formatting where possible. Return ONLY the result.`;

  try {
    const parts: any[] = [];

    if (file.isBinary) {
        // For PDF/Images, use inlineData
        parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        parts.push({ text: instruction });
    } else {
        // For Text files, inject directly into prompt
        parts.push({ text: `${instruction}\n\n--- START OF DOCUMENT CONTENT ---\n${file.data}\n--- END OF DOCUMENT CONTENT ---` });
    }

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: [{ role: 'user', parts: parts }],
      config: {
        temperature: 0.3,
      }
    });
    return response.text || "Document translation failed.";
  } catch (error) {
    console.error("Gemini Document Translation Error:", error);
    return "Error: Could not process content. Ensure it is a valid file.";
  }
};

// --- Text-to-Speech (TTS) ---

export const speakText = async (text: string): Promise<void> => {
  try {
    const response = await ai.models.generateContent({
      model: TTS_MODEL,
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data returned");

    const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)();

    const audioBuffer = await decodeAudioData(
      decode(base64Audio),
      outputAudioContext,
      24000,
      1,
    );

    const source = outputAudioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(outputAudioContext.destination);
    source.start();

  } catch (error) {
    console.error("TTS Error:", error);
    alert("Could not generate speech. Please check your network connection.");
  }
};

// --- Intelligent Hybrid Chat (Search + RAG) ---

export const chatHybrid = async (
  query: string,
  chatHistory: { role: string; parts: { text: string }[] }[],
  document?: { content: string; mimeType: string; isBinary: boolean },
  links?: string[]
): Promise<{ text: string, sources?: { uri: string; title: string }[] }> => {

  let systemInstruction = "";
  let tools = [];
  const hasLinks = links && links.length > 0;

  // BASE INSTRUCTION
  // We refine this to be context-aware of history.
  systemInstruction = `You are "NeuroLingua AI", an advanced, context-aware intelligence engine.

  **INSTRUCTION: ANALYZE AND ADAPT**
  1. **Identify the Expert Role**: Analyze the **entire conversation history** and the **current user query** to determine the specific domain (e.g., Theology, Law, Physics, History). 
  2. **Consistency**: Maintain the adopted persona if the user asks follow-up questions.

  **CONTEXTUAL LANGUAGE ENHANCEMENT**:
     - **Jewish Context**: If the context is Jewish, use **Hebrew** words to find better context and search results.
     - **Hindu Context**: If the context is Hindu, use **Sanskrit** words.
     - **Christian Context**: If the context is Christian, use **Latin** words.
     - **General**: For all other fields, use the specific vocabulary that an expert in that field would use.

  Always provide helpful, fully explanatory, concise, complete, and accurate answers.`;

  if (document) {
    // --- TRUTH GUARD MODE (RAG) ---
    systemInstruction += `\n\n**TRUTH GUARD MODE ACTIVE**:
    A document has been uploaded by the user.

    **RULES**:
    1. Priority: Answer strictly based on the provided DOCUMENT.
    2. If the answer is found in the document, cite it implicitly.
    3. If the answer is NOT in the document, state that clearly, then provide a general knowledge answer but label it as "General Knowledge (Outside Document)".`;

    if (hasLinks) {
      tools = [{ googleSearch: {} }];
      systemInstruction += `\n\nNOTE: The user has also provided external links. Use Google Search to verify or retrieve detailed information from these specific links if needed.`;
    } else {
      // If strictly document based, usually we disable search, but the prompt says "General Knowledge" is allowed if labelled.
      // To prevent hallucination, strict RAG usually disables tools. 
      // However, for "Hybrid" feel, we keep tools empty unless links provided.
      tools = []; 
    }
  } else {
    // --- GENERAL INTELLIGENCE MODE (Search) ---
    systemInstruction += `\n\nYou have access to Google Search. Use it for current events, facts, or general queries.`;
    tools = [{ googleSearch: {} }];
  }

  // Inject Links into the query
  let finalQuery = query;
  if (hasLinks) {
      finalQuery += `\n\n[USER PROVIDED REFERENCE LINKS]:\n${links?.map(l => `- ${l}`).join('\n')}\nPlease use these links as primary sources if accessible via Search.`;
  }

  // PREPARE HISTORY WITH DOCUMENT INJECTION
  // We need to clone the history to avoid mutating the UI state directly if it was passed by reference
  // And we need to inject the document at the start if it exists.
  const apiHistory = [...chatHistory];

  if (document) {
      // Logic: Ensure the document is present in the context.
      // Since we are stateless here (creating new chat each time), we must provide the doc.
      // For PDF (Binary), we add a 'user' part with inlineData.
      // For Text, we can also add a 'user' part or rely on system instruction. 
      // To support PDF seamlessly, we add it to the history as a User message at the very beginning.

      const docPart = document.isBinary 
          ? { inlineData: { mimeType: document.mimeType, data: document.content } }
          : { text: `[DOCUMENT CONTENT]\n${document.content}\n[END DOCUMENT]` };

      // We prepend a system/user turn to establish the document context.
      // Note: Gemini chat history must alternate user/model. 
      // We'll treat the document upload as a separate "User" turn that happened before the conversation.
      // We also add a dummy model response to maintain the turn structure if needed, 
      // but 'history' in create() allows starting with User? No, history must end with Model usually? 
      // Actually, history in `chats.create` is just previous turns. The `sendMessage` adds the new User turn.

      // Check if we already have the doc in history? 
      // Since we rebuild history from UI messages which are text-only, the doc isn't there.
      // So we ALWAYS prepend it here for the API call context.

      apiHistory.unshift({
          role: 'model',
          parts: [{ text: "I have acknowledged the document." }]
      });
      apiHistory.unshift({
          role: 'user',
          parts: [
              docPart,
              { text: "Here is the document I want to analyze." }
          ]
      });
  }

  try {
    const chat = ai.chats.create({
      model: MODEL_NAME,
      config: { 
        systemInstruction,
        tools: tools
      },
      history: apiHistory
    });

    const response = await chat.sendMessage({ message: finalQuery });

    // Extract Grounding (Web Sources)
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources: { uri: string; title: string }[] = [];

    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.web?.uri) {
          sources.push({
            uri: chunk.web.uri,
            title: chunk.web.title || "Web Source"
          });
        }
      });
    }

    return { 
      text: response.text || "I couldn't generate a response.", 
      sources: sources.length > 0 ? sources : undefined 
    };

  } catch (error) {
    console.error("Chat Error:", error);
    return { text: "Error connecting to NeuroLingua Intelligence." };
  }
};

export const chatWithDocument = async (
  query: string,
  documentContent: string,
  chatHistory: { role: string; parts: { text: string }[] }[]
): Promise<string> => {
  // Legacy wrapper if needed, but we mostly use chatHybrid now.
  // Assuming text doc here for backward compat.
  const result = await chatHybrid(query, chatHistory, { content: documentContent, mimeType: 'text/plain', isBinary: false });
  return result.text;
};

export const analyzeDocument = async (
    file: { content: string; mimeType: string; isBinary: boolean }, 
    task: 'summary' | 'questions' | 'keywords'
): Promise<string> => {
    let prompt = "";
