  const [playingMsgId, setPlayingMsgId] = useState<string | null>(null);

  const chatEndRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // --- Voice Input Setup ---
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = false;
            recognitionRef.current.lang = 'en-US';

            recognitionRef.current.onresult = (event: any) => {
                const transcript = event.results[0][0].transcript;
                setInputValue(prev => prev + (prev ? ' ' : '') + transcript);
                setIsListening(false);
            };

            recognitionRef.current.onerror = (event: any) => {
                console.error("Speech Error:", event.error);
                setIsListening(false);
            };

            recognitionRef.current.onend = () => {
                setIsListening(false);
            };
        } catch (e) {
            console.error("Speech Setup Failed", e);
        }
    }
  }, []);

  const toggleListening = () => {
      if (isListening) {
          recognitionRef.current?.stop();
          setIsListening(false);
      } else {
          recognitionRef.current?.start();
          setIsListening(true);
      }
  };

  const handleSpeakMessage = async (msgId: string, text: string) => {
      if (playingMsgId) return; // Prevent overlapping
      setPlayingMsgId(msgId);
      await speakText(text);
      setPlayingMsgId(null);
  };

  // --- File Handling ---
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const uploadedFile = event.target.files?.[0];
    if (uploadedFile) {
        const isPdf = uploadedFile.type === 'application/pdf' || uploadedFile.name.toLowerCase().endsWith('.pdf');

        const reader = new FileReader();
        reader.onload = async (e) => {
            let content = e.target?.result as string;

            if (isPdf) {
                 // Strip Data URL prefix for PDF
                 content = content.split(',')[1];
            }

            setFile({
                name: uploadedFile.name,
                mimeType: isPdf ? 'application/pdf' : (uploadedFile.type || 'text/plain'),
                isBinary: isPdf,
                size: uploadedFile.size,
                content: content
            });
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'model',
                content: `✅ I have ingested **${uploadedFile.name}**. \nTruth Guard™ mode is active. I will answer based on this document.`,
                timestamp: Date.now()
            }]);
        };

        if (isPdf) {
            reader.readAsDataURL(uploadedFile);
        } else {
            reader.readAsText(uploadedFile);
        }
    }
  };

  const handleRemoveFile = () => {
      setFile(null);
      setMessages(prev => [...prev, {
          id: Date.now().toString(),
          role: 'model',
          content: "Document removed. Returning to General Intelligence (Web Search) mode.",
          timestamp: Date.now()
      }]);
  };

  // --- Link Handling ---
  const handleAddLink = () => {
      if (linkInput.trim()) {
          // Basic URL validation
          let url = linkInput.trim();
          if (!url.startsWith('http://') && !url.startsWith('https://')) {
              url = 'https://' + url;
          }
          setLinks(prev => [...prev, url]);
          setLinkInput('');
          setIsLinkInputOpen(false);
      }
  };

  const handleRemoveLink = (indexToRemove: number) => {
      setLinks(prev => prev.filter((_, idx) => idx !== indexToRemove));
  };

  const runQuickAction = async (action: 'summary' | 'questions' | 'keywords') => {
      if (!file) return;
      setIsProcessing(true);
      // For binary files, we need to pass a special prompt to analyzeDocument or handle it there
      // Currently analyzeDocument expects string content. 
      // We will update analyzeDocument signature in service to match.
      const res = await analyzeDocument(file, action);

      const botMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'model',
        content: `**${action.toUpperCase()}**: \n${res}`,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, botMsg]);
      setIsProcessing(false);
  };

  // --- Chat Logic ---
  const handleSendMessage = async () => {
    if (!inputValue.trim()) return;

    const userMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'user',
        content: inputValue,
        timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsProcessing(true);

    // Format history for Gemini
    // We only pass text history here. The binary context is injected in the service based on 'file' prop.
    const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.content }]
    }));

    // Pass links along with query
    const result = await chatHybrid(userMsg.content, history, file || undefined, links);

    const botMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        content: result.text,
        timestamp: Date.now(),
        sources: result.sources
    };

    setMessages(prev => [...prev, botMsg]);
    setIsProcessing(false);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 h-[600px]">

        {/* Sidebar (Only shows when file attached) */}
        {file && (
            <div className="lg:col-span-1 space-y-4 animate-fade-in">
                <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-200 shadow-sm">
                    <div className="flex items-center gap-3 mb-2">
                        <div className="bg-indigo-600 text-white p-2 rounded-lg">
                            <i className={`fas ${file.isBinary ? 'fa-file-pdf' : 'fa-file-alt'}`}></i>
                        </div>
                        <div className="overflow-hidden">
                            <h4 className="font-bold text-sm truncate text-indigo-900">{file.name}</h4>
                            <p className="text-xs text-indigo-500">Truth Guard™ Active</p>
                        </div>
                    </div>
                    <button 
                        onClick={handleRemoveFile}
                        className="text-xs text-red-500 hover:text-red-700 w-full text-left mt-2 font-medium"
                    >
                        <i className="fas fa-times-circle mr-1"></i> Disconnect File
                    </button>
                </div>

                <div className="bg-white border border-gray-200 p-4 rounded-xl shadow-sm">
                    <h4 className="font-bold text-xs text-gray-400 mb-3 uppercase tracking-wider">Document Actions</h4>
                    <div className="space-y-2">
                        <button onClick={() => runQuickAction('summary')} className="w-full text-left px-3 py-2 hover:bg-gray-100 rounded-lg text-sm text-gray-700 transition-colors">
                            <i className="fas fa-list-ul mr-2 text-indigo-500"></i> Summarize
                        </button>
                        <button onClick={() => runQuickAction('questions')} className="w-full text-left px-3 py-2 hover:bg-gray-100 rounded-lg text-sm text-gray-700 transition-colors">
                            <i className="fas fa-question-circle mr-2 text-indigo-500"></i> Gen. Questions
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Chat Area */}
        <div className={`${file ? 'lg:col-span-3' : 'lg:col-span-4'} flex flex-col bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden transition-all duration-300`}>

            {/* Header */}
            <div className="bg-white border-b border-gray-100 p-4 flex justify-between items-center">
                 <div className="flex items-center gap-3">
                     <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white shadow-lg ${file ? 'bg-indigo-600' : 'bg-gradient-to-br from-cyan-400 to-blue-600'}`}>
                         <i className={`fas ${file ? 'fa-shield-alt' : 'fa-robot'}`}></i>
                     </div>
                     <div>
                         <h3 className="font-bold text-gray-800">{file ? 'Truth Guard™' : 'NeuroLingua AI'}</h3>
                         <p className="text-xs text-gray-500">
                            {file ? 'RAG Mode • Strictly Contextual' : 'General Mode • Web Search Enabled'}
                         </p>
                     </div>
                 </div>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-gray-50/30">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                        <div className={`max-w-[85%] rounded-2xl p-4 shadow-sm relative group ${
                            msg.role === 'user' 
                                ? 'bg-indigo-600 text-white rounded-tr-none' 
                                : 'bg-white border border-gray-200 text-gray-800 rounded-tl-none'
                        }`}>
                            <div className="whitespace-pre-wrap text-sm leading-relaxed">{msg.content}</div>

                            {/* Sources (if any) */}
                            {msg.sources && msg.sources.length > 0 && (
                                <div className="mt-3 pt-3 border-t border-gray-100">
                                    <p className="text-xs font-bold text-gray-400 mb-1">Sources:</p>
                                    <div className="flex flex-wrap gap-2">
                                        {msg.sources.map((src, idx) => (
                                            <a key={idx} href={src.uri} target="_blank" rel="noopener noreferrer" className="text-xs bg-blue-50 text-blue-600 px-2 py-1 rounded hover:bg-blue-100 truncate max-w-[200px] block">
                                                {src.title}
                                            </a>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* Speaker Button */}
                            <button 
                                onClick={() => handleSpeakMessage(msg.id, msg.content)}
                                className={`absolute -bottom-8 ${msg.role === 'user' ? 'right-0' : 'left-0'} text-gray-400 hover:text-indigo-600 text-xs p-1 opacity-0 group-hover:opacity-100 transition-opacity`}
                            >
                                <i className={`fas ${playingMsgId === msg.id ? 'fa-volume-up animate-pulse text-indigo-600' : 'fa-volume-off'}`}></i>
                                {playingMsgId === msg.id ? ' Playing...' : ' Read'}
                            </button>
                        </div>
                    </div>
                ))}
                <div ref={chatEndRef} />
            </div>

            {/* Input Area */}
            <div className="p-4 bg-white border-t border-gray-100 relative">

                {/* Active Links Chips */}
                {links.length > 0 && (
                    <div className="flex flex-wrap gap-2 mb-3 px-1">
                        {links.map((link, idx) => (
                            <div key={idx} className="flex items-center gap-1 bg-blue-50 text-blue-600 text-xs font-medium px-2 py-1 rounded-md border border-blue-100 max-w-[200px]">
                                <i className="fas fa-link text-[10px]"></i>
                                <span className="truncate">{link}</span>
                                <button onClick={() => handleRemoveLink(idx)} className="ml-1 text-blue-400 hover:text-red-500">
                                    <i className="fas fa-times"></i>
                                </button>
                            </div>
                        ))}
                    </div>
                )}

                {/* Link Input Popover */}
                {isLinkInputOpen && (
                    <div className="absolute bottom-20 left-4 z-20 bg-white p-3 rounded-xl shadow-xl border border-gray-200 w-72 animate-fade-in">
                        <h5 className="text-xs font-bold text-gray-600 mb-2">Add Reference Link</h5>
                        <div className="flex gap-2">
                            <input 
                                type="text" 
                                value={linkInput}
                                onChange={(e) => setLinkInput(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && handleAddLink()}
                                placeholder="https://example.com"
                                className="flex-1 text-sm border border-gray-300 rounded-lg px-2 py-1 focus:outline-none focus:border-indigo-500"
                                autoFocus
                            />
                            <button onClick={handleAddLink} className="bg-indigo-600 text-white px-2 rounded-lg text-xs hover:bg-indigo-700">Add</button>
                        </div>
                        <button onClick={() => setIsLinkInputOpen(false)} className="text-xs text-gray-400 mt-2 hover:text-gray-600 underline">Cancel</button>
                    </div>
                )}

                <div className="flex gap-2 relative items-center">

                    {/* Link Button */}
                    <button 
                         onClick={() => setIsLinkInputOpen(!isLinkInputOpen)}
                         className={`p-3 rounded-full transition-colors ${links.length > 0 ? 'text-blue-600 bg-blue-50' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'}`}
                         title="Add Reference URL"
                    >
                         <i className="fas fa-link text-lg"></i>
                    </button>

                    {/* File Upload Button */}
                    <label className={`cursor-pointer p-3 rounded-full transition-colors ${file ? 'text-indigo-600 bg-indigo-50' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'}`} title="Upload Document (PDF/Text) for Truth Guard">
                        <input type="file" className="hidden" accept=".pdf,.txt,.md,.json,.csv" onChange={handleFileUpload} disabled={!!file} />
                        <i className="fas fa-paperclip text-lg"></i>
                    </label>

                    {/* Microphone Button */}
                    <button 
                        onClick={toggleListening}
                        className={`p-3 rounded-full transition-colors ${isListening ? 'bg-red-100 text-red-600 animate-pulse' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'}`}
                        title="Voice Input"
                    >
                        <i className={`fas fa-microphone${isListening ? '' : '-slash'} text-lg`}></i>
                    </button>

                    <input
                        type="text"
                        value={inputValue}
                        onChange={(e) => setInputValue(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                        disabled={isProcessing}
                        placeholder={isListening ? "Listening..." : (file ? "Ask Truth Guard about the file..." : "Ask anything (Web Search enabled)...")}
                        className="flex-1 p-3 pl-4 rounded-xl border border-gray-300 focus:outline-none focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 transition-all"
                    />

                    <button 
                        onClick={handleSendMessage}
                        disabled={isProcessing || !inputValue.trim()}
                        className="bg-indigo-600 text-white w-12 h-12 rounded-xl hover:bg-indigo-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition-all shadow-md flex items-center justify-center"
                    >
                        {isProcessing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-paper-plane"></i>}
                    </button>
                </div>
            </div>
        </div>
    </div>
  );
};

export default IntelligentChat;

import React, { useState, useEffect, useRef } from 'react';
import { TranslationMode, SUPPORTED_LANGUAGES } from '../types';
import { translateText, translateDocument, speakText } from '../services/geminiService';

// Polyfill type for SpeechRecognition
declare global {
    interface Window {
        webkitSpeechRecognition: any;
        SpeechRecognition: any;
    }
}

interface AttachedFile {
    name: string;
    mimeType: string;
    data: string; // Base64 (for binary) OR Raw Text (for text files)
    isBinary: boolean;
}

const MAX_FILE_SIZE_MB = 10;
const MAX_FILE_SIZE_BYTES = MAX_FILE_SIZE_MB * 1024 * 1024;

const Translator: React.FC = () => {
  const [sourceText, setSourceText] = useState('');
  const [targetText, setTargetText] = useState('');
  const [sourceLang, setSourceLang] = useState('auto');
  const [targetLang, setTargetLang] = useState('es');
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TRANSLATE);
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);

  // Camera State
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const recognitionRef = useRef<any>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = false;

            recognitionRef.current.onresult = (event: any) => {
                const transcript = event.results[0][0].transcript;
                setSourceText(transcript);
                setIsListening(false);
            };

            recognitionRef.current.onerror = (event: any) => {
                console.error("Speech Recognition Error:", event.error);
                if (event.error === 'network') {
                    alert("Speech recognition failed due to network issues.");
                } else if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
                    alert("Microphone access denied. Please check your browser settings.");
                }
                setIsListening(false);
            };

            recognitionRef.current.onend = () => {
                setIsListening(false);
            };
        } catch (e) {
            console.error("Speech Recognition setup failed:", e);
        }
    }
  }, []);

  // Debounce translation trigger for text (not file)
  useEffect(() => {
    const timer = setTimeout(() => {
      if (sourceText.length > 1 && !attachedFile) { // Only auto-process text if no file attached
        handleProcess();
      }
    }, 1000);

    return () => clearTimeout(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [sourceText, sourceLang, targetLang, mode]);

  // Handle Camera Stream
  useEffect(() => {
    let stream: MediaStream | null = null;

    const startCamera = async () => {
        try {
            stream = await navigator.mediaDevices.getUserMedia({ 
                video: { facingMode: 'environment' } // Prefer back camera on mobile
            });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }
        } catch (err) {
            console.error("Error accessing camera:", err);
            alert("Could not access camera. Please check permissions.");
            setIsCameraOpen(false);
        }
    };

    if (isCameraOpen) {
        startCamera();
    }

    return () => {
        if (stream) {
            stream.getTracks().forEach(track => track.stop());
        }
    };
  }, [isCameraOpen]);

  const capturePhoto = () => {
      if (videoRef.current && canvasRef.current) {
          const video = videoRef.current;
          const canvas = canvasRef.current;

          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;

          const ctx = canvas.getContext('2d');
          if (ctx) {
              ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
              // Get Base64 image
              const dataUrl = canvas.toDataURL('image/jpeg');
              // Remove header for API
              const base64Data = dataUrl.split(',')[1];

              setAttachedFile({
                  name: `capture_${Date.now()}.jpg`,
                  mimeType: 'image/jpeg',
                  data: base64Data,
                  isBinary: true
              });

              setIsCameraOpen(false); // Close camera after capture
              setTargetText('');
          }
      }
  };

  const handleProcess = async () => {
    if (!sourceText.trim() && !attachedFile) return;

    setIsLoading(true);
    let result = "";

    try {
        if (attachedFile) {
            // Document or Image Translation
            result = await translateDocument(
                { 
                    data: attachedFile.data, 
                    mimeType: attachedFile.mimeType, 
                    isBinary: attachedFile.isBinary 
                },
                sourceLang,
                targetLang,
                mode
            );
        } else {
            // Text Translation
            result = await translateText(sourceText, sourceLang, targetLang, mode);
        }
        setTargetText(result);
    } catch (e) {
        setTargetText("Error processing request. Please try again.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
      const file = event.target.files?.[0];
      if (file) {
          if (file.size > MAX_FILE_SIZE_BYTES) {
              alert(`File too large. Maximum size allowed is ${MAX_FILE_SIZE_MB}MB.`);
              return;
          }

          // Determine if we should treat as binary (PDF/Image) or text
          const isBinary = file.type === 'application/pdf' || file.type.startsWith('image/');

          const reader = new FileReader();

          reader.onload = (e) => {
              let content = e.target?.result as string;

              if (isBinary) {
                  // Strip Data URL prefix
                  content = content.split(',')[1];
              }

              setAttachedFile({
                  name: file.name,
                  mimeType: file.type || 'text/plain',
                  data: content,
                  isBinary: isBinary
              });
              setTargetText(''); // Clear previous result
          };

          reader.onerror = () => {
              alert("Error reading file.");
          };

          if (isBinary) {
              reader.readAsDataURL(file); // Read as base64 for PDF/Images
          } else {
              reader.readAsText(file); // Read as string for Text files
          }
      }
  };

  const handleRemoveFile = () => {
      setAttachedFile(null);
      setTargetText('');
  };

  const handleDownload = () => {
      if (!targetText) return;

      const element = document.createElement("a");
      const file = new Blob([targetText], {type: 'text/plain'});
      element.href = URL.createObjectURL(file);

      // Generate filename based on attached file or default
      let filename = "translation.txt";
      if (attachedFile) {
          const namePart = attachedFile.name.substring(0, attachedFile.name.lastIndexOf('.')) || attachedFile.name;
          filename = `${namePart}_translated.txt`;
      }

      element.download = filename;
      document.body.appendChild(element); // Required for this to work in FireFox
      element.click();
      document.body.removeChild(element);
  };

  const toggleListening = () => {
    if (isListening) {
        recognitionRef.current?.stop();
        setIsListening(false);
    } else {
        if (recognitionRef.current) {
            // Set language if not auto
            if (sourceLang !== 'auto') {
                recognitionRef.current.lang = sourceLang;
            } else {
                recognitionRef.current.lang = 'en-US'; // Default for auto
            }
            try {
                recognitionRef.current.start();
                setIsListening(true);
            } catch (e) {
                console.error("Failed to start recognition:", e);
                setIsListening(false);
            }
        } else {
            alert("Speech recognition not supported in this browser.");
        }
    }
  };

  const handleSpeak = async () => {
      if (!targetText) return;
      setIsPlaying(true);
      await speakText(targetText);
      setIsPlaying(false);
  };

  const handleSwap = () => {
    if (sourceLang === 'auto') return; // Can't swap auto
    const oldSource = sourceLang;
    setSourceLang(targetLang);
    setTargetLang(oldSource);

    if (!attachedFile) {
        setSourceText(targetText);
        setTargetText(sourceText);
    }
  };

  return (
    <div className="space-y-6">
      {/* Control Panel */}
      <div className="bg-gray-50 p-6 rounded-xl border border-gray-200 grid grid-cols-1 md:grid-cols-3 gap-6 shadow-sm">
        <div className="flex flex-col gap-2">
          <label className="text-sm font-semibold text-gray-900">Source Language</label>
          <select 
            value={sourceLang}
            onChange={(e) => setSourceLang(e.target.value)}
            className="p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white text-gray-900"
          >
            {SUPPORTED_LANGUAGES.map(l => (
              <option key={`src-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>

        <div className="flex flex-col gap-2 justify-center items-center">
            <button 
                onClick={handleSwap}
                className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                title="Swap Languages"
            >
                <i className="fas fa-exchange-alt"></i>
            </button>
        </div>

        <div className="flex flex-col gap-2">
          <label className="text-sm font-semibold text-gray-900">Target Language</label>
          <select 
            value={targetLang}
            onChange={(e) => setTargetLang(e.target.value)}
            className="p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white text-gray-900"
          >
            {SUPPORTED_LANGUAGES.filter(l => l.code !== 'auto').map(l => (
              <option key={`tgt-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Mode Toggle */}
      <div className="flex justify-center">
        <div className="bg-gray-200 p-1 rounded-full flex gap-1 relative">
             <button
                onClick={() => setMode(TranslationMode.TRANSLATE)}
                className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${mode === TranslationMode.TRANSLATE ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600 hover:text-gray-800'}`}
             >
                <i className="fas fa-language mr-2"></i> Translate
             </button>
             <button
                onClick={() => setMode(TranslationMode.TRANSLITERATE)}
                className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${mode === TranslationMode.TRANSLITERATE ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600 hover:text-gray-800'}`}
             >
                <i className="fas fa-font mr-2"></i> Transliterate
             </button>
        </div>
      </div>

      {/* Text Areas */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative">

        {/* Camera Modal Overlay */}
        {isCameraOpen && (
            <div className="absolute inset-0 z-50 bg-black/90 rounded-2xl flex flex-col items-center justify-center p-4">
                <div className="relative w-full max-w-sm aspect-[3/4] bg-black rounded-lg overflow-hidden border border-gray-600 shadow-2xl">
                    <video 
                        ref={videoRef} 
                        autoPlay 
                        playsInline 
                        className="w-full h-full object-cover"
                    />
                    <canvas ref={canvasRef} className="hidden" />
                </div>
                <div className="flex gap-4 mt-6">
                    <button 
                        onClick={() => setIsCameraOpen(false)}
                        className="px-6 py-3 rounded-full bg-gray-700 text-white font-bold hover:bg-gray-600 transition-colors"
                    >
                        Cancel
                    </button>
                    <button 
                        onClick={capturePhoto}
                        className="px-6 py-3 rounded-full bg-white text-black font-bold hover:bg-gray-200 transition-colors flex items-center gap-2"
                    >
                        <i className="fas fa-camera"></i> Capture
                    </button>
                </div>
            </div>
        )}

        {/* SOURCE AREA */}
        <div className="relative group">
            <div className="flex justify-between mb-2">
                <span className="text-sm font-semibold text-gray-600">Source</span>
                <div className="flex gap-2">
                    {/* Camera Button */}
                     <button
                        onClick={() => setIsCameraOpen(true)}
                        disabled={!!attachedFile}
                        className={`text-xs flex items-center gap-1 font-bold transition-colors ${attachedFile ? 'opacity-30 cursor-not-allowed' : 'text-gray-500 hover:text-indigo-600'}`}
                    >
                        <i className="fas fa-camera"></i> Camera
                    </button>

                    {/* File Upload Button */}
                     <label className={`cursor-pointer text-xs flex items-center gap-1 font-bold transition-colors ${attachedFile ? 'text-indigo-600' : 'text-gray-500 hover:text-indigo-600'}`} title="Attach PDF, Image or Text file">
                        <input type="file" className="hidden" accept=".pdf,.txt,.md,.csv,.json,image/*" onChange={handleFileUpload} />
                        <i className="fas fa-paperclip"></i>
                        {attachedFile ? ' Change File' : ' Attach'}
                    </label>

                    {/* Microphone Button */}
                    <button
                        onClick={toggleListening}
                        disabled={!!attachedFile}
                        className={`text-xs flex items-center gap-1 font-bold transition-colors ${isListening ? 'text-red-600 animate-pulse' : 'text-gray-500 hover:text-indigo-600'} ${attachedFile ? 'opacity-30 cursor-not-allowed' : ''}`}
                    >
                        <i className={`fas fa-microphone${isListening ? '' : '-slash'}`}></i>
                        {isListening ? ' Listening...' : ' Voice'}
                    </button>
                </div>
            </div>

            <div className="relative w-full h-80">
                {attachedFile ? (
                    <div className="absolute inset-0 z-10 bg-indigo-50 border-2 border-indigo-200 border-dashed rounded-2xl flex flex-col items-center justify-center p-6 text-center animate-fade-in">
                        <div className="bg-white p-4 rounded-full shadow-sm mb-3 text-indigo-600 text-2xl">
                             <i className={`fas ${attachedFile.mimeType.startsWith('image/') ? 'fa-image' : (attachedFile.isBinary ? 'fa-file-pdf' : 'fa-file-alt')}`}></i>
                        </div>
                        <h4 className="font-bold text-gray-900 break-all max-w-full mb-1">{attachedFile.name}</h4>
                        <p className="text-xs text-gray-500 mb-4">
                            {attachedFile.mimeType.startsWith('image/') ? 'Image Captured/Uploaded' : 'Document ready'}
                        </p>

                        {/* If it's an image, show a small preview */}
                        {attachedFile.mimeType.startsWith('image/') && (
                             <div className="w-20 h-20 mb-4 rounded-lg overflow-hidden border border-gray-300 shadow-sm">
                                 <img src={`data:${attachedFile.mimeType};base64,${attachedFile.data}`} alt="Preview" className="w-full h-full object-cover" />
                             </div>
                        )}

                        <div className="flex gap-2">
                             <button 
                                onClick={handleProcess}
                                disabled={isLoading}
                                className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-indigo-700 transition-colors shadow-sm"
                             >
                                {isLoading ? <i className="fas fa-spinner fa-spin"></i> : (attachedFile.mimeType.startsWith('image/') ? 'Analyze Image' : 'Translate Doc')}
                             </button>
                             <button 
                                onClick={handleRemoveFile}
                                className="bg-white text-red-500 border border-red-200 px-4 py-2 rounded-lg text-sm font-bold hover:bg-red-50 transition-colors"
                             >
                                Remove
                             </button>
                        </div>
                    </div>
                ) : (
                    <textarea
                        value={sourceText}
                        onChange={(e) => setSourceText(e.target.value)}
                        placeholder="Type text, use voice, attach a file, or use camera..."
                        className="w-full h-full p-5 rounded-2xl border border-gray-300 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none resize-none shadow-inner transition-all text-lg bg-white text-gray-900 placeholder-gray-400"
                    ></textarea>
                )}
            </div>
        </div>

        {/* TARGET AREA */}
        <div className="relative group">
            <div className="flex justify-between mb-2">
                <span className="text-sm font-semibold text-gray-600 flex items-center gap-2">
                    Result 
                    {isLoading && <i className="fas fa-spinner fa-spin text-indigo-500"></i>}
                </span>
                <div className="flex gap-3">
                     {/* Download Button */}
                     <button
                        onClick={handleDownload}
                        disabled={!targetText}
                        className={`text-xs font-bold transition-colors flex items-center gap-1 ${targetText ? 'text-indigo-600 hover:text-indigo-800' : 'text-gray-300 cursor-not-allowed'}`}
                        title="Download Result as Text File"
                     >
                        <i className="fas fa-download"></i> Download
                     </button>

                     <button 
                        onClick={handleSpeak}
                        disabled={!targetText || isPlaying}
                        className={`text-xs font-bold transition-colors flex items-center gap-1 ${isPlaying ? 'text-green-600' : 'text-gray-500 hover:text-indigo-600'}`}
                     >
                        <i className={`fas fa-volume-${isPlaying ? 'up' : 'off'}`}></i>
                        {isPlaying ? ' Playing...' : ' Listen'}
                     </button>
                     <button 
                        onClick={() => navigator.clipboard.writeText(targetText)}
                        className="text-xs text-indigo-600 hover:text-indigo-800 font-medium"
                     >
                        <i className="fas fa-copy mr-1"></i> Copy
                     </button>
                </div>
            </div>
            <textarea
                readOnly
                value={targetText}
                placeholder={isLoading ? "Processing..." : "Result will appear here..."}
                className="w-full h-80 p-5 rounded-2xl border border-gray-300 bg-white text-gray-900 placeholder-gray-400 resize-none shadow-sm focus:outline-none text-lg"
            ></textarea>
        </div>
      </div>

      {/* Footer Info */}
      <div className="text-center text-xs text-gray-400">
         Powered by Gemini Neural Engine • Tier 1 Cloud Inference
      </div>
    </div>
  );
};

export default Translator;

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, UploadedFile } from '../types';
import { chatHybrid, speakText, analyzeDocument } from '../services/geminiService';

// Polyfill type for SpeechRecognition
declare global {
    interface Window {
        webkitSpeechRecognition: any;
        SpeechRecognition: any;
    }
}

const MAX_FILE_SIZE_MB = 10;
const MAX_FILE_SIZE_BYTES = MAX_FILE_SIZE_MB * 1024 * 1024;

const IntelligentChat: React.FC = () => {
  // State
  const [messages, setMessages] = useState<ChatMessage[]>([
      {
          id: 'intro',
          role: 'model',
          content: "Hello! I am NeuroLingua AI. You can ask me general questions (I can search the web) or upload a document (PDF or Text) to activate 'Truth Guard' mode for specific analysis. How can I help?",
          timestamp: Date.now()
      }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [file, setFile] = useState<UploadedFile | null>(null);

  // Link State
  const [links, setLinks] = useState<string[]>([]);
  const [isLinkInputOpen, setIsLinkInputOpen] = useState(false);
  const [linkInput, setLinkInput] = useState('');

  // Voice State
  const [isListening, setIsListening] = useState(false);
  const [playingMsgId, setPlayingMsgId] = useState<string | null>(null);

  const chatEndRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // --- Voice Input Setup ---
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = false;
            recognitionRef.current.lang = 'en-US';

            recognitionRef.current.onresult = (event: any) => {
                const transcript = event.results[0][0].transcript;
                setInputValue(prev => prev + (prev ? ' ' : '') + transcript);
                setIsListening(false);
            };

            recognitionRef.current.onerror = (event: any) => {
                console.error("Speech Error:", event.error);
                setIsListening(false);
            };

            recognitionRef.current.onend = () => {
                setIsListening(false);
            };
        } catch (e) {
            console.error("Speech Setup Failed", e);
        }
    }
  }, []);

  const toggleListening = () => {
      if (isListening) {
          recognitionRef.current?.stop();
          setIsListening(false);
      } else {
          recognitionRef.current?.start();
          setIsListening(true);
      }
  };

  const handleSpeakMessage = async (msgId: string, text: string) => {
      if (playingMsgId) return; // Prevent overlapping
      setPlayingMsgId(msgId);
      await speakText(text);
      setPlayingMsgId(null);
  };

  // --- File Handling ---
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const uploadedFile = event.target.files?.[0];
    if (uploadedFile) {
        if (uploadedFile.size > MAX_FILE_SIZE_BYTES) {
            alert(`File too large. Maximum size allowed is ${MAX_FILE_SIZE_MB}MB.`);
            return;
        }

        const isPdf = uploadedFile.type === 'application/pdf' || uploadedFile.name.toLowerCase().endsWith('.pdf');

        const reader = new FileReader();
        reader.onload = async (e) => {
            let content = e.target?.result as string;

            if (isPdf) {
                 // Strip Data URL prefix for PDF
                 content = content.split(',')[1];
            }

            setFile({
                name: uploadedFile.name,
                mimeType: isPdf ? 'application/pdf' : (uploadedFile.type || 'text/plain'),
                isBinary: isPdf,
                size: uploadedFile.size,
                content: content
            });
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'model',
                content: `✅ I have ingested **${uploadedFile.name}**. \nTruth Guard™ mode is active. I will answer based on this document.`,
                timestamp: Date.now()
            }]);
        };

        reader.onerror = () => {
             alert("Error reading file.");
        };

        if (isPdf) {
            reader.readAsDataURL(uploadedFile);
        } else {
            reader.readAsText(uploadedFile);
        }
    }
  };

  const handleRemoveFile = () => {
      setFile(null);
      setMessages(prev => [...prev, {
          id: Date.now().toString(),
          role: 'model',
          content: "Document removed. Returning to General Intelligence (Web Search) mode.",
          timestamp: Date.now()
      }]);
  };

  // --- Link Handling ---
  const handleAddLink = () => {
      if (linkInput.trim()) {
          // Basic URL validation
          let url = linkInput.trim();
          if (!url.startsWith('http://') && !url.startsWith('https://')) {
              url = 'https://' + url;
          }
          setLinks(prev => [...prev, url]);
          setLinkInput('');
          setIsLinkInputOpen(false);
      }
  };

  const handleRemoveLink = (indexToRemove: number) => {
      setLinks(prev => prev.filter((_, idx) => idx !== indexToRemove));
  };

  const runQuickAction = async (action: 'summary' | 'questions' | 'keywords') => {
      if (!file) return;
      setIsProcessing(true);
      try {
          // For binary files, we need to pass a special prompt to analyzeDocument or handle it there
          // Currently analyzeDocument expects string content. 
          // We will update analyzeDocument signature in service to match.
          const res = await analyzeDocument(file, action);

          const botMsg: ChatMessage = {
            id: Date.now().toString(),
            role: 'model',
            content: `**${action.toUpperCase()}**: \n${res}`,
            timestamp: Date.now()
          };
          setMessages(prev => [...prev, botMsg]);
      } catch (e) {
          alert("Failed to analyze document.");
      } finally {
          setIsProcessing(false);
      }
  };

  // --- Chat Logic ---
  const handleSendMessage = async () => {
    if (!inputValue.trim()) return;

    const userMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'user',
        content: inputValue,
        timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsProcessing(true);

    try {
        // Format history for Gemini
        // We only pass text history here. The binary context is injected in the service based on 'file' prop.
        const history = messages.map(m => ({
            role: m.role,
            parts: [{ text: m.content }]
        }));

        // Pass links along with query
        const result = await chatHybrid(userMsg.content, history, file || undefined, links);

        const botMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: 'model',
            content: result.text,
            timestamp: Date.now(),
            sources: result.sources
        };

        setMessages(prev => [...prev, botMsg]);
    } catch (e) {
        setMessages(prev => [...prev, {
            id: (Date.now() + 1).toString(),
            role: 'model',
            content: "I encountered an error while processing your request.",
            timestamp: Date.now()
        }]);
    } finally {
        setIsProcessing(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 h-[600px]">

        {/* Sidebar (Only shows when file attached) */}
        {file && (
            <div className="lg:col-span-1 space-y-4 animate-fade-in">
                <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-200 shadow-sm">
                    <div className="flex items-center gap-3 mb-2">
                        <div className="bg-indigo-600 text-white p-2 rounded-lg">
                            <i className={`fas ${file.isBinary ? 'fa-file-pdf' : 'fa-file-alt'}`}></i>
                        </div>
                        <div className="overflow-hidden">
                            <h4 className="font-bold text-sm truncate text-indigo-900">{file.name}</h4>
                            <p className="text-xs text-indigo-500">Truth Guard™ Active</p>
                        </div>
                    </div>
                    <button 
                        onClick={handleRemoveFile}
                        className="text-xs text-red-500 hover:text-red-700 w-full text-left mt-2 font-medium"
                    >
                        <i className="fas fa-times-circle mr-1"></i> Disconnect File
                    </button>
                </div>

                <div className="bg-white border border-gray-200 p-4 rounded-xl shadow-sm">
                    <h4 className="font-bold text-xs text-gray-400 mb-3 uppercase tracking-wider">Document Actions</h4>
                    <div className="space-y-2">
                        <button onClick={() => runQuickAction('summary')} className="w-full text-left px-3 py-2 hover:bg-gray-100 rounded-lg text-sm text-gray-900 transition-colors">
                            <i className="fas fa-list-ul mr-2 text-indigo-500"></i> Summarize
                        </button>
                        <button onClick={() => runQuickAction('questions')} className="w-full text-left px-3 py-2 hover:bg-gray-100 rounded-lg text-sm text-gray-900 transition-colors">
                            <i className="fas fa-question-circle mr-2 text-indigo-500"></i> Gen. Questions
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Chat Area */}
        <div className={`${file ? 'lg:col-span-3' : 'lg:col-span-4'} flex flex-col bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden transition-all duration-300`}>

            {/* Header */}
            <div className="bg-white border-b border-gray-100 p-4 flex justify-between items-center">
                 <div className="flex items-center gap-3">
                     <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white shadow-lg ${file ? 'bg-indigo-600' : 'bg-gradient-to-br from-cyan-400 to-blue-600'}`}>
                         <i className={`fas ${file ? 'fa-shield-alt' : 'fa-robot'}`}></i>
                     </div>
                     <div>
                         <h3 className="font-bold text-gray-800">{file ? 'Truth Guard™' : 'NeuroLingua AI'}</h3>
                         <p className="text-xs text-gray-500">
                            {file ? 'RAG Mode • Strictly Contextual' : 'General Mode • Web Search Enabled'}
                         </p>
                     </div>
                 </div>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-gray-50/30">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                        <div className={`max-w-[85%] rounded-2xl p-4 shadow-sm relative group ${
                            msg.role === 'user' 
                                ? 'bg-indigo-600 text-white rounded-tr-none' 
                                : 'bg-white border border-gray-200 text-gray-900 rounded-tl-none'
                        }`}>
                            <div className="whitespace-pre-wrap text-sm leading-relaxed">{msg.content}</div>

                            {/* Sources (if any) */}
                            {msg.sources && msg.sources.length > 0 && (
                                <div className="mt-3 pt-3 border-t border-gray-100">
                                    <p className="text-xs font-bold text-gray-400 mb-1">Sources:</p>
                                    <div className="flex flex-wrap gap-2">
                                        {msg.sources.map((src, idx) => (
                                            <a key={idx} href={src.uri} target="_blank" rel="noopener noreferrer" className="text-xs bg-blue-50 text-blue-600 px-2 py-1 rounded hover:bg-blue-100 truncate max-w-[200px] block">
                                                {src.title}
                                            </a>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* Speaker Button */}
                            <button 
                                onClick={() => handleSpeakMessage(msg.id, msg.content)}
                                className={`absolute -bottom-8 ${msg.role === 'user' ? 'right-0' : 'left-0'} text-gray-400 hover:text-indigo-600 text-xs p-1 opacity-0 group-hover:opacity-100 transition-opacity`}
                            >
                                <i className={`fas ${playingMsgId === msg.id ? 'fa-volume-up animate-pulse text-indigo-600' : 'fa-volume-off'}`}></i>
                                {playingMsgId === msg.id ? ' Playing...' : ' Read'}
                            </button>
                        </div>
                    </div>
                ))}
                <div ref={chatEndRef} />
            </div>

            {/* Input Area */}
            <div className="p-4 bg-white border-t border-gray-100 relative">

                {/* Active Links Chips */}
                {links.length > 0 && (
                    <div className="flex flex-wrap gap-2 mb-3 px-1">
                        {links.map((link, idx) => (
                            <div key={idx} className="flex items-center gap-1 bg-blue-50 text-blue-600 text-xs font-medium px-2 py-1 rounded-md border border-blue-100 max-w-[200px]">
                                <i className="fas fa-link text-[10px]"></i>
                                <span className="truncate">{link}</span>
                                <button onClick={() => handleRemoveLink(idx)} className="ml-1 text-blue-400 hover:text-red-500">
                                    <i className="fas fa-times"></i>
                                </button>
                            </div>
                        ))}
                    </div>
                )}

                {/* Link Input Popover */}
                {isLinkInputOpen && (
                    <div className="absolute bottom-20 left-4 z-20 bg-white p-3 rounded-xl shadow-xl border border-gray-200 w-72 animate-fade-in">
                        <h5 className="text-xs font-bold text-gray-600 mb-2">Add Reference Link</h5>
                        <div className="flex gap-2">
                            <input 
                                type="text" 
                                value={linkInput}
                                onChange={(e) => setLinkInput(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && handleAddLink()}
                                placeholder="https://example.com"
                                className="flex-1 text-sm border border-gray-300 rounded-lg px-2 py-1 focus:outline-none focus:border-indigo-500 text-gray-900 bg-white"
                                autoFocus
                            />
                            <button onClick={handleAddLink} className="bg-indigo-600 text-white px-2 rounded-lg text-xs hover:bg-indigo-700">Add</button>
                        </div>
                        <button onClick={() => setIsLinkInputOpen(false)} className="text-xs text-gray-400 mt-2 hover:text-gray-600 underline">Cancel</button>
                    </div>
                )}

                <div className="flex gap-2 relative items-center">

                    {/* Link Button */}
                    <button 
                         onClick={() => setIsLinkInputOpen(!isLinkInputOpen)}
                         className={`p-3 rounded-full transition-colors ${links.length > 0 ? 'text-blue-600 bg-blue-50' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'}`}
                         title="Add Reference URL"
                    >
                         <i className="fas fa-link text-lg"></i>
                    </button>

                    {/* File Upload Button */}
                    <label className={`cursor-pointer p-3 rounded-full transition-colors ${file ? 'text-indigo-600 bg-indigo-50' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'}`} title="Upload Document (PDF/Text) for Truth Guard">
                        <input type="file" className="hidden" accept=".pdf,.txt,.md,.json,.csv" onChange={handleFileUpload} disabled={!!file} />
                        <i className="fas fa-paperclip text-lg"></i>
                    </label>

                    {/* Microphone Button */}
                    <button 
                        onClick={toggleListening}
                        className={`p-3 rounded-full transition-colors ${isListening ? 'bg-red-100 text-red-600 animate-pulse' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'}`}
                        title="Voice Input"
                    >
                        <i className={`fas fa-microphone${isListening ? '' : '-slash'} text-lg`}></i>
                    </button>

                    <input
                        type="text"
                        value={inputValue}
                        onChange={(e) => setInputValue(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                        disabled={isProcessing}
                        placeholder={isListening ? "Listening..." : (file ? "Ask Truth Guard about the file..." : "Ask anything (Web Search enabled)...")}
                        className="flex-1 p-3 pl-4 rounded-xl border border-gray-300 focus:outline-none focus:border-indigo-500 focus:ring-2 focus:ring-indigo-200 transition-all bg-white text-gray-900 placeholder-gray-400"
                    />

                    <button 
                        onClick={handleSendMessage}
                        disabled={isProcessing || !inputValue.trim()}
                        className="bg-indigo-600 text-white w-12 h-12 rounded-xl hover:bg-indigo-700 disabled:bg-gray-300 disabled:cursor-not-allowed transition-all shadow-md flex items-center justify-center"
                    >
                        {isProcessing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-paper-plane"></i>}
                    </button>
                </div>
            </div>
        </div>
    </div>
  );
};

export default IntelligentChat;

import React, { Component, ErrorInfo, ReactNode } from "react";

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error?: Error;
}

class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false
  };

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[400px] p-8 text-center bg-white rounded-3xl shadow-xl">
            <div className="bg-red-100 p-6 rounded-full text-red-600 text-4xl mb-4">
                <i className="fas fa-exclamation-triangle"></i>
            </div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">Something went wrong</h2>
            <p className="text-gray-500 mb-6 max-w-md">
                We encountered an unexpected error. This might be due to a connectivity issue or a temporary glitch.
            </p>
            <div className="bg-gray-100 p-4 rounded-lg mb-6 text-left w-full max-w-lg overflow-auto text-xs text-red-500 font-mono border border-red-200">
                {this.state.error?.toString()}
            </div>
            <button
                onClick={() => window.location.reload()}
                className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-indigo-700 transition-colors"
            >
                Reload Application
            </button>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

