  // --- File Handling ---
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const uploadedFile = event.target.files?.[0];
    if (uploadedFile) {
        // Tier Checks
        if (uploadedFile.size > tierConfig.maxFileSizeMB * 1024 * 1024) {
            alert(`File too large for ${currentTier} tier. Max size is ${tierConfig.maxFileSizeMB}MB. Please upgrade.`);
            return;
        }

        // Mime Type Check
        const isPdf = uploadedFile.type === 'application/pdf' || uploadedFile.name.toLowerCase().endsWith('.pdf');

        if (!isPdf && !tierConfig.allowedMimeTypes.includes(uploadedFile.type)) {
             alert(`This file type is not allowed in ${currentTier} tier. Allowed: ${tierConfig.allowedMimeTypes.join(', ')}`);
             return;
        }

        const reader = new FileReader();
        reader.onload = async (e) => {
            let content = e.target?.result as string;

            if (isPdf) {
                 content = content.split(',')[1];
            }

            setFile({
                name: uploadedFile.name,
                mimeType: isPdf ? 'application/pdf' : (uploadedFile.type || 'text/plain'),
                isBinary: isPdf,
                size: uploadedFile.size,
                content: content
            });
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'model',
                content: `✅ I have ingested **${uploadedFile.name}**. \nTruth Guard™ mode is active. I will answer based on this document.`,
                timestamp: Date.now()
            }]);
        };

        reader.onerror = () => {
             alert("Error reading file.");
        };

        if (isPdf) {
            reader.readAsDataURL(uploadedFile);
        } else {
            reader.readAsText(uploadedFile);
        }
    }
  };

  const handleRemoveFile = () => {
      setFile(null);
      setMessages(prev => [...prev, {
