                                    </div>
                                </div>
                            )}
                        </div>

                        {/* Text Input */}
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                            disabled={isProcessing}
                            placeholder={isListening ? "Listening..." : "Message NeuroLingua..."}
                            className="flex-1 bg-transparent border-none focus:ring-0 text-sm text-gray-800 placeholder-gray-400 px-2"
                        />

                        {/* Mic */}
                        <button 
                            onClick={toggleListening}
                            className={`w-10 h-10 flex items-center justify-center rounded-full transition-all ${isListening ? 'bg-red-50 text-red-500 animate-pulse' : 'text-gray-400 hover:bg-gray-100 hover:text-indigo-600'}`}
                        >
                            <i className={`fas fa-microphone${isListening ? '' : '-slash'}`}></i>
                        </button>

                        {/* Send */}
                        <button 
                            onClick={handleSendMessage}
                            disabled={isProcessing || !inputValue.trim()}
                            className="w-10 h-10 flex items-center justify-center rounded-full bg-indigo-600 text-white shadow-md hover:bg-indigo-700 hover:shadow-lg disabled:opacity-50 disabled:shadow-none transition-all transform hover:scale-105"
                        >
                            {isProcessing ? <i className="fas fa-circle-notch fa-spin text-xs"></i> : <i className="fas fa-arrow-up text-sm"></i>}
                        </button>
                    </div>
                </div>
            </div>

            {/* Document Quick Actions (Visible if file loaded) */}
            {file && (
                <div className="w-full lg:w-64 flex flex-col gap-3 animate-fade-in">
                    <div className="bg-white/60 p-4 rounded-3xl border border-white/60 shadow-sm h-full">
                        <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-4">Quick Analysis</h4>
                        <div className="flex flex-col gap-2">
                             <button onClick={() => runQuickAction('summary')} className="flex items-center gap-3 w-full text-left px-4 py-3 bg-white hover:bg-indigo-50 border border-gray-100 rounded-xl text-sm font-medium text-gray-700 transition-all hover:shadow-sm group">
                                <div className="w-8 h-8 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                                    <i className="fas fa-list-ul text-xs"></i>
                                </div>
                                Summarize
                            </button>
                            <button onClick={() => runQuickAction('questions')} className="flex items-center gap-3 w-full text-left px-4 py-3 bg-white hover:bg-indigo-50 border border-gray-100 rounded-xl text-sm font-medium text-gray-700 transition-all hover:shadow-sm group">
                                <div className="w-8 h-8 rounded-full bg-purple-100 text-purple-600 flex items-center justify-center group-hover:bg-purple-600 group-hover:text-white transition-colors">
                                    <i className="fas fa-question text-xs"></i>
                                </div>
                                Suggest Q's
                            </button>
                             <button onClick={() => runQuickAction('keywords')} className="flex items-center gap-3 w-full text-left px-4 py-3 bg-white hover:bg-indigo-50 border border-gray-100 rounded-xl text-sm font-medium text-gray-700 transition-all hover:shadow-sm group">
                                <div className="w-8 h-8 rounded-full bg-emerald-100 text-emerald-600 flex items-center justify-center group-hover:bg-emerald-600 group-hover:text-white transition-colors">
                                    <i className="fas fa-key text-xs"></i>
                                </div>
                                Keywords
                            </button>
                        </div>

                        <div className="mt-6 p-3 bg-blue-50 rounded-xl border border-blue-100">
                            <div className="flex items-start gap-2">
                                <i className="fas fa-info-circle text-blue-500 mt-0.5"></i>
                                <p className="text-[10px] text-blue-700 leading-tight">
                                    Truth Guard™ is enforcing strict adherence to <strong>{file.name}</strong>. External knowledge is limited to prevent hallucinations.
                                </p>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    </div>
  );
};

export default IntelligentChat;

import React, { useState, useEffect, useRef } from 'react';
import { TranslationMode, SUPPORTED_LANGUAGES, Tier } from '../types';
import { translateText, translateDocument, speakText } from '../services/geminiService';
import { useTier } from '../contexts/TierContext';

// Polyfill type for SpeechRecognition
declare global {
    interface Window {
        webkitSpeechRecognition: any;
        SpeechRecognition: any;
    }
}

interface AttachedFile {
    name: string;
    mimeType: string;
    data: string; // Base64 (for binary) OR Raw Text (for text files)
    isBinary: boolean;
}

const Translator: React.FC = () => {
  const { tierConfig, currentTier } = useTier();

  const [sourceText, setSourceText] = useState('');
  const [targetText, setTargetText] = useState('');
  const [sourceLang, setSourceLang] = useState('auto');
  const [targetLang, setTargetLang] = useState('es');
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TRANSLATE);
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);

  // Camera State
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const recognitionRef = useRef<any>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = false;

            recognitionRef.current.onresult = (event: any) => {
                const transcript = event.results[0][0].transcript;
                setSourceText(transcript);
                setIsListening(false);
            };

            recognitionRef.current.onerror = (event: any) => {
                setIsListening(false);
            };

            recognitionRef.current.onend = () => {
                setIsListening(false);
            };
        } catch (e) {
            console.error("Speech Recognition setup failed:", e);
        }
    }
  }, []);

  // Debounce translation trigger for text (not file)
  useEffect(() => {
    const timer = setTimeout(() => {
      if (sourceText.length > 1 && !attachedFile) { // Only auto-process text if no file attached
        handleProcess();
      }
    }, 1000);

    return () => clearTimeout(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [sourceText, sourceLang, targetLang, mode]);

  // Handle Camera Stream
  useEffect(() => {
    let stream: MediaStream | null = null;

    const startCamera = async () => {
        try {
            stream = await navigator.mediaDevices.getUserMedia({ 
                video: { facingMode: 'environment' } // Prefer back camera on mobile
            });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }
        } catch (err) {
            console.error("Error accessing camera:", err);
            alert("Could not access camera. Please check permissions.");
            setIsCameraOpen(false);
        }
    };

    if (isCameraOpen) {
        startCamera();
    }

    return () => {
        if (stream) {
            stream.getTracks().forEach(track => track.stop());
        }
    };
  }, [isCameraOpen]);

  const capturePhoto = () => {
      if (videoRef.current && canvasRef.current) {
          const video = videoRef.current;
          const canvas = canvasRef.current;

          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;

          const ctx = canvas.getContext('2d');
          if (ctx) {
              ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
              // Get Base64 image
              const dataUrl = canvas.toDataURL('image/jpeg');
              // Remove header for API
              const base64Data = dataUrl.split(',')[1];

              setAttachedFile({
                  name: `capture_${Date.now()}.jpg`,
                  mimeType: 'image/jpeg',
                  data: base64Data,
                  isBinary: true
              });

              setIsCameraOpen(false); // Close camera after capture
              setTargetText('');
          }
      }
  };

  const handleProcess = async () => {
    if (!sourceText.trim() && !attachedFile) return;

    setIsLoading(true);
    let result = "";

    try {
        if (attachedFile) {
            // Document or Image Translation
            result = await translateDocument(
                { 
                    data: attachedFile.data, 
                    mimeType: attachedFile.mimeType, 
                    isBinary: attachedFile.isBinary 
                },
                sourceLang,
                targetLang,
                mode
            );
        } else {
            // Text Translation
            result = await translateText(sourceText, sourceLang, targetLang, mode);
        }
        setTargetText(result);
    } catch (e) {
        setTargetText("Error processing request. Please try again.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
      const file = event.target.files?.[0];
      if (file) {
          // Tier Checks
          if (file.size > tierConfig.maxFileSizeMB * 1024 * 1024) {
              alert(`File too large for ${currentTier} tier. Max size is ${tierConfig.maxFileSizeMB}MB. Please upgrade.`);
              return;
          }

          if (!tierConfig.allowedMimeTypes.includes(file.type) && !file.name.endsWith('.pdf')) {
               if (file.type !== '' || !file.name.toLowerCase().endsWith('.pdf')) {
                   alert(`This file type is not allowed in ${currentTier} tier.`);
                   return;
               }
          }

          const isBinary = file.type === 'application/pdf' || file.type.startsWith('image/') || file.name.toLowerCase().endsWith('.pdf');

          const reader = new FileReader();
          reader.onload = (e) => {
              let content = e.target?.result as string;
              if (isBinary) content = content.split(',')[1];

              setAttachedFile({
                  name: file.name,
                  mimeType: file.type || 'text/plain',
                  data: content,
                  isBinary: isBinary
              });
              setTargetText(''); 
          };
          if (isBinary) reader.readAsDataURL(file);
          else reader.readAsText(file);
      }
  };

  const handleRemoveFile = () => {
      setAttachedFile(null);
      setTargetText('');
  };

  const handleDownload = () => {
      if (!targetText) return;
      const element = document.createElement("a");
      const file = new Blob([targetText], {type: 'text/plain'});
      element.href = URL.createObjectURL(file);

      let filename = "translation.txt";
      if (attachedFile) {
          const namePart = attachedFile.name.substring(0, attachedFile.name.lastIndexOf('.')) || attachedFile.name;
          filename = `${namePart}_translated.txt`;
      }

      element.download = filename;
      document.body.appendChild(element); 
      element.click();
      document.body.removeChild(element);
  };

  const toggleListening = () => {
    if (isListening) {
        recognitionRef.current?.stop();
        setIsListening(false);
    } else {
        if (recognitionRef.current) {
            if (sourceLang !== 'auto') recognitionRef.current.lang = sourceLang;
            else recognitionRef.current.lang = 'en-US'; 
            try {
                recognitionRef.current.start();
                setIsListening(true);
            } catch (e) {
                setIsListening(false);
            }
        }
    }
  };

  const handleSpeak = async () => {
      if (!targetText) return;
      setIsPlaying(true);
      await speakText(targetText);
      setIsPlaying(false);
  };

  const handleSwap = () => {
    if (sourceLang === 'auto') return; 
    const oldSource = sourceLang;
    setSourceLang(targetLang);
    setTargetLang(oldSource);

    if (!attachedFile) {
        setSourceText(targetText);
        setTargetText(sourceText);
    }
  };

  const getButtonLabel = () => {
      if (attachedFile?.mimeType.startsWith('image/')) return 'Analyze Image';
      return mode === TranslationMode.TRANSLITERATE ? 'Transliterate Doc' : 'Translate Doc';
  };

  return (
    <div className="flex flex-col h-full gap-4">
      {/* Control Bar */}
      <div className="bg-white/60 p-4 rounded-3xl border border-gray-100 shadow-sm grid grid-cols-1 md:grid-cols-12 gap-4 items-center">

        {/* Source Lang */}
        <div className="md:col-span-4 flex flex-col gap-1">
          <label className="text-[10px] font-bold uppercase text-gray-400 tracking-wider">Source</label>
          <div className="relative">
              <select 
                value={sourceLang}
                onChange={(e) => setSourceLang(e.target.value)}
                className="w-full p-2.5 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none text-sm font-semibold appearance-none"
              >
                {SUPPORTED_LANGUAGES.map(l => (
                  <option key={`src-${l.code}`} value={l.code}>{l.name}</option>
                ))}
              </select>
              <i className="fas fa-chevron-down absolute right-3 top-3.5 text-gray-400 text-xs pointer-events-none"></i>
          </div>
        </div>

        {/* Swap Button */}
        <div className="md:col-span-1 flex justify-center">
             <button 
                onClick={handleSwap}
                className="w-10 h-10 rounded-full bg-indigo-50 text-indigo-500 hover:bg-indigo-500 hover:text-white transition-all shadow-sm flex items-center justify-center"
                title="Swap Languages"
            >
                <i className="fas fa-exchange-alt"></i>
            </button>
        </div>

        {/* Target Lang */}
        <div className="md:col-span-4 flex flex-col gap-1">
          <label className="text-[10px] font-bold uppercase text-gray-400 tracking-wider">Target</label>
          <div className="relative">
            <select 
                value={targetLang}
                onChange={(e) => setTargetLang(e.target.value)}
                className="w-full p-2.5 bg-white border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none text-sm font-semibold appearance-none"
            >
                {SUPPORTED_LANGUAGES.filter(l => l.code !== 'auto').map(l => (
                <option key={`tgt-${l.code}`} value={l.code}>{l.name}</option>
                ))}
            </select>
            <i className="fas fa-chevron-down absolute right-3 top-3.5 text-gray-400 text-xs pointer-events-none"></i>
          </div>
        </div>

        {/* Mode Toggle */}
        <div className="md:col-span-3 flex justify-end">
            <div className="bg-gray-100 p-1 rounded-xl flex w-full">
                <button
                    onClick={() => setMode(TranslationMode.TRANSLATE)}
                    className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${mode === TranslationMode.TRANSLATE ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-400'}`}
                >
                    Translate
                </button>
                <button
                    onClick={() => setMode(TranslationMode.TRANSLITERATE)}
                    className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${mode === TranslationMode.TRANSLITERATE ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-400'}`}
                >
                    Script
                </button>
            </div>
        </div>
      </div>

      {/* Editor Area */}
      <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-4 min-h-0">

        {/* Camera Modal Overlay */}
        {isCameraOpen && (
            <div className="fixed inset-0 z-50 bg-black/90 backdrop-blur-sm flex flex-col items-center justify-center p-4">
                <div className="relative w-full max-w-sm aspect-[3/4] bg-black rounded-2xl overflow-hidden border border-white/20 shadow-2xl">
                    <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover"/>
                    <canvas ref={canvasRef} className="hidden" />
                </div>
                <div className="flex gap-6 mt-8">
                    <button onClick={() => setIsCameraOpen(false)} className="w-16 h-16 rounded-full bg-gray-800 text-white flex items-center justify-center hover:bg-gray-700 transition-colors">
                        <i className="fas fa-times text-xl"></i>
                    </button>
                    <button onClick={capturePhoto} className="w-20 h-20 rounded-full bg-white border-4 border-gray-300 flex items-center justify-center hover:scale-105 transition-transform">
                        <div className="w-16 h-16 rounded-full bg-white border-2 border-black"></div>
                    </button>
                </div>
            </div>
        )}

        {/* Source */}
        <div className="relative flex flex-col h-full bg-white/40 border border-white/60 rounded-3xl p-4 shadow-sm backdrop-blur-sm focus-within:ring-2 focus-within:ring-indigo-100 transition-shadow">
            <div className="flex justify-between items-center mb-2 px-2">
                <div className="flex gap-2">
                     <button
                        onClick={() => setIsCameraOpen(true)}
                        disabled={!!attachedFile}
                        className={`w-8 h-8 rounded-lg flex items-center justify-center transition-colors ${attachedFile ? 'opacity-30' : 'bg-white text-gray-500 hover:text-indigo-600 shadow-sm'}`}
                        title="Camera"
                    >
                        <i className="fas fa-camera"></i>
                    </button>
                    <label className={`w-8 h-8 rounded-lg flex items-center justify-center cursor-pointer transition-colors ${attachedFile ? 'bg-indigo-100 text-indigo-600' : 'bg-white text-gray-500 hover:text-indigo-600 shadow-sm'}`}>
                        <input type="file" className="hidden" accept={tierConfig.allowedMimeTypes.join(',')} onChange={handleFileUpload} />
                        <i className="fas fa-paperclip"></i>
                    </label>
                    <button
                        onClick={toggleListening}
                        disabled={!!attachedFile}
                        className={`w-8 h-8 rounded-lg flex items-center justify-center transition-colors ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-gray-500 hover:text-indigo-600 shadow-sm'} ${attachedFile ? 'opacity-30' : ''}`}
                    >
                        <i className={`fas fa-microphone${isListening ? '' : '-slash'}`}></i>
                    </button>
                </div>
            </div>

            <div className="flex-1 relative rounded-2xl overflow-hidden bg-white/50 border border-gray-100">
                {attachedFile ? (
                    <div className="absolute inset-0 flex flex-col items-center justify-center p-6 text-center">
                        <div className="w-16 h-16 bg-indigo-100 rounded-2xl flex items-center justify-center mb-4 text-indigo-600 text-2xl shadow-inner">
                             <i className={`fas ${attachedFile.mimeType.startsWith('image/') ? 'fa-image' : (attachedFile.isBinary ? 'fa-file-pdf' : 'fa-file-alt')}`}></i>
                        </div>
                        <h4 className="font-bold text-gray-800 break-all max-w-full mb-1">{attachedFile.name}</h4>
                        <p className="text-xs text-gray-500 mb-6">
                            {attachedFile.mimeType.startsWith('image/') ? 'Image Ready' : 'Document Ready'}
                        </p>

                        {attachedFile.mimeType.startsWith('image/') && (
                             <div className="w-24 h-24 mb-6 rounded-xl overflow-hidden border border-gray-200 shadow-sm">
                                 <img src={`data:${attachedFile.mimeType};base64,${attachedFile.data}`} alt="Preview" className="w-full h-full object-cover" />
                             </div>
                        )}

                        <div className="flex gap-3">
                             <button 
                                onClick={handleProcess}
                                disabled={isLoading}
                                className="bg-indigo-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
                             >
                                {isLoading ? <i className="fas fa-circle-notch fa-spin"></i> : getButtonLabel()}
                             </button>
                             <button 
                                onClick={handleRemoveFile}
                                className="text-red-500 px-4 py-2.5 rounded-xl text-sm font-bold hover:bg-red-50 transition-colors"
                             >
                                Clear
                             </button>
                        </div>
                    </div>
                ) : (
                    <textarea
                        value={sourceText}
                        onChange={(e) => setSourceText(e.target.value)}
                        placeholder="Type to translate..."
                        className="w-full h-full p-4 bg-transparent outline-none resize-none text-lg text-gray-700 placeholder-gray-400"
                    ></textarea>
                )}
            </div>
        </div>

        {/* Target */}
        <div className="relative flex flex-col h-full bg-white/40 border border-white/60 rounded-3xl p-4 shadow-sm backdrop-blur-sm">
             <div className="flex justify-between items-center mb-2 px-2">
                <span className="text-[10px] font-bold uppercase text-gray-400 tracking-wider">Result</span>
                <div className="flex gap-2">
                     <button
                        onClick={handleDownload}
                        disabled={!targetText}
                        className={`w-8 h-8 rounded-lg flex items-center justify-center transition-colors ${targetText ? 'bg-white text-gray-500 hover:text-indigo-600 shadow-sm' : 'opacity-30'}`}
                     >
                        <i className="fas fa-download"></i>
                     </button>
                     <button 
                        onClick={handleSpeak}
                        disabled={!targetText || isPlaying}
                        className={`w-8 h-8 rounded-lg flex items-center justify-center transition-colors ${isPlaying ? 'bg-indigo-100 text-indigo-600' : 'bg-white text-gray-500 hover:text-indigo-600 shadow-sm'}`}
                     >
                        <i className={`fas fa-volume-${isPlaying ? 'up' : 'off'}`}></i>
                     </button>
                     <button 
                        onClick={() => navigator.clipboard.writeText(targetText)}
                        className="w-8 h-8 rounded-lg flex items-center justify-center bg-white text-gray-500 hover:text-indigo-600 shadow-sm transition-colors"
                     >
                        <i className="fas fa-copy"></i>
                     </button>
                </div>
            </div>

            <div className="flex-1 rounded-2xl overflow-hidden bg-white/80 border border-gray-100">
                <textarea
                    readOnly
                    value={targetText}
                    placeholder="Translation..."
                    className="w-full h-full p-4 bg-transparent outline-none resize-none text-lg text-gray-800 placeholder-gray-400"
                ></textarea>
            </div>

            {isLoading && (
                <div className="absolute inset-0 bg-white/50 backdrop-blur-sm rounded-3xl flex items-center justify-center z-10">
                    <div className="flex flex-col items-center">
                        <i className="fas fa-circle-notch fa-spin text-3xl text-indigo-600 mb-2"></i>
                        <span className="text-sm font-medium text-indigo-800">Neural Processing...</span>
                    </div>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

export default Translator;

export enum AppMode {
  TRANSLATOR = 'translator',
  INTELLIGENT_CHAT = 'intelligent_chat',
  KNOWLEDGE_BASE = 'knowledge_base'
}

export enum TranslationMode {
  TRANSLATE = 'TRANSLATE',
  TRANSLITERATE = 'TRANSLITERATE'
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  content: string;
  timestamp: number;
  sources?: { uri: string; title: string }[]; // For Search Grounding
}

export interface UploadedFile {
  name: string;
  content: string; // Base64 for binary, Text for text
  mimeType: string;
  isBinary: boolean;
  size: number;
}

export const SUPPORTED_LANGUAGES = [
  { code: 'auto', name: 'Auto-detect' },
  { code: 'en', name: 'English' },
  { code: 'es', name: 'Spanish' },
  { code: 'fr', name: 'French' },
  { code: 'de', name: 'German' },
  { code: 'hi', name: 'Hindi' },
  { code: 'bn', name: 'Bengali' },
  { code: 'ta', name: 'Tamil' },
  { code: 'ja', name: 'Japanese' },
  { code: 'ko', name: 'Korean' },
  { code: 'zh', name: 'Chinese' },
  { code: 'ru', name: 'Russian' },
  { code: 'ar', name: 'Arabic' },
];

// --- Tier Architecture ---

export enum Tier {
  FREE = 'Free',
  PRO = 'Pro',
  ENTERPRISE = 'Enterprise'
}

export interface TierConfig {
  name: Tier;
  maxFileSizeMB: number;
  allowedMimeTypes: string[]; 
  features: string[];
  color: string;
}

export const TIER_CONFIGS: Record<Tier, TierConfig> = {
  [Tier.FREE]: {
    name: Tier.FREE,
    maxFileSizeMB: 2,
    allowedMimeTypes: ['text/plain', 'application/pdf', 'application/json', 'text/csv', 'text/markdown'],
    features: ['Basic Translation', 'Web Search', 'PDF & Text Support', 'Scholar Modes'],
    color: 'bg-gray-500'
  },
  [Tier.PRO]: {
    name: Tier.PRO,
    maxFileSizeMB: 10,
    allowedMimeTypes: ['text/plain', 'application/pdf', 'image/jpeg', 'image/png', 'application/json', 'text/csv', 'text/markdown'],
    features: ['PDF Analysis', 'Truth Guard RAG', 'Image Analysis', 'Higher Limits'],
    color: 'bg-indigo-600'
  },
  [Tier.ENTERPRISE]: {
    name: Tier.ENTERPRISE,
