// --- Translation ---

export const translateText = async (
  text: string, 
  sourceLang: string, 
  targetLang: string, 
  mode: TranslationMode
): Promise<string> => {
  if (!text.trim()) return "";

  let prompt = "";

  if (mode === TranslationMode.TRANSLITERATE) {
    prompt = `You are a strict transliteration engine. Convert the following text phonetically from ${sourceLang === 'auto' ? 'detected language' : sourceLang} script to ${targetLang} script. 
    DO NOT translate the meaning. Only convert the sounds/script.
    Input: "${text}"`;
  } else {
    prompt = `You are a high-fidelity neural translation engine. Translate the following text from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}.
    Maintain tone, context, and nuance.
    Input: "${text}"`;
  }

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        temperature: 0.3, 
      }
    });
    return response.text || "Translation failed.";
  } catch (error) {
    console.error("Gemini Translation Error:", error);
    return "Error: Could not process text. Please check connectivity and API Key.";
  }
};

export const translateDocument = async (
  file: { data: string; mimeType: string; isBinary: boolean },
  sourceLang: string,
  targetLang: string,
  mode: TranslationMode
): Promise<string> => {

  let taskDescription = "";

  // Check if it is an image
  if (file.mimeType.startsWith('image/')) {
    taskDescription = `You are a Vision-to-Text Translator. 
    1. Analyze the attached image.
    2. If the image contains legible text, extract it and translate it from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}.
    3. If the image does NOT contain significant text (or is just an object/scene), provide a detailed description of what you see in the image, written in ${targetLang}.`;
  } else {
    // Standard Document logic
    taskDescription = mode === TranslationMode.TRANSLITERATE
    ? `Transliterate the document content from ${sourceLang === 'auto' ? 'detected language' : sourceLang} script to ${targetLang} script.`
    : `Translate the document content from ${sourceLang === 'auto' ? 'auto-detected language' : sourceLang} to ${targetLang}.`;
  }

  const instruction = `${taskDescription} Preserve original formatting where possible. Return ONLY the result.`;

  try {
    const parts: any[] = [];

    if (file.isBinary) {
        // For PDF/Images, use inlineData
        parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        parts.push({ text: instruction });
    } else {
        // For Text files, inject directly into prompt
        parts.push({ text: `${instruction}\n\n--- START OF DOCUMENT CONTENT ---\n${file.data}\n--- END OF DOCUMENT CONTENT ---` });
    }

    const response: GenerateContentResponse = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: [{ role: 'user', parts: parts }],
      config: {
        temperature: 0.3,
      }
    });
    return response.text || "Document translation failed.";
  } catch (error) {
    console.error("Gemini Document Translation Error:", error);
    return "Error: Could not process content. Ensure it is a valid file.";
  }
};

// --- Text-to-Speech (TTS) ---

export const speakText = async (text: string): Promise<void> => {
  try {
    const response = await ai.models.generateContent({
      model: TTS_MODEL,
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("No audio data returned");

    const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});

    const audioBuffer = await decodeAudioData(
      decode(base64Audio),
      outputAudioContext,
      24000,
      1,
    );

    const source = outputAudioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(outputAudioContext.destination);
    source.start();

  } catch (error) {
    console.error("TTS Error:", error);
    alert("Could not generate speech. Please check your network connection.");
  }
};

