export const analyzeDocument = async (
    file: { content: string; mimeType: string; isBinary: boolean }, 
    task: 'summary' | 'questions' | 'keywords'
): Promise<string> => {
    let prompt = "";
    switch(task) {
        case 'summary':
            prompt = "Provide a concise executive summary of the following document.";
            break;
        case 'questions':
            prompt = "Generate 5 critical questions that this document answers.";
            break;
        case 'keywords':
            prompt = "Extract the top 10 most significant keywords or entities from this document.";
            break;
    }

    try {
        const parts: any[] = [];
        if (file.isBinary) {
             parts.push({ inlineData: { mimeType: file.mimeType, data: file.content } });
             parts.push({ text: prompt });
        } else {
             parts.push({ text: `${prompt}\n\nDocument:\n${file.content.substring(0, 30000)}` });
        }

        const response = await ai.models.generateContent({
            model: MODEL_NAME,
            contents: [{ role: 'user', parts: parts }]
        });
        return response.text || "Analysis failed.";
    } catch (error) {
        return "Error analyzing document.";
    }
}

// --- Audio Helper Functions ---

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import { VectorDocument } from "../types";
import { getEmbedding } from "./geminiService";

// In-Memory Vector Store (simulating a DB like Pinecone/Weaviate)
class VectorStore {
    private documents: VectorDocument[] = [];

    // Adds a text to the store (automatically embeds it)
    async addDocument(text: string, source: string, category: string) {
        // Chunking Strategy: Simple text chunking (in production, use smart recursive splitters)
        const chunks = this.chunkText(text, 500); // 500 char chunks

        for (const chunk of chunks) {
            const embedding = await getEmbedding(chunk);
            if (embedding.length > 0) {
                const doc: VectorDocument = {
                    id: Math.random().toString(36).substring(7),
                    text: chunk,
                    source,
                    category,
                    embedding,
                    timestamp: Date.now()
                };
                this.documents.push(doc);
            }
        }
    }

    // Searches the store using Cosine Similarity
    async similaritySearch(query: string, topK: number = 3): Promise<VectorDocument[]> {
        const queryEmbedding = await getEmbedding(query);
        if (queryEmbedding.length === 0) return [];

        const scoredDocs = this.documents.map(doc => ({
            doc,
            score: this.cosineSimilarity(queryEmbedding, doc.embedding)
        }));

        // Sort by score descending
        scoredDocs.sort((a, b) => b.score - a.score);

        return scoredDocs.slice(0, topK).map(sd => sd.doc);
    }

    getStats() {
        return {
            totalDocuments: this.documents.length,
            categories: [...new Set(this.documents.map(d => d.category))]
        };
    }

    private chunkText(text: string, chunkSize: number): string[] {
        const chunks = [];
        for (let i = 0; i < text.length; i += chunkSize) {
            chunks.push(text.slice(i, i + chunkSize));
        }
        return chunks;
    }

    private cosineSimilarity(vecA: number[], vecB: number[]): number {
        let dotProduct = 0;
        let magA = 0;
        let magB = 0;
        for (let i = 0; i < vecA.length; i++) {
            dotProduct += vecA[i] * vecB[i];
            magA += vecA[i] * vecA[i];
            magB += vecB[i] * vecB[i];
        }
        return dotProduct / (Math.sqrt(magA) * Math.sqrt(magB));
    }
}

export const vectorStore = new VectorStore();

