    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isProcessing]);

  // --- Voice Input Setup ---
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = false;
            recognitionRef.current.lang = 'en-US';

            recognitionRef.current.onresult = (event: any) => {
                const transcript = event.results[0][0].transcript;
                setInputValue(prev => prev + (prev ? ' ' : '') + transcript);
                setIsListening(false);
            };

            recognitionRef.current.onerror = (event: any) => {
                setIsListening(false);
            };

            recognitionRef.current.onend = () => {
                setIsListening(false);
            };
        } catch (e) {
            console.error("Speech Setup Failed", e);
        }
    }
  }, []);

  const toggleListening = () => {
      if (isListening) {
          recognitionRef.current?.stop();
          setIsListening(false);
      } else {
          recognitionRef.current?.start();
          setIsListening(true);
      }
  };

  const handleSpeakMessage = async (msgId: string, text: string) => {
      if (playingMsgId) return; // Prevent overlapping
      setPlayingMsgId(msgId);
      await speakText(text);
      setPlayingMsgId(null);
  };

  // --- File Handling ---
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const uploadedFile = event.target.files?.[0];
    if (uploadedFile) {
        // Tier Checks
        if (uploadedFile.size > tierConfig.maxFileSizeMB * 1024 * 1024) {
            alert(`File too large for ${currentTier} tier. Max size is ${tierConfig.maxFileSizeMB}MB. Please upgrade.`);
            return;
        }

        const isPdf = uploadedFile.type === 'application/pdf' || uploadedFile.name.toLowerCase().endsWith('.pdf');

        if (!isPdf && !tierConfig.allowedMimeTypes.includes(uploadedFile.type)) {
             alert(`This file type is not allowed in ${currentTier} tier.`);
             return;
        }

        const reader = new FileReader();
        reader.onload = async (e) => {
            let content = e.target?.result as string;
            if (isPdf) content = content.split(',')[1];

            setFile({
                name: uploadedFile.name,
                mimeType: isPdf ? 'application/pdf' : (uploadedFile.type || 'text/plain'),
                isBinary: isPdf,
                size: uploadedFile.size,
                content: content
            });
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'model',
                content: `✅ I have ingested **${uploadedFile.name}**. \nTruth Guard™ mode is active.`,
                timestamp: Date.now()
            }]);
        };
        if (isPdf) reader.readAsDataURL(uploadedFile);
        else reader.readAsText(uploadedFile);
    }
  };

  const handleRemoveFile = () => {
      setFile(null);
      setMessages(prev => [...prev, {
          id: Date.now().toString(),
          role: 'model',
          content: "Document removed. Returning to Standard Chat mode.",
          timestamp: Date.now()
      }]);
  };

  // --- Link Handling ---
  const handleAddLink = () => {
      if (linkInput.trim()) {
          let url = linkInput.trim();
          if (!url.startsWith('http://') && !url.startsWith('https://')) {
              url = 'https://' + url;
          }
          setLinks(prev => [...prev, url]);
          setLinkInput('');
          setIsLinkInputOpen(false);
      }
  };

  const handleRemoveLink = (indexToRemove: number) => {
      setLinks(prev => prev.filter((_, idx) => idx !== indexToRemove));
  };

  const runQuickAction = async (action: 'summary' | 'questions' | 'keywords') => {
      if (!file) return;
      setIsProcessing(true);
      try {
          const res = await analyzeDocument(file, action);
          const botMsg: ChatMessage = {
            id: Date.now().toString(),
            role: 'model',
            content: `**${action.toUpperCase()}**: \n${res}`,
            timestamp: Date.now()
          };
          setMessages(prev => [...prev, botMsg]);
      } catch (e) {
          alert("Failed to analyze document.");
      } finally {
          setIsProcessing(false);
      }
  };

  // --- Chat Logic ---
  const handleSendMessage = async () => {
    if (!inputValue.trim()) return;

    const userMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'user',
        content: inputValue,
        timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsProcessing(true);

    try {
        const history = messages.map(m => ({
            role: m.role,
            parts: [{ text: m.content }]
        }));

        // 1. Retrieval (RAG) Step
        let ragContext = "";
        if (useRAG && !file) { // Use Vector Store if active and no direct document overrides
            const docs = await vectorStore.similaritySearch(userMsg.content);
            if (docs.length > 0) {
                ragContext = docs.map(d => `Source: ${d.source} (${d.category})\nContent: ${d.text}`).join('\n\n');
                console.log("RAG Retrieval:", docs.length, "documents found.");
            }
        }

        // 2. Generation Step
        const result = await chatHybrid(
            userMsg.content, 
            history, 
            file || undefined, 
            links, 
            scholarMode,
            ragContext
        );

        const botMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: 'model',
            content: result.text,
            timestamp: Date.now(),
            sources: result.sources
        };

        setMessages(prev => [...prev, botMsg]);
    } catch (e) {
        setMessages(prev => [...prev, {
            id: (Date.now() + 1).toString(),
            role: 'model',
            content: "I encountered an error while processing your request.",
            timestamp: Date.now()
        }]);
    } finally {
        setIsProcessing(false);
    }
  };

  const ScholarIcon = ({ mode }: { mode: ScholarMode }) => {
      switch(mode) {
          case ScholarMode.GENERAL: return <i className="fas fa-brain"></i>;
          case ScholarMode.HINDU: return <i className="fas fa-om"></i>;
          case ScholarMode.MUSLIM: return <i className="fas fa-moon"></i>;
          case ScholarMode.CHRISTIAN: return <i className="fas fa-cross"></i>;
      }
  };

  return (
    <div className="flex flex-col h-full gap-4">

        {/* Top Controls: Scholar & File */}
        <div className="flex flex-col xl:flex-row gap-4">

            {/* Scholar Selector */}
            <div className="flex-1 bg-white/60 p-1.5 rounded-2xl border border-gray-100 flex gap-1 shadow-sm overflow-x-auto">
                {Object.values(ScholarMode).map((mode) => (
                    <button
                    key={mode}
                    onClick={() => setScholarMode(mode)}
                    className={`flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-xl text-xs font-semibold transition-all duration-200 whitespace-nowrap ${
                        scholarMode === mode 
                        ? 'bg-white text-indigo-700 shadow-md ring-1 ring-black/5' 
                        : 'text-gray-500 hover:bg-white/50 hover:text-gray-700'
                    }`}
                    >
                    <span className="text-sm"><ScholarIcon mode={mode}/></span>
                    {mode === ScholarMode.GENERAL ? 'General' : mode.split(' ')[0]}
                    </button>
                ))}
            </div>

            {/* RAG Toggle */}
            {!file && (
                <div className="flex items-center gap-2 bg-indigo-50 px-3 rounded-2xl border border-indigo-100">
                    <span className="text-[10px] font-bold text-indigo-800 uppercase">KB RAG</span>
                    <button 
                        onClick={() => setUseRAG(!useRAG)}
                        className={`w-10 h-5 rounded-full relative transition-colors ${useRAG ? 'bg-indigo-600' : 'bg-gray-300'}`}
                    >
                        <div className={`w-3 h-3 bg-white rounded-full absolute top-1 transition-all ${useRAG ? 'left-6' : 'left-1'}`}></div>
                    </button>
                </div>
            )}

            {/* File Info / Status */}
            {file && (
                <div className="animate-fade-in bg-indigo-50 border border-indigo-100 text-indigo-800 px-4 py-2 rounded-2xl flex items-center justify-between gap-4 shadow-sm min-w-[250px]">
                    <div className="flex items-center gap-2 overflow-hidden">
                        <i className={`fas ${file.isBinary ? 'fa-file-pdf' : 'fa-file-alt'} text-indigo-500`}></i>
                        <span className="text-xs font-bold truncate">{file.name}</span>
                    </div>
                    <button onClick={handleRemoveFile} className="text-indigo-400 hover:text-red-500 transition-colors">
                        <i className="fas fa-times"></i>
                    </button>
                </div>
            )}
        </div>

        <div className="flex-1 flex flex-col lg:flex-row gap-4 min-h-0">

            {/* Main Chat Window */}
            <div className="flex-1 flex flex-col bg-white/40 border border-white/60 rounded-3xl shadow-sm overflow-hidden relative backdrop-blur-sm">

                {/* Messages */}
                <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 scroll-smooth">
                    {messages.map((msg) => (
                        <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-slide-up`}>
                            <div className={`max-w-[85%] md:max-w-[75%] rounded-2xl p-4 shadow-sm relative group transition-all hover:shadow-md ${
                                msg.role === 'user' 
                                    ? 'bg-gradient-to-br from-indigo-600 to-indigo-700 text-white rounded-tr-sm' 
                                    : 'bg-white text-gray-800 border border-gray-100 rounded-tl-sm'
                            }`}>
                                <div className="whitespace-pre-wrap text-sm leading-relaxed">{msg.content}</div>

                                {msg.sources && msg.sources.length > 0 && (
                                    <div className="mt-3 pt-3 border-t border-white/10 opacity-90">
                                        <p className="text-[10px] font-bold uppercase tracking-wider mb-1 opacity-70">Sources</p>
                                        <div className="flex flex-wrap gap-2">
                                            {msg.sources.map((src, idx) => (
                                                <a key={idx} href={src.uri} target="_blank" rel="noopener noreferrer" className="text-[10px] bg-black/5 hover:bg-black/10 px-2 py-1 rounded truncate max-w-[150px] transition-colors">
                                                    <i className="fas fa-external-link-alt mr-1"></i> {src.title}
                                                </a>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                <button 
                                    onClick={() => handleSpeakMessage(msg.id, msg.content)}
                                    className={`absolute -bottom-6 ${msg.role === 'user' ? 'right-0' : 'left-0'} text-gray-400 hover:text-indigo-600 text-xs p-1 opacity-0 group-hover:opacity-100 transition-opacity`}
                                >
                                    <i className={`fas ${playingMsgId === msg.id ? 'fa-volume-up animate-pulse text-indigo-600' : 'fa-volume-off'}`}></i>
                                </button>
                            </div>
                            <span className="text-[10px] text-gray-400 mt-1 px-1">
                                {msg.role === 'user' ? 'You' : (file ? 'Truth Guard AI' : scholarMode)}
                            </span>
                        </div>
                    ))}
                    {isProcessing && (
                         <div className="flex items-center gap-2 text-gray-400 text-xs p-4 animate-pulse">
                            <i className="fas fa-circle-notch fa-spin text-indigo-500"></i> Thinking...
                        </div>
                    )}
                    <div ref={chatEndRef} />
                </div>

                {/* Floating Input Area */}
                <div className="p-4 bg-gradient-to-t from-white/90 via-white/80 to-transparent">

                    {/* Link Chips */}
                    {links.length > 0 && (
                        <div className="flex flex-wrap gap-2 mb-2 px-2">
                            {links.map((link, idx) => (
                                <div key={idx} className="flex items-center gap-1 bg-blue-50 text-blue-600 text-[10px] font-medium px-2 py-1 rounded-full border border-blue-100 max-w-[200px]">
                                    <i className="fas fa-link"></i>
                                    <span className="truncate">{link}</span>
                                    <button onClick={() => handleRemoveLink(idx)} className="ml-1 hover:text-red-500"><i className="fas fa-times"></i></button>
                                </div>
                            ))}
                        </div>
                    )}

                    {/* Input Bar */}
                    <div className="bg-white p-1.5 rounded-[2rem] border border-gray-200 shadow-lg flex items-center gap-1 transition-shadow hover:shadow-xl focus-within:ring-2 focus-within:ring-indigo-100 focus-within:border-indigo-300">

                        {/* Attach File */}
                        <label className="w-10 h-10 flex items-center justify-center rounded-full cursor-pointer text-gray-400 hover:bg-gray-100 hover:text-indigo-600 transition-all" title="Upload Document">
                            <input type="file" className="hidden" accept={tierConfig.allowedMimeTypes.join(',')} onChange={handleFileUpload} disabled={!!file} />
                            <i className="fas fa-paperclip text-lg"></i>
                        </label>

                        {/* Link Toggle */}
                        <div className="relative">
                            <button 
                                onClick={() => setIsLinkInputOpen(!isLinkInputOpen)}
                                className={`w-10 h-10 flex items-center justify-center rounded-full transition-all ${links.length > 0 ? 'text-blue-500 bg-blue-50' : 'text-gray-400 hover:bg-gray-100 hover:text-indigo-600'}`}
                            >
                                <i className="fas fa-link"></i>
                            </button>
                            {isLinkInputOpen && (
                                <div className="absolute bottom-12 left-0 z-50 bg-white p-3 rounded-xl shadow-xl border border-gray-100 w-64 animate-slide-up">
                                    <div className="flex gap-2">
                                        <input 
                                            type="text" 
                                            value={linkInput}
                                            onChange={(e) => setLinkInput(e.target.value)}
                                            onKeyDown={(e) => e.key === 'Enter' && handleAddLink()}
                                            placeholder="Paste URL..."
                                            className="flex-1 text-xs border border-gray-200 rounded-lg px-2 py-2 focus:outline-none focus:border-indigo-500"
                                            autoFocus
                                        />
                                        <button onClick={handleAddLink} className="bg-indigo-600 text-white px-3 rounded-lg text-xs font-bold hover:bg-indigo-700">Add</button>
                                    </div>
                                </div>
                            )}
                        </div>

                        {/* Text Input */}
                        <input
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                            disabled={isProcessing}
                            placeholder={isListening ? "Listening..." : "Message NeuroLingua..."}
                            className="flex-1 bg-transparent border-none focus:ring-0 text-sm text-gray-800 placeholder-gray-400 px-2"
                        />

                        {/* Mic */}
                        <button 
                            onClick={toggleListening}
                            className={`w-10 h-10 flex items-center justify-center rounded-full transition-all ${isListening ? 'bg-red-50 text-red-500 animate-pulse' : 'text-gray-400 hover:bg-gray-100 hover:text-indigo-600'}`}
                        >
                            <i className={`fas fa-microphone${isListening ? '' : '-slash'}`}></i>
                        </button>

                        {/* Send */}
                        <button 
                            onClick={handleSendMessage}
                            disabled={isProcessing || !inputValue.trim()}
                            className="w-10 h-10 flex items-center justify-center rounded-full bg-indigo-600 text-white shadow-md hover:bg-indigo-700 hover:shadow-lg disabled:opacity-50 disabled:shadow-none transition-all transform hover:scale-105"
                        >
                            {isProcessing ? <i className="fas fa-circle-notch fa-spin text-xs"></i> : <i className="fas fa-arrow-up text-sm"></i>}
                        </button>
                    </div>
                </div>
            </div>

            {/* Document Quick Actions (Visible if file loaded) */}
            {file && (
                <div className="w-full lg:w-64 flex flex-col gap-3 animate-fade-in">
                    <div className="bg-white/60 p-4 rounded-3xl border border-white/60 shadow-sm h-full">
                        <h4 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-4">Quick Analysis</h4>
                        <div className="flex flex-col gap-2">
                             <button onClick={() => runQuickAction('summary')} className="flex items-center gap-3 w-full text-left px-4 py-3 bg-white hover:bg-indigo-50 border border-gray-100 rounded-xl text-sm font-medium text-gray-700 transition-all hover:shadow-sm group">
                                <div className="w-8 h-8 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                                    <i className="fas fa-list-ul text-xs"></i>
                                </div>
                                Summarize
                            </button>
                        </div>

                        <div className="mt-6 p-3 bg-blue-50 rounded-xl border border-blue-100">
                            <div className="flex items-start gap-2">
                                <i className="fas fa-info-circle text-blue-500 mt-0.5"></i>
                                <p className="text-[10px] text-blue-700 leading-tight">
                                    Truth Guard™ is enforcing strict adherence to <strong>{file.name}</strong>.
                                </p>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    </div>
  );
};

