import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, UploadedFile, ScholarMode } from '../types';
import { chatHybrid, speakText, analyzeDocument, fetchKnowledgeFromWeb } from '../services/geminiService';
import { vectorStore } from '../services/vectorStore';
