// Polyfill type for SpeechRecognition
declare global {
    interface Window {
        webkitSpeechRecognition: any;
        SpeechRecognition: any;
    }
}

const IntelligentChat: React.FC = () => {
  const { tierConfig, currentTier } = useTier();

  // State
  const [messages, setMessages] = useState<ChatMessage[]>([
      {
          id: 'intro',
          role: 'model',
          content: "Hello! I am NeuroLingua AI. You can ask me general questions, select a specialized Scholar Mode, or upload a document to activate 'Truth Guard'.",
          timestamp: Date.now()
      }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [file, setFile] = useState<UploadedFile | null>(null);
  const [scholarMode, setScholarMode] = useState<ScholarMode>(ScholarMode.GENERAL);
  const [useRAG, setUseRAG] = useState(true); // Toggle for Vector DB

  // Link State
  const [links, setLinks] = useState<string[]>([]);
  const [isLinkInputOpen, setIsLinkInputOpen] = useState(false);
  const [linkInput, setLinkInput] = useState('');
  const [indexingLinks, setIndexingLinks] = useState<Record<number, boolean>>({});

  // Voice State
  const [isListening, setIsListening] = useState(false);
  const [playingMsgId, setPlayingMsgId] = useState<string | null>(null);

  const chatEndRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isProcessing]);

  // --- Voice Input Setup ---
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = false;
            recognitionRef.current.lang = 'en-US';

            recognitionRef.current.onresult = (event: any) => {
                const transcript = event.results[0][0].transcript;
                setInputValue(prev => prev + (prev ? ' ' : '') + transcript);
                setIsListening(false);
            };

            recognitionRef.current.onerror = (event: any) => {
                setIsListening(false);
            };

            recognitionRef.current.onend = () => {
                setIsListening(false);
            };
        } catch (e) {
            console.error("Speech Setup Failed", e);
        }
    }
  }, []);

  const toggleListening = () => {
      if (isListening) {
          recognitionRef.current?.stop();
          setIsListening(false);
      } else {
          recognitionRef.current?.start();
          setIsListening(true);
      }
  };

  const handleSpeakMessage = async (msgId: string, text: string) => {
      if (playingMsgId) return; // Prevent overlapping
      setPlayingMsgId(msgId);
      await speakText(text);
      setPlayingMsgId(null);
  };

  // --- File Handling ---
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const uploadedFile = event.target.files?.[0];
    if (uploadedFile) {
        // Tier Checks
        if (uploadedFile.size > tierConfig.maxFileSizeMB * 1024 * 1024) {
            alert(`File too large for ${currentTier} tier. Max size is ${tierConfig.maxFileSizeMB}MB. Please upgrade.`);
            return;
        }

        const isPdf = uploadedFile.type === 'application/pdf' || uploadedFile.name.toLowerCase().endsWith('.pdf');
        // Add basic checking for docx, though extraction relies on text/pdf logic mainly.
        // For now, if it's not PDF or Image, we try readAsText which won't work well for binary DOCX.
        // We'll allow it if user insists but it might need server-side parsing.

        if (!isPdf && !tierConfig.allowedMimeTypes.includes(uploadedFile.type)) {
             // Relaxed check for docx if tier allows "All File Types" effectively or just warn
             if (uploadedFile.name.endsWith('.docx') || uploadedFile.name.endsWith('.doc')) {
                // Warning: DOCX support in client-only mode is limited
                alert("Note: Word documents may not be fully parsed in browser-only mode. PDF is recommended.");
             } else {
                alert(`This file type is not allowed in ${currentTier} tier.`);
                return;
             }
        }

        const reader = new FileReader();
        reader.onload = async (e) => {
            let content = e.target?.result as string;
            if (isPdf) content = content.split(',')[1];

            setFile({
                name: uploadedFile.name,
                mimeType: isPdf ? 'application/pdf' : (uploadedFile.type || 'text/plain'),
                isBinary: isPdf,
                size: uploadedFile.size,
                content: content
            });
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'model',
                content: `✅ I have ingested **${uploadedFile.name}**. \nTruth Guard™ mode is active.`,
                timestamp: Date.now()
            }]);
        };
        if (isPdf) reader.readAsDataURL(uploadedFile);
        else reader.readAsText(uploadedFile);
    }
  };

  const handleRemoveFile = () => {
      setFile(null);
      setMessages(prev => [...prev, {
          id: Date.now().toString(),
          role: 'model',
          content: "Document removed. Returning to Standard Chat mode.",
          timestamp: Date.now()
      }]);
  };

  // --- Link Handling ---
  const handleAddLink = () => {
      if (linkInput.trim()) {
          let url = linkInput.trim();
          if (!url.startsWith('http://') && !url.startsWith('https://')) {
              url = 'https://' + url;
          }
          setLinks(prev => [...prev, url]);
          setLinkInput('');
          setIsLinkInputOpen(false);
      }
  };

  const handleRemoveLink = (indexToRemove: number) => {
      setLinks(prev => prev.filter((_, idx) => idx !== indexToRemove));
  };

  // Indexes a link into the vector store for RAG
  const handleIndexLink = async (index: number) => {
      const url = links[index];
      if (!url) return;

      setIndexingLinks(prev => ({ ...prev, [index]: true }));
      try {
          // Use Gemini to read/summarize the URL
