// Using a popular open model. In a real app, you might want to allow users to input their own HF Token.
// For this demo, we assume the user might have set REACT_APP_HF_TOKEN or similar, 
// or we use the free inference API (which has rate limits).
const HF_API_URL = "https://api-inference.huggingface.co/models/mistralai/Mistral-7B-Instruct-v0.3";

export const chatWithHuggingFace = async (
    query: string,
    history: Content[],
    systemInstruction: string,
    ragContext?: string
): Promise<string> => {

    // Construct prompt manually as HF models expect a single string usually
    let fullPrompt = `<s>[INST] ${systemInstruction}\n\n`;

    if (ragContext) {
        fullPrompt += `CONTEXT INFORMATION:\n${ragContext}\n\n`;
    }

    // Add recent history (last 2 turns to save context window)
    history.slice(-2).forEach(msg => {
        if (msg.role === 'user') fullPrompt += `User: ${msg.parts[0].text}\n`;
        else fullPrompt += `Assistant: ${msg.parts[0].text}\n`;
    });

    fullPrompt += `User: ${query} [/INST]`;

    try {
        const response = await fetch(HF_API_URL, {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
                // "Authorization": `Bearer ${process.env.HF_API_KEY}` // Uncomment if you have a key
            },
            body: JSON.stringify({
                inputs: fullPrompt,
                parameters: {
                    max_new_tokens: 500,
                    temperature: 0.7,
                    return_full_text: false
                }
            })
        });

        if (!response.ok) {
            throw new Error(`HF API Error: ${response.statusText}`);
        }

        const result = await response.json();
        // HF Inference API returns an array
        return result[0]?.generated_text || "No response from Hugging Face.";

    } catch (error) {
        console.error("Hugging Face Error:", error);
        return "Error: Could not connect to Open Source model. You may need an API Key or the service is busy.";
    }
};

