export const getEmbedding = async (text: string): Promise<number[]> => {
  try {
    return await withRetry(async () => {
        const response = await ai.models.embedContent({
        model: EMBEDDING_MODEL,
        contents: { parts: [{ text }] }
        });
        return response.embeddings?.[0]?.values || [];
    });
  } catch (error) {
    console.error("Embedding Error:", error);
    return [];
  }
};

// --- Knowledge Fetching (Hybrid: Python Scraper -> Gemini Fallback) ---

export const fetchKnowledgeFromWeb = async (topic: string): Promise<string> => {
    // 1. Try Python Scraper (Localhost)
    try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 3000); // 3s timeout

        const response = await fetch('http://localhost:5000/scrape', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ url: topic, query: topic }), // Scraper handles raw query or url
            signal: controller.signal
        });
        clearTimeout(timeoutId);

        if (response.ok) {
            const data = await response.json();
            if (data.content) {
                console.log("Used Python Scraper for Knowledge");
                return data.content;
            }
        }
    } catch (e) {
        console.warn("Python scraper unavailable, falling back to Gemini Search.");
    }

    // 2. Fallback to Gemini Search (Consumes Tokens)
    const executeFetch = async () => {
      const prompt = `Research the following topic thoroughly: "${topic}".
      Provide a detailed, structured summary suitable for a knowledge base.
      Extract key facts, dates, and definitions.`;

      const response = await ai.models.generateContent({
        model: MODEL_NAME,
        contents: prompt,
        config: {
          tools: [{ googleSearch: {} }]
        }
      });
      return response.text || "";
    };

    try {
        return await withRetry(executeFetch, 3, 2000);
    } catch (error) {
        console.error("Knowledge Fetch Error:", error);
        throw new Error("Could not fetch knowledge from web.");
    }
};

// --- Translation ---

export const translateText = async (
  text: string, 
  sourceLang: string, 
  targetLang: string, 
  mode: TranslationMode
): Promise<string> => {
  if (!text.trim()) return "";

  let prompt = mode === TranslationMode.TRANSLITERATE
    ? `Transliterate the following text from ${sourceLang} script to ${targetLang} script. Phonetic conversion only. Input: "${text}"`
    : `Translate the following text from ${sourceLang} to ${targetLang}. Input: "${text}"`;

  try {
    return await withRetry(async () => {
        const response = await ai.models.generateContent({
            model: MODEL_NAME,
            contents: prompt
        });
        return response.text || "Translation failed.";
    });
  } catch (error) {
    return "Error: Could not process text.";
  }
};

export const translateDocument = async (
  file: { data: string; mimeType: string; isBinary: boolean },
  sourceLang: string,
  targetLang: string,
  mode: TranslationMode
): Promise<string> => {
  const prompt = `Translate this document from ${sourceLang} to ${targetLang}. Preserve formatting.`;

  try {
    const parts: Part[] = [];
    if (file.isBinary) {
        parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        parts.push({ text: prompt });
    } else {
        parts.push({ text: `${prompt}\n\n${file.data}` });
    }

    return await withRetry(async () => {
        const response = await ai.models.generateContent({
            model: MODEL_NAME,
            contents: [{ role: 'user', parts }]
        });
        return response.text || "Document translation failed.";
    }, 2, 2000);
  } catch (error) {
    return "Error processing document.";
  }
};

// --- Native Free Text-to-Speech ---

export const speakText = async (text: string): Promise<void> => {
    return new Promise((resolve, reject) => {
        if (!window.speechSynthesis) {
            alert("Your browser does not support Speech Synthesis.");
            return resolve();
        }

        // Cancel any ongoing speech
        window.speechSynthesis.cancel();

        const utterance = new SpeechSynthesisUtterance(text);
        utterance.rate = 1.0;
        utterance.pitch = 1.0;

        // Try to select a decent voice
        const voices = window.speechSynthesis.getVoices();
        const preferredVoice = voices.find(v => v.lang.startsWith('en') && v.name.includes('Google')) || voices[0];
        if (preferredVoice) utterance.voice = preferredVoice;

        utterance.onend = () => resolve();
        utterance.onerror = (e) => {
            console.error("Speech error", e);
            resolve(); // Resolve anyway to not block UI
        };

        window.speechSynthesis.speak(utterance);
    });
};

// --- Chat Logic ---

export const chatHybrid = async (
  query: string,
  chatHistory: Content[],
  document?: { content: string; mimeType: string; isBinary: boolean },
  links?: string[],
  persona: ChatPersona = ChatPersona.GENERAL,
  ragContext?: string
): Promise<{ text: string, sources?: { uri: string; title: string }[] }> => {

  let systemInstruction = PERSONA_PROMPTS[persona];

  let tools = [];
  const hasLinks = links && links.length > 0;

  if (ragContext) {
      systemInstruction += `\n\n[RAG CONTEXT]\nUse this information to answer:\n${ragContext}`;
  }

  if (document) {
    systemInstruction += `\n\n[DOCUMENT CONTEXT]\nAnalyze the uploaded document strictly.`;
  }

  // Enable Search for General Persona or if links provided
  if (!document || hasLinks) {
     tools = [{ googleSearch: {} }];
  }

  // Inject Links
  let finalQuery = query;
  if (hasLinks) {
      finalQuery += `\n\nRefer to: ${links?.join(', ')}`;
  }

  const apiHistory: Content[] = [...chatHistory];

  if (document) {
      const docPart: Part = document.isBinary 
          ? { inlineData: { mimeType: document.mimeType, data: document.content } }
          : { text: `[DOCUMENT]\n${document.content}` };

      apiHistory.unshift({ role: 'user', parts: [docPart, { text: "Context Document" }] });
      apiHistory.unshift({ role: 'model', parts: [{ text: "Document received." }] });
  }

  try {
    return await withRetry(async () => {
        const chat = ai.chats.create({
            model: MODEL_NAME,
            config: { systemInstruction, tools },
            history: apiHistory
        });

        const response = await chat.sendMessage({ message: finalQuery });

        const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
        const sources: { uri: string; title: string }[] = [];

        if (groundingChunks) {
            groundingChunks.forEach((chunk: any) => {
                if (chunk.web?.uri) sources.push({ uri: chunk.web.uri, title: chunk.web.title || "Source" });
            });
        }

        return { 
            text: response.text || "No response.", 
            sources: sources.length > 0 ? sources : undefined 
        };
    });
  } catch (error) {
    console.error("Chat Error:", error);
    return { text: "Error connecting to AI." };
  }
};

export const chatWithDocument = async (
    query: string,
    documentContent: string,
    chatHistory: { role: string; parts: { text: string }[] }[]
): Promise<string> => {
    const result = await chatHybrid(query, chatHistory, { content: documentContent, mimeType: 'text/plain', isBinary: false });
    return result.text;
};

export const analyzeDocument = async (
    file: { content: string; mimeType: string; isBinary: boolean }, 
    task: 'summary' | 'questions' | 'keywords'
): Promise<string> => {
    // Quick analysis using a single-shot prompt
    const prompt = `Perform task: ${task.toUpperCase()} on the attached document.`;
    try {
        const parts: Part[] = [];
        if (file.isBinary) parts.push({ inlineData: { mimeType: file.mimeType, data: file.content } });
        else parts.push({ text: `Document:\n${file.content}` });

        parts.push({ text: prompt });

        const response = await ai.models.generateContent({
            model: MODEL_NAME,
            contents: [{ role: 'user', parts }]
        });
        return response.text || "Analysis failed.";
    } catch (e) {
        return "Error analyzing document.";
    }
}

