                )}

                <div className="flex items-center gap-2 bg-white border border-gray-200 p-1.5 rounded-full shadow-lg">
                    <label className="w-10 h-10 flex items-center justify-center text-gray-400 hover:text-indigo-600 cursor-pointer rounded-full hover:bg-gray-50 transition-colors">
                        <input type="file" className="hidden" accept=".pdf,.doc,.docx,.txt" onChange={handleFileUpload} />
                        <i className={`fas ${file ? 'fa-check text-green-500' : 'fa-paperclip'}`}></i>
                    </label>

                    <div className="relative">
                        <button onClick={() => setIsLinkInputOpen(!isLinkInputOpen)} className="w-10 h-10 flex items-center justify-center text-gray-400 hover:text-blue-500 rounded-full hover:bg-gray-50">
                            <i className="fas fa-link"></i>
                        </button>
                        {isLinkInputOpen && (
                            <div className="absolute bottom-12 left-0 z-50 bg-white p-2 rounded-xl shadow-xl border border-gray-200 w-64">
                                <input 
                                    type="text" 
                                    value={linkInput}
                                    onChange={(e) => setLinkInput(e.target.value)}
                                    onKeyDown={(e) => e.key === 'Enter' && (setLinks(prev => [...prev, linkInput]), setLinkInput(''), setIsLinkInputOpen(false))}
                                    placeholder="Paste URL..."
                                    className="w-full text-xs border border-gray-200 rounded p-2 mb-2"
                                    autoFocus
                                />
                            </div>
                        )}
                    </div>

                    <input
                        type="text"
                        value={inputValue}
                        onChange={(e) => setInputValue(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                        disabled={isProcessing}
                        placeholder={isListening ? "Listening..." : "Message..."}
                        className="flex-1 bg-transparent border-none focus:ring-0 text-sm"
                    />

                    <button onClick={toggleListening} className={`w-10 h-10 rounded-full ${isListening ? 'text-red-500 animate-pulse' : 'text-gray-400 hover:text-indigo-600'}`}>
                        <i className={`fas fa-microphone${isListening ? '' : '-slash'}`}></i>
                    </button>

                    <button onClick={handleSendMessage} disabled={!inputValue.trim()} className="w-10 h-10 bg-indigo-600 text-white rounded-full hover:bg-indigo-700 shadow-md flex items-center justify-center">
                        {isProcessing ? <i className="fas fa-spinner fa-spin text-xs"></i> : <i className="fas fa-arrow-up text-sm"></i>}
                    </button>
                </div>
            </div>
        </div>
    </div>
  );
};

export default IntelligentChat;

import React, { useState } from 'react';
import { vectorStore } from '../services/vectorStore';
import { fetchKnowledgeFromWeb } from '../services/geminiService';
import { useTier } from '../contexts/TierContext';
import { Tier } from '../types';

interface KnowledgeSource {
    name: string;
    query: string;
    description: string;
}

// Generalized Topics for "Foundational Knowledge"
const TIER_KNOWLEDGE: Record<Tier, KnowledgeSource[]> = {
    [Tier.FREE]: [
        { name: 'General Science', query: 'Key concepts in physics, chemistry, and biology summary', description: 'Scientific Principles' },
        { name: 'World History', query: 'Summary of major world history events 20th century', description: 'Historical Context' }
    ],
    [Tier.PRO]: [
        { name: 'Advanced Philosophy', query: 'Major philosophical schools: Stoicism, Existentialism, Eastern Philosophy', description: 'Ethics & Thought' },
        { name: 'Literature Classics', query: 'Summary of Shakespeare, Homer, and Dante key themes', description: 'Classic Literature' }
    ],
    [Tier.ENTERPRISE]: [
        { name: 'Global Economics', query: 'Macroeconomic principles and global market structures', description: 'Economics' },
        { name: 'Cutting Edge Tech', query: 'Latest developments in AI, Quantum Computing, and Biotech', description: 'Future Tech' }
    ]
};

const KnowledgeBase: React.FC = () => {
    const { currentTier } = useTier();
    const [isSyncing, setIsSyncing] = useState(false);
    const [progress, setProgress] = useState(0);
    const [customTopic, setCustomTopic] = useState("");
    const [stats, setStats] = useState(vectorStore.getStats());

    const getSources = () => {
        let sources = [...TIER_KNOWLEDGE[Tier.FREE]];
        if (currentTier !== Tier.FREE) sources = [...sources, ...TIER_KNOWLEDGE[Tier.PRO]];
        if (currentTier === Tier.ENTERPRISE) sources = [...sources, ...TIER_KNOWLEDGE[Tier.ENTERPRISE]];
        return sources;
    };

    const handleSync = async () => {
        if (isSyncing) return;
        setIsSyncing(true);
        const sources = getSources();
        let completed = 0;

        for (const source of sources) {
            try {
                const content = await fetchKnowledgeFromWeb(source.query);
                await vectorStore.addDocument(content, source.name, "Core Knowledge");
                completed++;
                setProgress((completed / sources.length) * 100);
            } catch (e) {
                console.error(`Failed: ${source.name}`);
            }
        }
        setIsSyncing(false);
        setStats(vectorStore.getStats());
    };

    const handleAddCustom = async () => {
        if (!customTopic.trim()) return;
        setIsSyncing(true);
        try {
            const content = await fetchKnowledgeFromWeb(customTopic);
            await vectorStore.addDocument(content, customTopic, "User Custom");
            setCustomTopic("");
            setStats(vectorStore.getStats());
        } catch(e) {
            alert("Failed to fetch topic");
        } finally {
            setIsSyncing(false);
        }
    };

    return (
        <div className="flex flex-col h-full gap-6">
            <div className="bg-gradient-to-r from-gray-900 to-gray-800 text-white p-6 rounded-3xl shadow-lg relative overflow-hidden">
                <div className="relative z-10">
                    <h2 className="text-2xl font-bold mb-2">Knowledge Base</h2>
                    <p className="text-gray-300 text-sm mb-4">
                        Build a custom RAG corpus. Sync foundational topics or add your own research interests.
                        {stats.totalDocuments > 0 && <span className="block mt-2 text-green-400 font-bold">{stats.totalDocuments} vectors indexed.</span>}
                    </p>

                    <div className="flex flex-wrap gap-3">
                        <button 
                            onClick={handleSync} 
                            disabled={isSyncing}
                            className="bg-white text-gray-900 px-4 py-2 rounded-lg font-bold hover:bg-gray-200 transition-colors"
                        >
                            {isSyncing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-sync"></i>} Sync Core Topics
                        </button>
                    </div>

                    <div className="mt-4 flex gap-2">
                        <input 
                            type="text" 
                            value={customTopic}
                            onChange={(e) => setCustomTopic(e.target.value)}
                            placeholder="Add custom topic (e.g. 'Quantum Mechanics')..."
                            className="flex-1 bg-white/10 border border-white/20 rounded-lg px-3 py-2 text-sm text-white placeholder-gray-400 focus:outline-none focus:border-white"
                        />
                        <button 
                            onClick={handleAddCustom}
                            disabled={isSyncing || !customTopic}
                            className="bg-indigo-600 px-4 py-2 rounded-lg font-bold hover:bg-indigo-500"
                        >
                            Add
                        </button>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 flex-1 overflow-y-auto">
                <div className="space-y-2">
                    <h3 className="text-xs font-bold text-gray-500 uppercase">Core Topics ({currentTier})</h3>
                    {getSources().map((s, i) => (
                        <div key={i} className="bg-white/60 p-3 rounded-xl border border-white shadow-sm">
                            <h4 className="font-bold text-sm">{s.name}</h4>
                            <p className="text-xs text-gray-500">{s.description}</p>
                        </div>
                    ))}
                </div>
                <div className="space-y-2">
                    <h3 className="text-xs font-bold text-gray-500 uppercase">Active Vectors</h3>
                     {vectorStore.getStats().categories.map((c, i) => (
                        <div key={i} className="bg-green-50 p-3 rounded-xl border border-green-100 shadow-sm flex items-center gap-2">
                            <i className="fas fa-database text-green-600"></i>
                            <span className="text-sm font-medium text-green-800">{c}</span>
                        </div>
                    ))}
                    {vectorStore.getStats().categories.length === 0 && (
                        <p className="text-xs text-gray-400 italic">No topics indexed yet.</p>
                    )}
                </div>
            </div>
        </div>
    );
};

export default KnowledgeBase;

import React, { useState, useEffect, useRef } from 'react';
import { TranslationMode, SUPPORTED_LANGUAGES, Tier } from '../types';
import { translateText, translateDocument, speakText } from '../services/geminiService';
import { useTier } from '../contexts/TierContext';
import { createWorker } from 'tesseract.js';

// Polyfill type for SpeechRecognition
declare global {
    interface Window {
        webkitSpeechRecognition: any;
        SpeechRecognition: any;
    }
}

interface AttachedFile {
    name: string;
    mimeType: string;
    data: string; // Base64 (for binary) OR Raw Text (for text files)
    isBinary: boolean;
}

const getTesseractLang = (code: string) => {
    const map: Record<string, string> = {
        'en': 'eng', 'es': 'spa', 'fr': 'fra', 'de': 'deu',
        'hi': 'hin', 'bn': 'ben', 'ta': 'tam', 'ja': 'jpn',
        'ko': 'kor', 'zh': 'chi_sim', 'ru': 'rus', 'ar': 'ara'
    };
    return map[code] || 'eng';
};

const Translator: React.FC = () => {
  const { tierConfig, currentTier } = useTier();

  const [sourceText, setSourceText] = useState('');
  const [targetText, setTargetText] = useState('');
  const [sourceLang, setSourceLang] = useState('auto');
  const [targetLang, setTargetLang] = useState('es');
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TRANSLATE);
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);

  // Camera State
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [ocrText, setOcrText] = useState('');
  const [isOcrInitializing, setIsOcrInitializing] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const recognitionRef = useRef<any>(null);
  const workerRef = useRef<any>(null);
  const ocrIntervalRef = useRef<any>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = false;

            recognitionRef.current.onresult = (event: any) => {
                const transcript = event.results[0][0].transcript;
                setSourceText(transcript);
                setIsListening(false);
            };

            recognitionRef.current.onerror = (event: any) => {
                console.error("Speech Recognition Error:", event.error);
                if (event.error === 'network') {
                    alert("Speech recognition failed due to network issues.");
                } else if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
                    alert("Microphone access denied. Please check your browser settings.");
                }
                setIsListening(false);
            };

            recognitionRef.current.onend = () => {
                setIsListening(false);
            };
        } catch (e) {
            console.error("Speech Recognition setup failed:", e);
        }
    }
  }, []);

  // Debounce translation trigger for text (not file)
  useEffect(() => {
    const timer = setTimeout(() => {
      if (sourceText.length > 1 && !attachedFile) { // Only auto-process text if no file attached
        handleProcess();
      }
    }, 1000);

    return () => clearTimeout(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [sourceText, sourceLang, targetLang, mode]);

  // Handle Camera Stream & OCR
  useEffect(() => {
    let stream: MediaStream | null = null;

    const startCameraAndOCR = async () => {
        try {
            stream = await navigator.mediaDevices.getUserMedia({ 
                video: { facingMode: 'environment' } 
            });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }

            // Init OCR Worker
            setIsOcrInitializing(true);
            const lang = getTesseractLang(sourceLang === 'auto' ? 'en' : sourceLang);
            const worker = await createWorker(lang);
            workerRef.current = worker;
            setIsOcrInitializing(false);

            // Start OCR Loop
            ocrIntervalRef.current = setInterval(async () => {
                if (videoRef.current && canvasRef.current && workerRef.current) {
                    const video = videoRef.current;
                    const canvas = canvasRef.current;

                    // Only process if video is ready
                    if (video.readyState === video.HAVE_ENOUGH_DATA) {
                        canvas.width = video.videoWidth / 2; // Downscale for speed
                        canvas.height = video.videoHeight / 2;
                        const ctx = canvas.getContext('2d');
                        if (ctx) {
                            ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
                            // Convert to blob or use data url? Tesseract accepts image data
                            // Using dataURL is easiest for Tesseract.js in browser
                            const dataUrl = canvas.toDataURL('image/jpeg', 0.5);

                            try {
                                const { data: { text } } = await workerRef.current.recognize(dataUrl);
                                if (text.trim().length > 2) {
                                    setOcrText(text.trim());
                                }
                            } catch (e) {
                                // Silent fail for frame error
                            }
                        }
                    }
                }
            }, 1500); // Check every 1.5s

        } catch (err) {
            console.error("Error accessing camera or OCR:", err);
            alert("Could not access camera or initialize OCR. Please check permissions.");
            setIsCameraOpen(false);
        }
    };

    if (isCameraOpen) {
        startCameraAndOCR();
    } else {
        // Cleanup
        if (ocrIntervalRef.current) clearInterval(ocrIntervalRef.current);
        if (workerRef.current) {
            workerRef.current.terminate();
            workerRef.current = null;
        }
        setOcrText('');
    }

    return () => {
        if (stream) {
            stream.getTracks().forEach(track => track.stop());
        }
        if (ocrIntervalRef.current) clearInterval(ocrIntervalRef.current);
        if (workerRef.current) {
            workerRef.current.terminate();
        }
    };
  }, [isCameraOpen, sourceLang]);

  const capturePhoto = () => {
      if (videoRef.current && canvasRef.current) {
          const video = videoRef.current;
          const canvas = canvasRef.current;

          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;

          const ctx = canvas.getContext('2d');
          if (ctx) {
              ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
              // Get Base64 image
              const dataUrl = canvas.toDataURL('image/jpeg');
              // Remove header for API
              const base64Data = dataUrl.split(',')[1];

              setAttachedFile({
                  name: `capture_${Date.now()}.jpg`,
                  mimeType: 'image/jpeg',
                  data: base64Data,
                  isBinary: true
              });

              setIsCameraOpen(false); // Close camera after capture
              setTargetText('');
          }
      }
  };

  const useScannedText = () => {
      if (ocrText) {
          setSourceText(ocrText);
          setIsCameraOpen(false);
      }
  };

  const handleProcess = async () => {
    if (!sourceText.trim() && !attachedFile) return;

    setIsLoading(true);
    let result = "";

    try {
        if (attachedFile) {
            // Document or Image Translation
            result = await translateDocument(
                { 
                    data: attachedFile.data, 
                    mimeType: attachedFile.mimeType, 
                    isBinary: attachedFile.isBinary 
                },
                sourceLang,
                targetLang,
                mode
            );
        } else {
            // Text Translation
            result = await translateText(sourceText, sourceLang, targetLang, mode);
        }
        setTargetText(result);
    } catch (e) {
        setTargetText("Error processing request. Please try again.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
      const file = event.target.files?.[0];
      if (file) {
          // Tier Checks
          if (file.size > tierConfig.maxFileSizeMB * 1024 * 1024) {
              alert(`File too large for ${currentTier} tier. Max size is ${tierConfig.maxFileSizeMB}MB. Please upgrade.`);
              return;
          }

          if (!tierConfig.allowedMimeTypes.includes(file.type) && !file.name.endsWith('.pdf')) {
               // Basic extension check for PDF if mime type fails on some browsers
               if (file.type !== '' || !file.name.toLowerCase().endsWith('.pdf')) {
                   alert(`This file type is not allowed in ${currentTier} tier. Upgrade for more formats.`);
                   return;
               }
          }

          // Determine if we should treat as binary (PDF/Image) or text
          const isBinary = file.type === 'application/pdf' || file.type.startsWith('image/') || file.name.toLowerCase().endsWith('.pdf');

          const reader = new FileReader();

          reader.onload = (e) => {
              let content = e.target?.result as string;

              if (isBinary) {
                  // Strip Data URL prefix
                  content = content.split(',')[1];
              }

              setAttachedFile({
                  name: file.name,
                  mimeType: file.type || 'text/plain',
                  data: content,
                  isBinary: isBinary
              });
              setTargetText(''); // Clear previous result
          };

          reader.onerror = () => {
              alert("Error reading file.");
          };

          if (isBinary) {
              reader.readAsDataURL(file); // Read as base64 for PDF/Images
          } else {
              reader.readAsText(file); // Read as string for Text files
          }
      }
  };

  const handleRemoveFile = () => {
      setAttachedFile(null);
      setTargetText('');
  };

  const handleDownload = () => {
      if (!targetText) return;

      const element = document.createElement("a");
      const file = new Blob([targetText], {type: 'text/plain'});
      element.href = URL.createObjectURL(file);

      // Generate filename based on attached file or default
      let filename = "translation.txt";
      if (attachedFile) {
          const namePart = attachedFile.name.substring(0, attachedFile.name.lastIndexOf('.')) || attachedFile.name;
          filename = `${namePart}_translated.txt`;
      }

      element.download = filename;
      document.body.appendChild(element); // Required for this to work in FireFox
      element.click();
      document.body.removeChild(element);
  };

  const toggleListening = () => {
    if (isListening) {
        recognitionRef.current?.stop();
        setIsListening(false);
    } else {
        if (recognitionRef.current) {
            // Set language if not auto
            if (sourceLang !== 'auto') {
                recognitionRef.current.lang = sourceLang;
            } else {
                recognitionRef.current.lang = 'en-US'; // Default for auto
            }
            try {
                recognitionRef.current.start();
                setIsListening(true);
            } catch (e) {
                console.error("Failed to start recognition:", e);
                setIsListening(false);
            }
        } else {
            alert("Speech recognition not supported in this browser.");
        }
    }
  };

  const handleSpeak = async () => {
      if (!targetText) return;
      setIsPlaying(true);
      await speakText(targetText);
      setIsPlaying(false);
  };

  const handleSwap = () => {
    if (sourceLang === 'auto') return; // Can't swap auto
    const oldSource = sourceLang;
    setSourceLang(targetLang);
    setTargetLang(oldSource);

    if (!attachedFile) {
        setSourceText(targetText);
        setTargetText(sourceText);
    }
  };

  // UI Helper for Button Text
  const getButtonLabel = () => {
      if (attachedFile?.mimeType.startsWith('image/')) return 'Analyze Image';
      return mode === TranslationMode.TRANSLITERATE ? 'Transliterate Doc' : 'Translate Doc';
  };

  return (
    <div className="space-y-6">
      {/* Control Panel */}
      <div className="bg-gray-50 p-6 rounded-xl border border-gray-200 grid grid-cols-1 md:grid-cols-3 gap-6 shadow-sm">
        <div className="flex flex-col gap-2">
          <label className="text-sm font-semibold text-gray-900">Source Language</label>
          <select 
            value={sourceLang}
            onChange={(e) => setSourceLang(e.target.value)}
            className="p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white text-gray-900"
          >
            {SUPPORTED_LANGUAGES.map(l => (
              <option key={`src-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>

        <div className="flex flex-col gap-2 justify-center items-center">
            <button 
                onClick={handleSwap}
                className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                title="Swap Languages"
            >
                <i className="fas fa-exchange-alt"></i>
            </button>
        </div>

        <div className="flex flex-col gap-2">
          <label className="text-sm font-semibold text-gray-900">Target Language</label>
          <select 
            value={targetLang}
            onChange={(e) => setTargetLang(e.target.value)}
            className="p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white text-gray-900"
          >
            {SUPPORTED_LANGUAGES.filter(l => l.code !== 'auto').map(l => (
              <option key={`tgt-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Mode Toggle */}
      <div className="flex justify-center">
        <div className="bg-gray-200 p-1 rounded-full flex gap-1 relative">
             <button
                onClick={() => setMode(TranslationMode.TRANSLATE)}
                className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${mode === TranslationMode.TRANSLATE ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600 hover:text-gray-800'}`}
             >
                <i className="fas fa-language mr-2"></i> Translate
             </button>
             <button
                onClick={() => setMode(TranslationMode.TRANSLITERATE)}
                className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${mode === TranslationMode.TRANSLITERATE ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600 hover:text-gray-800'}`}
             >
                <i className="fas fa-font mr-2"></i> Transliterate
             </button>
        </div>
      </div>

      {/* Text Areas */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative">

        {/* Camera Modal Overlay */}
        {isCameraOpen && (
            <div className="absolute inset-0 z-50 bg-black/90 rounded-2xl flex flex-col items-center justify-center p-4 animate-fade-in">
                <div className="relative w-full max-w-sm aspect-[3/4] bg-black rounded-lg overflow-hidden border border-gray-600 shadow-2xl">
                    <video 
                        ref={videoRef} 
                        autoPlay 
                        playsInline 
                        className="w-full h-full object-cover"
                    />
                    <canvas ref={canvasRef} className="hidden" />

                    {/* OCR Overlay */}
                    <div className="absolute bottom-0 left-0 right-0 bg-black/60 p-3 min-h-[80px] flex flex-col items-center justify-center text-center">
                        {isOcrInitializing ? (
                            <div className="text-white text-xs flex items-center gap-2">
                                <i className="fas fa-circle-notch fa-spin"></i> Initializing OCR Engine...
                            </div>
                        ) : (
                            ocrText ? (
                                <div>
                                    <p className="text-white text-xs font-mono mb-2 line-clamp-3">"{ocrText}"</p>
                                    <button 
                                        onClick={useScannedText}
                                        className="bg-indigo-600 text-white text-[10px] px-3 py-1 rounded-full font-bold hover:bg-indigo-500"
                                    >
                                        Use this Text
                                    </button>
                                </div>
                            ) : (
                                <p className="text-gray-400 text-xs animate-pulse">Scanning for text...</p>
                            )
                        )}
                    </div>
                </div>
                <div className="flex gap-4 mt-6">
                    <button 
                        onClick={() => setIsCameraOpen(false)}
                        className="px-6 py-3 rounded-full bg-gray-700 text-white font-bold hover:bg-gray-600 transition-colors"
                    >
                        Cancel
                    </button>
                    <button 
                        onClick={capturePhoto}
                        className="px-6 py-3 rounded-full bg-white text-black font-bold hover:bg-gray-200 transition-colors flex items-center gap-2"
                    >
                        <i className="fas fa-camera"></i> Capture Photo
                    </button>
                </div>
                <p className="text-white/30 text-[10px] mt-4">Real-time OCR powered by Tesseract.js (Client-side)</p>
            </div>
        )}

        {/* SOURCE AREA */}
        <div className="relative group">
            <div className="flex justify-between mb-2">
                <span className="text-sm font-semibold text-gray-600">Source</span>
                <div className="flex gap-2">
                    {/* Camera Button */}
                     <button
                        onClick={() => setIsCameraOpen(true)}
                        disabled={!!attachedFile}
