from flask import Flask, request, jsonify
from flask_cors import CORS
import requests
from bs4 import BeautifulSoup
import os

app = Flask(__name__)
CORS(app)  # Allow frontend to call this

# Use Zephyr 7B Beta as it is a high-quality free model often available on Inference API
HF_API_URL = "https://api-inference.huggingface.co/models/HuggingFaceH4/zephyr-7b-beta"

@app.route('/scrape', methods=['POST'])
def scrape():
    data = request.json
    url = data.get('url')

    if not url:
        return jsonify({"error": "No URL provided"}), 400

    if not url.startswith('http'):
        return jsonify({"error": "Please provide a valid URL starting with http"}), 400

    try:
        headers = {'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36'}
        response = requests.get(url, headers=headers, timeout=10)

        if response.status_code != 200:
            return jsonify({"error": "Failed to fetch page"}), 500

        soup = BeautifulSoup(response.content, 'html.parser')

        paragraphs = soup.find_all('p')
        text_content = ' '.join([p.get_text() for p in paragraphs])

        summary = text_content[:5000] 

        return jsonify({
            "source": url,
            "title": soup.title.string if soup.title else url,
            "content": summary
        })

    except Exception as e:
        print(f"Scrape error: {e}")
        return jsonify({"error": str(e)}), 500

@app.route('/chat/hf', methods=['POST'])
def chat_hf():
    try:
        data = request.json
        # Forward the request to Hugging Face
        # We don't send an auth header if not present, hoping for free tier access.
        # If the user sets HF_API_KEY env var for this python script, we use it.
        headers = {"Content-Type": "application/json"}
        api_key = os.environ.get("HF_API_KEY")
        if api_key:
            headers["Authorization"] = f"Bearer {api_key}"

        response = requests.post(HF_API_URL, headers=headers, json=data)

        if response.status_code != 200:
             return jsonify({"error": f"HF API Error: {response.text}"}), response.status_code

        return jsonify(response.json())
    except Exception as e:
        print(f"HF Proxy Error: {e}")
        return jsonify({"error": str(e)}), 500

if __name__ == '__main__':
    print("Starting NeuroLingua Backend on port 5000...")
    app.run(port=5000, debug=True)

import { Content } from "@google/genai";

// We try the local python backend first (to avoid CORS), then fall back to direct (which might fail due to CORS/Auth)
const LOCAL_PROXY_URL = "http://localhost:5000/chat/hf";
const DIRECT_API_URL = "https://api-inference.huggingface.co/models/HuggingFaceH4/zephyr-7b-beta";

export const chatWithHuggingFace = async (
    query: string,
    history: Content[],
    systemInstruction: string,
    ragContext?: string
): Promise<string> => {

    // Construct prompt for Zephyr/Mistral format
    // <|system|>\n...</s>\n<|user|>\n...</s>\n<|assistant|>\n...
    let fullPrompt = `<|system|>\n${systemInstruction}\n`;

    if (ragContext) {
        fullPrompt += `CONTEXT INFORMATION:\n${ragContext}\n`;
    }
    fullPrompt += `</s>\n`;

    // Add recent history
    history.slice(-4).forEach(msg => {
        if (msg.role === 'user') fullPrompt += `<|user|>\n${msg.parts[0].text}</s>\n`;
        else fullPrompt += `<|assistant|>\n${msg.parts[0].text}</s>\n`;
    });

    fullPrompt += `<|user|>\n${query}</s>\n<|assistant|>\n`;

    const payload = {
        inputs: fullPrompt,
        parameters: {
            max_new_tokens: 500,
            temperature: 0.7,
            return_full_text: false,
            do_sample: true,
            top_k: 50,
            top_p: 0.95
        }
    };

    // 1. Try Local Proxy
    try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 3000); // Fast fail 3s

        const response = await fetch(LOCAL_PROXY_URL, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payload),
            signal: controller.signal
        });
        clearTimeout(timeoutId);

        if (response.ok) {
            const result = await response.json();
            return result[0]?.generated_text || "No response from Open Source model.";
        }
    } catch (e) {
        console.warn("Local HF Proxy unavailable, trying direct...");
    }

    // 2. Fallback Direct (May have CORS issues without a proxy server or specific browser settings)
    try {
        const response = await fetch(DIRECT_API_URL, {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
                // Note: Direct calls often require a token to avoid rate limits or 401s
                // "Authorization": `Bearer {YOUR_HF_TOKEN}` 
            },
            body: JSON.stringify(payload)
        });

        if (!response.ok) {
            const errText = await response.text();
            if (response.status === 503) {
                 return "Model is loading (Cold Boot). Please try again in 20 seconds.";
            }
            throw new Error(`HF API Error: ${response.status} ${errText}`);
        }

        const result = await response.json();
        return result[0]?.generated_text || "No response from Open Source model.";

    } catch (error) {
        console.error("Hugging Face Error:", error);
        return "Error: Could not connect to Open Source model. Please ensure the Python backend is running (port 5000) for the best experience, or checking your network connection.";
    }
};

import { Content } from "@google/genai";

const LOCAL_PROXY_URL = "http://localhost:5000/chat/hf";

// List of models to try in order. 
// Zephyr is great but sometimes unstable. Mistral is a solid backup.
const MODELS = [
    "HuggingFaceH4/zephyr-7b-beta",
    "mistralai/Mistral-7B-Instruct-v0.2",
    "microsoft/Phi-3-mini-4k-instruct"
];

const getPromptForModel = (modelId: string, query: string, history: Content[], systemInstruction: string, ragContext?: string) => {
    // 1. Zephyr / Phi-3 (ChatML-like)
    if (modelId.includes("zephyr") || modelId.includes("Phi")) {
        let prompt = `<|system|>\n${systemInstruction}\n`;
        if (ragContext) prompt += `CONTEXT:\n${ragContext}\n`;
        prompt += `</s>\n`;

        history.slice(-4).forEach(msg => {
             const role = msg.role === 'user' ? 'user' : 'assistant';
             prompt += `<|${role}|>\n${msg.parts[0].text}</s>\n`;
        });
        prompt += `<|user|>\n${query}</s>\n<|assistant|>\n`;
        return prompt;
    }

    // 2. Mistral (Inst format)
    if (modelId.includes("Mistral")) {
        let prompt = `<s>[INST] ${systemInstruction}\n`;
        if (ragContext) prompt += `CONTEXT:\n${ragContext}\n\n`;

        history.slice(-4).forEach(msg => {
            if (msg.role === 'user') prompt += `User: ${msg.parts[0].text}\n`;
            else prompt += `Assistant: ${msg.parts[0].text}\n`;
        });

        prompt += `User: ${query} [/INST]`;
        return prompt;
    }

    // Default
    return `${systemInstruction}\n\n${ragContext ? "Context: " + ragContext + "\n\n" : ""}User: ${query}\nAssistant:`;
};

export const chatWithHuggingFace = async (
    query: string,
    history: Content[],
    systemInstruction: string,
    ragContext?: string
): Promise<string> => {

    // 1. Try Local Proxy (Fastest if available, avoids CORS)
    try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 2000); // 2s check

        // Construct a generic prompt for the default backend model (Zephyr)
        const prompt = getPromptForModel("HuggingFaceH4/zephyr-7b-beta", query, history, systemInstruction, ragContext);

        const response = await fetch(LOCAL_PROXY_URL, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                inputs: prompt,
                parameters: { max_new_tokens: 512, temperature: 0.7, return_full_text: false }
            }),
            signal: controller.signal
        });
        clearTimeout(timeoutId);

        if (response.ok) {
            const result = await response.json();
            return result[0]?.generated_text || result.error || "No response from local backend.";
        }
    } catch (e) {
        // console.warn("Local backend unreachable, switching to direct API...");
    }

    // 2. Fallback: Rotate through Direct APIs
    for (const model of MODELS) {
        const apiUrl = `https://api-inference.huggingface.co/models/${model}`;
        const prompt = getPromptForModel(model, query, history, systemInstruction, ragContext);

        try {
            console.log(`Attempting connection to ${model}...`);
            const response = await fetch(apiUrl, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    inputs: prompt,
                    parameters: { 
                        max_new_tokens: 512, 
                        temperature: 0.7, 
                        return_full_text: false,
                        do_sample: true 
                    }
                })
            });

            if (response.status === 503) {
                console.warn(`${model} is loading... trying next.`);
                continue; // Model loading, try next
            }

            if (!response.ok) {
                throw new Error(`Status ${response.status}`);
            }

            const result = await response.json();
            if (Array.isArray(result) && result[0]?.generated_text) {
                return result[0].generated_text;
            }

        } catch (err) {
            console.warn(`Failed to fetch ${model}:`, err);
            // Continue to next model
        }
    }

    return "Error: All Open Source models are currently busy or unreachable. Please try again later or ensure the local python backend is running.";
};

import React, { useState, useEffect, useRef } from 'react';
import { TranslationMode, SUPPORTED_LANGUAGES, Tier } from '../types';
import { translateText, translateDocument, speakText } from '../services/geminiService';
import { useTier } from '../contexts/TierContext';
import { createWorker } from 'tesseract.js';

// Polyfill type for SpeechRecognition
declare global {
    interface Window {
        webkitSpeechRecognition: any;
        SpeechRecognition: any;
    }
}

interface AttachedFile {
    name: string;
    mimeType: string;
    data: string; // Base64 (for binary) OR Raw Text (for text files)
    isBinary: boolean;
}

const getTesseractLang = (code: string) => {
    // Extended language support
    const map: Record<string, string> = {
        'en': 'eng', 'es': 'spa', 'fr': 'fra', 'de': 'deu',
        'it': 'ita', 'pt': 'por', 'ru': 'rus', 'zh': 'chi_sim',
        'ja': 'jpn', 'ko': 'kor', 'hi': 'hin', 'bn': 'ben',
        'ar': 'ara', 'tr': 'tur', 'pl': 'pol', 'nl': 'nld'
    };
    return map[code] || 'eng';
};

const Translator: React.FC = () => {
  const { tierConfig, currentTier } = useTier();

  const [sourceText, setSourceText] = useState('');
  const [targetText, setTargetText] = useState('');
  const [sourceLang, setSourceLang] = useState('auto');
  const [targetLang, setTargetLang] = useState('es');
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TRANSLATE);
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);

  // Camera State
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [ocrText, setOcrText] = useState('');
  const [isOcrInitializing, setIsOcrInitializing] = useState(false);
  const [ocrConfidence, setOcrConfidence] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null); // For capturing frame
  const overlayRef = useRef<HTMLCanvasElement>(null); // For drawing boxes
  const recognitionRef = useRef<any>(null);
  const workerRef = useRef<any>(null);
  const ocrIntervalRef = useRef<any>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = false;

            recognitionRef.current.onresult = (event: any) => {
                const transcript = event.results[0][0].transcript;
                setSourceText(transcript);
                setIsListening(false);
            };

            recognitionRef.current.onerror = (event: any) => {
                console.error("Speech Recognition Error:", event.error);
                setIsListening(false);
            };

            recognitionRef.current.onend = () => {
                setIsListening(false);
            };
        } catch (e) {
            console.error("Speech Recognition setup failed:", e);
        }
    }
  }, []);

  // Debounce translation trigger for text
  useEffect(() => {
    const timer = setTimeout(() => {
      if (sourceText.length > 1 && !attachedFile) { 
        handleProcess();
      }
    }, 1000);
    return () => clearTimeout(timer);
  }, [sourceText, sourceLang, targetLang, mode]);

  // Handle Camera Stream & OCR
  useEffect(() => {
    let stream: MediaStream | null = null;

    const startCameraAndOCR = async () => {
        try {
            stream = await navigator.mediaDevices.getUserMedia({ 
                video: { facingMode: 'environment' } 
            });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }

            // Init OCR Worker
            setIsOcrInitializing(true);
            const langCode = sourceLang === 'auto' ? 'en' : sourceLang;
            const tLang = getTesseractLang(langCode);

            // Re-create worker if language changes
            if (workerRef.current) {
                await workerRef.current.terminate();
            }

            const worker = await createWorker(tLang);
            workerRef.current = worker;
            setIsOcrInitializing(false);

            // Start OCR Loop
            ocrIntervalRef.current = setInterval(async () => {
                if (videoRef.current && canvasRef.current && workerRef.current) {
                    const video = videoRef.current;
                    const canvas = canvasRef.current;
                    const overlay = overlayRef.current;

                    if (video.readyState === video.HAVE_ENOUGH_DATA) {
                        // Capture Frame
                        canvas.width = video.videoWidth;
                        canvas.height = video.videoHeight;
                        const ctx = canvas.getContext('2d');
                        if (!ctx) return;

                        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
                        const dataUrl = canvas.toDataURL('image/jpeg', 0.5);

                        try {
                            const { data } = await workerRef.current.recognize(dataUrl);

                            if (data.text.trim().length > 1) {
                                setOcrText(data.text.trim());
                                setOcrConfidence(data.confidence);
                            }

                            // Draw Bounding Boxes on Overlay
                            if (overlay) {
                                overlay.width = video.clientWidth;
                                overlay.height = video.clientHeight;
                                const oCtx = overlay.getContext('2d');
                                if (oCtx) {
                                    oCtx.clearRect(0, 0, overlay.width, overlay.height);

                                    // Scale factors (Video Source -> Displayed Size)
                                    // Assuming object-contain or similar aspect ratio preservation
                                    // We need to calculate the actual displayed rect of the video within the element
                                    // This is complex, so we will use object-fill or match dimensions for simplicity in this demo,
                                    // OR we calculate the scale simply:
                                    const scaleX = overlay.width / video.videoWidth;
                                    const scaleY = overlay.height / video.videoHeight;

                                    oCtx.strokeStyle = '#4F46E5'; // Indigo-600
                                    oCtx.lineWidth = 2;
                                    oCtx.fillStyle = 'rgba(79, 70, 229, 0.1)';

                                    data.words.forEach((word: any) => {
                                        if (word.confidence > 60) {
                                            const { x0, y0, x1, y1 } = word.bbox;
                                            const w = (x1 - x0) * scaleX;
                                            const h = (y1 - y0) * scaleY;
                                            const x = x0 * scaleX;
                                            const y = y0 * scaleY;

                                            oCtx.beginPath();
                                            oCtx.rect(x, y, w, h);
                                            oCtx.stroke();
                                            oCtx.fill();
                                        }
                                    });
                                }
                            }

                        } catch (e) {
                            // console.debug("OCR Frame Error", e);
                        }
                    }
                }
            }, 1000); // 1s interval

        } catch (err) {
            console.error("Error accessing camera or OCR:", err);
            alert("Could not access camera or initialize OCR.");
            setIsCameraOpen(false);
        }
    };

    if (isCameraOpen) {
        startCameraAndOCR();
    } else {
        if (ocrIntervalRef.current) clearInterval(ocrIntervalRef.current);
        if (workerRef.current) {
            workerRef.current.terminate();
            workerRef.current = null;
        }
        setOcrText('');
    }

    return () => {
        if (stream) {
            stream.getTracks().forEach(track => track.stop());
        }
        if (ocrIntervalRef.current) clearInterval(ocrIntervalRef.current);
        // Don't terminate worker here to allow quick re-open? No, safer to clean up.
        if (workerRef.current) workerRef.current.terminate();
    };
  }, [isCameraOpen, sourceLang]);

  const capturePhoto = () => {
      if (videoRef.current && canvasRef.current) {
          const video = videoRef.current;
          const canvas = canvasRef.current;

          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          const ctx = canvas.getContext('2d');
          if (ctx) {
              ctx.drawImage(video, 0, 0);
              const dataUrl = canvas.toDataURL('image/jpeg');
              const base64Data = dataUrl.split(',')[1];

              setAttachedFile({
                  name: `capture_${Date.now()}.jpg`,
                  mimeType: 'image/jpeg',
                  data: base64Data,
                  isBinary: true
              });
              setIsCameraOpen(false);
              setTargetText('');
          }
      }
  };

  const useScannedText = () => {
      if (ocrText) {
          setSourceText(ocrText);
          setIsCameraOpen(false);
      }
  };

  const handleProcess = async () => {
    if (!sourceText.trim() && !attachedFile) return;
    setIsLoading(true);
    let result = "";

    try {
        if (attachedFile) {
            result = await translateDocument(
                { data: attachedFile.data, mimeType: attachedFile.mimeType, isBinary: attachedFile.isBinary },
                sourceLang, targetLang, mode
            );
        } else {
            result = await translateText(sourceText, sourceLang, targetLang, mode);
        }
        setTargetText(result);
    } catch (e) {
        setTargetText("Error processing request. Please try again.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
      const file = event.target.files?.[0];
      if (file) {
          if (file.size > tierConfig.maxFileSizeMB * 1024 * 1024) {
              alert(`File too large for ${currentTier} tier.`);
              return;
          }
          const reader = new FileReader();
          reader.onload = (e) => {
              const content = e.target?.result as string;
              setAttachedFile({
                  name: file.name,
                  mimeType: file.type || 'text/plain',
                  data: file.type.startsWith('image/') || file.type.includes('pdf') ? content.split(',')[1] : content,
                  isBinary: file.type.startsWith('image/') || file.type.includes('pdf')
              });
              setTargetText('');
          };
          if (file.type.startsWith('image/') || file.type.includes('pdf')) reader.readAsDataURL(file);
          else reader.readAsText(file);
      }
  };

  // ... (Other handlers: handleRemoveFile, handleDownload, toggleListening, handleSpeak, handleSwap)
  const handleRemoveFile = () => { setAttachedFile(null); setTargetText(''); };
  const handleDownload = () => {
      if (!targetText) return;
      const element = document.createElement("a");
      const file = new Blob([targetText], {type: 'text/plain'});
      element.href = URL.createObjectURL(file);
      element.download = "translation.txt";
      document.body.appendChild(element); element.click(); document.body.removeChild(element);
  };
  const toggleListening = () => {
    if (isListening) { recognitionRef.current?.stop(); setIsListening(false); }
    else { recognitionRef.current?.start(); setIsListening(true); }
  };
  const handleSpeak = async () => {
      if (!targetText) return;
      setIsPlaying(true);
      await speakText(targetText);
      setIsPlaying(false);
  };
  const handleSwap = () => {
    if (sourceLang === 'auto') return;
    const oldSource = sourceLang; setSourceLang(targetLang); setTargetLang(oldSource);
    if (!attachedFile) { setSourceText(targetText); setTargetText(sourceText); }
  };
  const getButtonLabel = () => {
      if (attachedFile?.mimeType.startsWith('image/')) return 'Analyze Image';
