  // --- Chat Logic ---
  const handleSendMessage = async () => {
    if (!inputValue.trim()) return;

    const userMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'user',
        content: inputValue,
        timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsProcessing(true);

    try {
        const history = messages.map(m => ({
            role: m.role,
            parts: [{ text: m.content }]
        }));

        // 1. Retrieval (RAG)
        let ragContext = "";
        if (useRAG && !file) {
            const docs = await vectorStore.similaritySearch(userMsg.content);
            if (docs.length > 0) {
                ragContext = docs.map(d => `Source: ${d.source}\n${d.text}`).join('\n\n');
            }
        }

        // 2. Generation (Provider Switch)
        let responseText = "";
        let sources = undefined;

        if (provider === LLMProvider.GEMINI) {
            const result = await chatHybrid(
                userMsg.content, 
                history, 
                file || undefined, 
                links, 
                persona,
                ragContext
            );
            responseText = result.text;
            sources = result.sources;
        } else {
            // Hugging Face Fallback
            responseText = await chatWithHuggingFace(
                userMsg.content,
                history,
                `You are a ${persona}.`,
                ragContext
            );
        }

        const botMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: 'model',
            content: responseText,
            timestamp: Date.now(),
            sources: sources,
            provider: provider
        };

        setMessages(prev => [...prev, botMsg]);
    } catch (e) {
        setMessages(prev => [...prev, {
            id: (Date.now() + 1).toString(),
            role: 'model',
            content: "Error processing request.",
            timestamp: Date.now()
        }]);
    } finally {
        setIsProcessing(false);
    }
  };

  return (
    <div className="flex flex-col h-full md:gap-4 relative">

        {/* Controls Bar */}
        <div className="flex flex-col xl:flex-row gap-3 p-2 bg-white/50 rounded-2xl border border-white/60 flex-shrink-0">

            {/* Persona Selector */}
            <div className="flex-1 overflow-x-auto flex gap-1 no-scrollbar">
                {Object.values(ChatPersona).map((p) => (
                    <button
                        key={p}
                        onClick={() => setPersona(p)}
                        className={`px-3 py-1.5 rounded-lg text-xs font-semibold whitespace-nowrap transition-all ${
                            persona === p ? 'bg-indigo-600 text-white shadow' : 'bg-white text-gray-600 hover:bg-indigo-50'
                        }`}
                    >
                        {p}
                    </button>
                ))}
            </div>

            <div className="flex items-center gap-2 border-t md:border-t-0 md:border-l border-gray-200 pt-2 md:pt-0 md:pl-2">
                {/* Model Toggle */}
                <button 
                    onClick={() => setProvider(provider === LLMProvider.GEMINI ? LLMProvider.HUGGING_FACE : LLMProvider.GEMINI)}
                    className="flex-1 md:flex-none flex items-center justify-center gap-2 px-3 py-1.5 bg-white border border-gray-200 rounded-lg text-xs font-bold text-gray-700 hover:border-indigo-300 transition-colors"
                >
                    <i className={`fas ${provider === LLMProvider.GEMINI ? 'fa-gem' : 'fa-robot'} ${provider === LLMProvider.GEMINI ? 'text-indigo-600' : 'text-orange-500'}`}></i>
                    {provider === LLMProvider.GEMINI ? 'Gemini' : 'Mistral'}
                </button>

                {/* RAG Toggle */}
                {!file && (
                    <button 
                        onClick={() => setUseRAG(!useRAG)}
                        className={`w-8 h-5 rounded-full relative transition-colors ${useRAG ? 'bg-green-500' : 'bg-gray-300'}`}
                        title="Toggle Knowledge Base RAG"
                    >
                        <div className={`w-3 h-3 bg-white rounded-full absolute top-1 transition-all ${useRAG ? 'left-4' : 'left-1'}`}></div>
                    </button>
                )}
            </div>
        </div>

        {/* Chat Area */}
        <div className="flex-1 flex flex-col md:bg-white/40 md:border md:border-white/60 md:rounded-3xl md:shadow-sm md:backdrop-blur-sm relative overflow-hidden">
            <div className="flex-1 overflow-y-auto p-4 space-y-4 pb-24 md:pb-4">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                        <div className={`max-w-[85%] rounded-2xl p-4 shadow-sm ${
