import React, { useState, useEffect, useRef } from 'react';
import { TranslationMode, SUPPORTED_LANGUAGES, Tier } from '../types';
import { translateText, translateDocument, speakText } from '../services/geminiService';
import { useTier } from '../contexts/TierContext';
import { createWorker } from 'tesseract.js';

// Polyfill type for SpeechRecognition
declare global {
    interface Window {
        webkitSpeechRecognition: any;
        SpeechRecognition: any;
    }
}

interface AttachedFile {
    name: string;
    mimeType: string;
    data: string; // Base64 (for binary) OR Raw Text (for text files)
    isBinary: boolean;
}

const getTesseractLang = (code: string) => {
    // Extended language support
    const map: Record<string, string> = {
        'en': 'eng', 'es': 'spa', 'fr': 'fra', 'de': 'deu',
        'it': 'ita', 'pt': 'por', 'ru': 'rus', 'zh': 'chi_sim',
        'ja': 'jpn', 'ko': 'kor', 'hi': 'hin', 'bn': 'ben',
        'ar': 'ara', 'tr': 'tur', 'pl': 'pol', 'nl': 'nld'
    };
    return map[code] || 'eng';
};

// Simple stop-word based language detection
const STOP_WORDS: Record<string, string[]> = {
    'en': ['the', 'and', 'is', 'in', 'to', 'of', 'it', 'you', 'that', 'for'],
    'es': ['el', 'la', 'de', 'que', 'en', 'y', 'a', 'los', 'del', 'las', 'por', 'un'],
    'fr': ['le', 'la', 'les', 'de', 'et', 'est', 'un', 'une', 'du', 'en', 'qui'],
    'de': ['der', 'die', 'das', 'und', 'ist', 'in', 'zu', 'den', 'von', 'mit'],
    'it': ['il', 'la', 'che', 'di', 'e', 'in', 'un', 'per', 'sono', 'mi'],
    'pt': ['o', 'a', 'de', 'que', 'e', 'do', 'da', 'em', 'um', 'para']
};

const detectLanguage = (text: string): string | null => {
    const lowerText = text.toLowerCase();
    const tokens = lowerText.split(/[\s,.;!?]+/);

    let bestLang = null;
    let maxMatches = 0;

    for (const [lang, words] of Object.entries(STOP_WORDS)) {
        const matches = tokens.filter(t => words.includes(t)).length;
        if (matches > maxMatches) {
            maxMatches = matches;
            bestLang = lang;
        }
    }
    return maxMatches >= 2 ? bestLang : null;
};

const Translator: React.FC = () => {
  const { tierConfig, currentTier } = useTier();

  const [sourceText, setSourceText] = useState('');
  const [targetText, setTargetText] = useState('');
  const [sourceLang, setSourceLang] = useState('auto');
  const [targetLang, setTargetLang] = useState('es');
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TRANSLATE);
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);

  // Camera State
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [ocrText, setOcrText] = useState('');
  const [isOcrInitializing, setIsOcrInitializing] = useState(false);
  const [ocrConfidence, setOcrConfidence] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null); 
  const overlayRef = useRef<HTMLCanvasElement>(null);
  const recognitionRef = useRef<any>(null);
  const workerRef = useRef<any>(null);
  const ocrIntervalRef = useRef<any>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = false;

            recognitionRef.current.onresult = (event: any) => {
                const transcript = event.results[0][0].transcript;
                setSourceText(transcript);
                setIsListening(false);
            };

            recognitionRef.current.onerror = (event: any) => {
                console.error("Speech Recognition Error:", event.error);
                setIsListening(false);
            };

            recognitionRef.current.onend = () => {
                setIsListening(false);
            };
        } catch (e) {
            console.error("Speech Recognition setup failed:", e);
        }
    }
  }, []);

  // Debounce translation trigger
  useEffect(() => {
    const timer = setTimeout(() => {
      if (sourceText.length > 1 && !attachedFile) { 
        handleProcess();
      }
    }, 1000);
    return () => clearTimeout(timer);
  }, [sourceText, sourceLang, targetLang, mode]);

  // Handle Camera Stream & OCR
  useEffect(() => {
    let stream: MediaStream | null = null;

    const startCameraAndOCR = async () => {
        try {
            stream = await navigator.mediaDevices.getUserMedia({ 
                video: { facingMode: 'environment' } 
            });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }

            setIsOcrInitializing(true);
            const tLang = sourceLang === 'auto' ? 'eng+spa+fra+deu' : getTesseractLang(sourceLang);

            if (workerRef.current) await workerRef.current.terminate();

            const worker = await createWorker(tLang);
            workerRef.current = worker;
            setIsOcrInitializing(false);

            ocrIntervalRef.current = setInterval(async () => {
                if (videoRef.current && canvasRef.current && workerRef.current) {
                    const video = videoRef.current;
                    const canvas = canvasRef.current;
                    const overlay = overlayRef.current;

                    if (video.readyState === video.HAVE_ENOUGH_DATA) {
                        canvas.width = video.videoWidth;
                        canvas.height = video.videoHeight;
                        const ctx = canvas.getContext('2d');
                        if (!ctx) return;

                        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
                        const dataUrl = canvas.toDataURL('image/jpeg', 0.5);

                        try {
                            const { data } = await workerRef.current.recognize(dataUrl);

                            if (sourceLang === 'auto' && data.text.trim().length > 15) {
                                const detected = detectLanguage(data.text);
                                if (detected) {
                                    setSourceLang(detected);
                                    return;
                                }
                            }

                            if (data.text.trim().length > 1) {
                                setOcrText(data.text.trim());
                                setOcrConfidence(data.confidence);
                            }

                            if (overlay) {
                                overlay.width = video.clientWidth;
                                overlay.height = video.clientHeight;
                                const oCtx = overlay.getContext('2d');
                                if (oCtx) {
                                    oCtx.clearRect(0, 0, overlay.width, overlay.height);
                                    const scaleX = overlay.width / video.videoWidth;
                                    const scaleY = overlay.height / video.videoHeight;

                                    data.words.forEach((word: any) => {
                                        if (word.confidence > 50) {
                                            const { x0, y0, x1, y1 } = word.bbox;
                                            const w = (x1 - x0) * scaleX;
                                            const h = (y1 - y0) * scaleY;
                                            const x = x0 * scaleX;
                                            const y = y0 * scaleY;

                                            oCtx.beginPath();
                                            if (oCtx.roundRect) oCtx.roundRect(x, y, w, h, 4);
                                            else oCtx.rect(x, y, w, h);

                                            oCtx.strokeStyle = `rgba(6, 182, 212, ${word.confidence / 100})`; 
                                            oCtx.lineWidth = 2;
                                            oCtx.shadowColor = "#06B6D4";
                                            oCtx.shadowBlur = 8;
                                            oCtx.stroke();
                                            oCtx.shadowBlur = 0;

                                            if (word.confidence > 75) {
                                                const fontSize = 10;
                                                oCtx.font = `bold ${fontSize}px sans-serif`;
                                                const textWidth = oCtx.measureText(word.text).width;
                                                oCtx.fillStyle = "rgba(6, 182, 212, 0.9)";
                                                oCtx.fillRect(x, y - fontSize - 6, textWidth + 8, fontSize + 4);
                                                oCtx.fillStyle = "#FFFFFF";
                                                oCtx.fillText(word.text, x + 4, y - 6);
                                            }
                                        }
                                    });
                                }
                            }

                        } catch (e) {
                            // console.debug("OCR Frame Error", e);
                        }
                    }
                }
            }, 1000);

        } catch (err) {
            console.error("Error accessing camera or OCR:", err);
            alert("Could not access camera. Ensure you have allowed permissions.");
            setIsCameraOpen(false);
        }
    };

    if (isCameraOpen) {
        startCameraAndOCR();
    } else {
        if (ocrIntervalRef.current) clearInterval(ocrIntervalRef.current);
        if (workerRef.current) {
            workerRef.current.terminate();
            workerRef.current = null;
        }
        setOcrText('');
    }

    return () => {
        if (stream) stream.getTracks().forEach(track => track.stop());
        if (ocrIntervalRef.current) clearInterval(ocrIntervalRef.current);
        if (workerRef.current) workerRef.current.terminate();
    };
  }, [isCameraOpen, sourceLang]);

  const capturePhoto = () => {
      if (videoRef.current && canvasRef.current) {
          const video = videoRef.current;
          const canvas = canvasRef.current;
          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          const ctx = canvas.getContext('2d');
          if (ctx) {
              ctx.drawImage(video, 0, 0);
              const dataUrl = canvas.toDataURL('image/jpeg');
              const base64Data = dataUrl.split(',')[1];

              setAttachedFile({
                  name: `capture_${Date.now()}.jpg`,
                  mimeType: 'image/jpeg',
                  data: base64Data,
                  isBinary: true
              });
              setIsCameraOpen(false);
              setTargetText('');
          }
      }
  };

  const useScannedText = () => {
      if (ocrText) {
          setSourceText(ocrText);
          setIsCameraOpen(false);
      }
  };

  const handleProcess = async () => {
    if (!sourceText.trim() && !attachedFile) return;
    setIsLoading(true);
    let result = "";

    try {
        if (attachedFile) {
            result = await translateDocument(
                { data: attachedFile.data, mimeType: attachedFile.mimeType, isBinary: attachedFile.isBinary },
                sourceLang, targetLang, mode
            );
        } else {
            result = await translateText(sourceText, sourceLang, targetLang, mode);
        }
        setTargetText(result);
    } catch (e) {
        setTargetText("Error processing request.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
      const file = event.target.files?.[0];
      if (file) {
          if (file.size > tierConfig.maxFileSizeMB * 1024 * 1024) {
              alert(`File too large for ${currentTier} tier.`);
              return;
          }
          const reader = new FileReader();
          reader.onload = (e) => {
              const content = e.target?.result as string;
              setAttachedFile({
                  name: file.name,
                  mimeType: file.type || 'text/plain',
                  data: file.type.startsWith('image/') || file.type.includes('pdf') ? content.split(',')[1] : content,
                  isBinary: file.type.startsWith('image/') || file.type.includes('pdf')
              });
              setTargetText('');
          };
          if (file.type.startsWith('image/') || file.type.includes('pdf')) reader.readAsDataURL(file);
          else reader.readAsText(file);
      }
  };

  const handleRemoveFile = () => { setAttachedFile(null); setTargetText(''); };
  const handleDownload = () => {
      if (!targetText) return;
      const element = document.createElement("a");
      const file = new Blob([targetText], {type: 'text/plain'});
      element.href = URL.createObjectURL(file);
      element.download = "translation.txt";
      document.body.appendChild(element); element.click(); document.body.removeChild(element);
  };
  const toggleListening = () => {
    if (isListening) { recognitionRef.current?.stop(); setIsListening(false); }
    else { recognitionRef.current?.start(); setIsListening(true); }
  };
  const handleSpeak = async () => {
      if (!targetText) return;
      setIsPlaying(true);
      await speakText(targetText);
      setIsPlaying(false);
  };
  const handleSwap = () => {
    if (sourceLang === 'auto') return;
    const oldSource = sourceLang; setSourceLang(targetLang); setTargetLang(oldSource);
    if (!attachedFile) { setSourceText(targetText); setTargetText(sourceText); }
  };
  const getButtonLabel = () => {
      if (attachedFile?.mimeType.startsWith('image/')) return 'Analyze';
      return mode === TranslationMode.TRANSLITERATE ? 'Transliterate' : 'Translate';
  };

  return (
    <div className="flex flex-col h-full gap-4">
      {/* Control Panel */}
      <div className="bg-white md:bg-gray-50 p-4 rounded-xl border border-gray-100 md:border-gray-200 grid grid-cols-1 md:grid-cols-3 gap-3 shadow-sm flex-shrink-0">
        <div className="flex flex-col gap-1">
          <label className="text-[10px] font-bold text-gray-500 uppercase">Source (OCR)</label>
          <select 
            value={sourceLang}
            onChange={(e) => setSourceLang(e.target.value)}
            className="p-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white text-gray-900 text-sm font-medium shadow-sm w-full"
          >
            {SUPPORTED_LANGUAGES.map(l => (
              <option key={`src-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>

        <div className="flex flex-col justify-end items-center pb-1">
             <div className="bg-gray-100 p-0.5 rounded-full flex gap-1 relative w-full md:w-auto">
                 <button onClick={() => setMode(TranslationMode.TRANSLATE)} className={`flex-1 md:flex-none px-3 py-1.5 rounded-full text-xs font-bold transition-all ${mode === TranslationMode.TRANSLATE ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500'}`}>Translate</button>
                 <button onClick={() => setMode(TranslationMode.TRANSLITERATE)} className={`flex-1 md:flex-none px-3 py-1.5 rounded-full text-xs font-bold transition-all ${mode === TranslationMode.TRANSLITERATE ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500'}`}>Translit</button>
            </div>
        </div>

        <div className="flex flex-col gap-1">
          <label className="text-[10px] font-bold text-gray-500 uppercase">Target</label>
          <select 
            value={targetLang}
            onChange={(e) => setTargetLang(e.target.value)}
            className="p-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white text-gray-900 text-sm font-medium shadow-sm w-full"
          >
            {SUPPORTED_LANGUAGES.filter(l => l.code !== 'auto').map(l => (
              <option key={`tgt-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Main Content Area - Flexible Height */}
      <div className="flex-1 flex flex-col md:flex-row gap-4 min-h-0">

        {/* Full Screen Camera Modal for Mobile */}
        {isCameraOpen && (
            <div className="fixed inset-0 z-50 bg-black flex flex-col items-center justify-center animate-fade-in">
                <div className="relative w-full h-full flex flex-col">
                    <video 
                        ref={videoRef} 
                        autoPlay 
                        playsInline 
                        muted
                        className="w-full h-full object-fill md:object-contain bg-black" 
                    />
                    <canvas ref={canvasRef} className="hidden" />
                    <canvas ref={overlayRef} className="absolute inset-0 w-full h-full pointer-events-none" />

                    {/* Top Bar */}
                    <div className="absolute top-0 left-0 right-0 p-6 flex justify-between items-start bg-gradient-to-b from-black/80 to-transparent">
                         <div className="text-white">
                             <h3 className="font-bold text-lg">AI Vision</h3>
                             <p className="text-xs text-indigo-400 font-mono">{isOcrInitializing ? "Initializing..." : "Scanning..."}</p>
                         </div>
                         <button onClick={() => setIsCameraOpen(false)} className="bg-white/10 p-3 rounded-full text-white backdrop-blur-md">
                             <i className="fas fa-times"></i>
                         </button>
                    </div>

                    {/* Bottom OCR Preview */}
                    <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-black via-black/90 to-transparent flex flex-col gap-4">
                        <div className="bg-white/10 backdrop-blur-md p-4 rounded-2xl border border-white/10">
                             <div className="flex justify-between items-center text-[10px] text-gray-400 uppercase tracking-wider font-bold mb-2">
                                <span>Detected Text</span>
                                {ocrConfidence > 0 && <span>Conf: {ocrConfidence.toFixed(0)}%</span>}
                            </div>
                            <p className="text-white text-sm font-medium line-clamp-3">
                                {ocrText || <span className="text-gray-500 italic">Point at text...</span>}
                            </p>
                        </div>

                        <div className="flex gap-4">
                            {ocrText && (
                                <button onClick={useScannedText} className="flex-1 bg-white text-black py-4 rounded-xl font-bold flex items-center justify-center gap-2">
                                    <i className="fas fa-check"></i> Use Text
                                </button>
                            )}
                            <button onClick={capturePhoto} className={`flex-1 py-4 rounded-xl font-bold flex items-center justify-center gap-2 ${ocrText ? 'bg-indigo-600 text-white' : 'bg-white text-black w-full'}`}>
                                <i className="fas fa-camera"></i> Capture
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}

        {/* SOURCE AREA */}
        <div className="flex-1 relative group flex flex-col">
            <div className="flex justify-between mb-2 px-1 flex-shrink-0">
                <span className="text-xs font-bold text-gray-500 uppercase">Source</span>
                <div className="flex gap-3">
                     <button onClick={() => setIsCameraOpen(true)} disabled={!!attachedFile} className={`text-xs flex items-center gap-1 font-bold transition-colors ${attachedFile ? 'opacity-30' : 'text-indigo-600'}`}>
                        <i className="fas fa-camera"></i> <span className="hidden sm:inline">Camera</span>
                    </button>
                     <label className={`cursor-pointer text-xs flex items-center gap-1 font-bold transition-colors ${attachedFile ? 'text-indigo-600' : 'text-gray-500 hover:text-indigo-600'}`}>
                        <input type="file" className="hidden" accept={tierConfig.allowedMimeTypes.join(',')} onChange={handleFileUpload} />
                        <i className="fas fa-paperclip"></i> {attachedFile ? ' Change' : ' Attach'}
                    </label>
                    <button onClick={toggleListening} disabled={!!attachedFile} className={`text-xs flex items-center gap-1 font-bold transition-colors ${isListening ? 'text-red-600 animate-pulse' : 'text-gray-500 hover:text-indigo-600'}`}>
                        <i className={`fas fa-microphone${isListening ? '' : '-slash'}`}></i> <span className="hidden sm:inline">Voice</span>
                    </button>
                </div>
            </div>

            <div className="flex-1 relative min-h-[150px]">
                {attachedFile ? (
                    <div className="absolute inset-0 z-10 bg-indigo-50 border-2 border-indigo-200 border-dashed rounded-2xl flex flex-col items-center justify-center p-6 text-center animate-fade-in">
                        <div className="bg-white p-3 rounded-full shadow-sm mb-3 text-indigo-600 text-xl"><i className={`fas ${attachedFile.mimeType.startsWith('image/') ? 'fa-image' : 'fa-file-alt'}`}></i></div>
                        <h4 className="font-bold text-gray-900 break-all max-w-full mb-1 text-sm">{attachedFile.name}</h4>
                        {attachedFile.mimeType.startsWith('image/') && (
                             <div className="w-16 h-16 mb-4 rounded-lg overflow-hidden border border-gray-300 shadow-sm">
                                 <img src={`data:${attachedFile.mimeType};base64,${attachedFile.data}`} alt="Preview" className="w-full h-full object-cover" />
                             </div>
                        )}
                        <div className="flex gap-2">
                             <button onClick={handleProcess} disabled={isLoading} className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-indigo-700 shadow-sm">{isLoading ? <i className="fas fa-spinner fa-spin"></i> : getButtonLabel()}</button>
                             <button onClick={handleRemoveFile} className="bg-white text-red-500 border border-red-200 px-4 py-2 rounded-lg text-sm font-bold hover:bg-red-50">Remove</button>
                        </div>
                    </div>
                ) : (
                    <textarea value={sourceText} onChange={(e) => setSourceText(e.target.value)} placeholder="Type here..." className="w-full h-full p-4 rounded-2xl border border-gray-200 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none resize-none shadow-sm text-base bg-white text-gray-900"></textarea>
                )}
            </div>
        </div>

        {/* TARGET AREA */}
        <div className="flex-1 relative group flex flex-col">
            <div className="flex justify-between mb-2 px-1 flex-shrink-0">
                <span className="text-xs font-bold text-gray-500 uppercase">Result</span>
                <div className="flex gap-3">
                     <button onClick={handleDownload} disabled={!targetText} className={`text-xs font-bold flex items-center gap-1 ${targetText ? 'text-indigo-600' : 'text-gray-300'}`}><i className="fas fa-download"></i> <span className="hidden sm:inline">Save</span></button>
                     <button onClick={handleSpeak} disabled={!targetText} className={`text-xs font-bold flex items-center gap-1 ${isPlaying ? 'text-green-600' : 'text-gray-500 hover:text-indigo-600'}`}><i className={`fas fa-volume-${isPlaying ? 'up' : 'off'}`}></i> <span className="hidden sm:inline">Listen</span></button>
                     <button onClick={() => navigator.clipboard.writeText(targetText)} className="text-xs text-indigo-600 hover:text-indigo-800 font-medium"><i className="fas fa-copy mr-1"></i> Copy</button>
                </div>
            </div>
            <div className="flex-1 min-h-[150px]">
                 <textarea readOnly value={targetText} placeholder="..." className="w-full h-full p-4 rounded-2xl border border-gray-200 bg-gray-50/50 text-gray-900 resize-none shadow-inner focus:outline-none text-base"></textarea>
            </div>
        </div>
      </div>
    </div>
  );
};

export default Translator;

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, UploadedFile, ChatPersona, LLMProvider } from '../types';
import { chatHybrid, speakText, analyzeDocument, fetchKnowledgeFromWeb } from '../services/geminiService';
import { chatWithHuggingFace } from '../services/huggingFaceService';
import { vectorStore } from '../services/vectorStore';
import { useTier } from '../contexts/TierContext';

// Polyfill type for SpeechRecognition
declare global {
    interface Window {
        webkitSpeechRecognition: any;
        SpeechRecognition: any;
    }
}

const IntelligentChat: React.FC = () => {
  const { tierConfig, currentTier } = useTier();

  // State
  const [messages, setMessages] = useState<ChatMessage[]>([
      {
          id: 'intro',
          role: 'model',
          content: "Hello! I am NeuroLingua AI. Select a persona or model below to get started.",
          timestamp: Date.now(),
          provider: 'System'
      }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [file, setFile] = useState<UploadedFile | null>(null);
  const [persona, setPersona] = useState<ChatPersona>(ChatPersona.GENERAL);
  const [provider, setProvider] = useState<LLMProvider>(LLMProvider.GEMINI);
  const [useRAG, setUseRAG] = useState(true);

  // Link State
  const [links, setLinks] = useState<string[]>([]);
  const [isLinkInputOpen, setIsLinkInputOpen] = useState(false);
  const [linkInput, setLinkInput] = useState('');
  const [indexingLinks, setIndexingLinks] = useState<Record<number, boolean>>({});

  // Voice State
  const [isListening, setIsListening] = useState(false);

  const chatEndRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isProcessing]);

  // --- Voice Input Setup ---
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = false;
            recognitionRef.current.lang = 'en-US';

            recognitionRef.current.onresult = (event: any) => {
                const transcript = event.results[0][0].transcript;
                setInputValue(prev => prev + (prev ? ' ' : '') + transcript);
                setIsListening(false);
            };

            recognitionRef.current.onerror = () => setIsListening(false);
            recognitionRef.current.onend = () => setIsListening(false);
        } catch (e) {
            console.error("Speech Setup Failed", e);
        }
    }
  }, []);

  const toggleListening = () => {
      if (isListening) {
          recognitionRef.current?.stop();
          setIsListening(false);
      } else {
          recognitionRef.current?.start();
          setIsListening(true);
      }
  };

  // --- File Handling ---
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const uploadedFile = event.target.files?.[0];
    if (uploadedFile) {
        if (uploadedFile.size > tierConfig.maxFileSizeMB * 1024 * 1024) {
            alert(`File too large. Limit: ${tierConfig.maxFileSizeMB}MB`);
            return;
        }

        const isPdf = uploadedFile.type === 'application/pdf' || uploadedFile.name.toLowerCase().endsWith('.pdf');

        const reader = new FileReader();
        reader.onload = async (e) => {
            let content = e.target?.result as string;
            if (isPdf) content = content.split(',')[1];

            setFile({
                name: uploadedFile.name,
                mimeType: isPdf ? 'application/pdf' : (uploadedFile.type || 'text/plain'),
                isBinary: isPdf,
                size: uploadedFile.size,
                content: content
            });
            setMessages(prev => [...prev, {
                id: Date.now().toString(),
                role: 'model',
                content: `✅ Attached **${uploadedFile.name}**.`,
                timestamp: Date.now()
            }]);
        };
        if (isPdf) reader.readAsDataURL(uploadedFile);
        else reader.readAsText(uploadedFile);
    }
  };

  const handleIndexLink = async (index: number) => {
      const url = links[index];
      if (!url) return;
      setIndexingLinks(prev => ({ ...prev, [index]: true }));
      try {
          const content = await fetchKnowledgeFromWeb(url);
          await vectorStore.addDocument(content, url, "Web Link");
          alert(`Indexed content from ${url}`);
      } catch (e) {
          alert("Failed to index link.");
      } finally {
          setIndexingLinks(prev => ({ ...prev, [index]: false }));
      }
  };

  // --- Chat Logic ---
  const handleSendMessage = async () => {
    if (!inputValue.trim()) return;

    const userMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'user',
        content: inputValue,
        timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsProcessing(true);

    try {
        const history = messages.map(m => ({
            role: m.role,
            parts: [{ text: m.content }]
        }));

        // 1. Retrieval (RAG)
        let ragContext = "";
        if (useRAG && !file) {
            const docs = await vectorStore.similaritySearch(userMsg.content);
            if (docs.length > 0) {
                ragContext = docs.map(d => `Source: ${d.source}\n${d.text}`).join('\n\n');
            }
        }

        // 2. Generation (Provider Switch)
        let responseText = "";
        let sources = undefined;

        if (provider === LLMProvider.GEMINI) {
            const result = await chatHybrid(
                userMsg.content, 
                history, 
                file || undefined, 
                links, 
                persona,
                ragContext
            );
            responseText = result.text;
            sources = result.sources;
        } else {
            // Hugging Face Fallback
            responseText = await chatWithHuggingFace(
                userMsg.content,
                history,
                `You are a ${persona}.`,
                ragContext
            );
        }

        const botMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: 'model',
            content: responseText,
            timestamp: Date.now(),
            sources: sources,
            provider: provider
        };

        setMessages(prev => [...prev, botMsg]);
    } catch (e) {
        setMessages(prev => [...prev, {
            id: (Date.now() + 1).toString(),
            role: 'model',
            content: "Error processing request.",
            timestamp: Date.now()
        }]);
    } finally {
        setIsProcessing(false);
    }
  };

  return (
    <div className="flex flex-col h-full overflow-hidden">

        {/* Controls Bar */}
        <div className="flex-shrink-0 flex flex-col xl:flex-row gap-3 p-2 bg-gray-50/80 md:bg-white/50 rounded-2xl border border-gray-200/60 mb-2">

            {/* Persona Selector */}
            <div className="flex-1 overflow-x-auto flex gap-1 no-scrollbar">
                {Object.values(ChatPersona).map((p) => (
                    <button
                        key={p}
                        onClick={() => setPersona(p)}
                        className={`px-3 py-1.5 rounded-lg text-xs font-semibold whitespace-nowrap transition-all ${
                            persona === p ? 'bg-indigo-600 text-white shadow' : 'bg-white text-gray-600 hover:bg-indigo-50 border border-gray-100'
                        }`}
                    >
                        {p}
                    </button>
                ))}
            </div>

            <div className="flex items-center gap-2 border-t md:border-t-0 md:border-l border-gray-200 pt-2 md:pt-0 md:pl-2">
                {/* Model Toggle */}
                <button 
                    onClick={() => setProvider(provider === LLMProvider.GEMINI ? LLMProvider.HUGGING_FACE : LLMProvider.GEMINI)}
                    className="flex-1 md:flex-none flex items-center justify-center gap-2 px-3 py-1.5 bg-white border border-gray-200 rounded-lg text-xs font-bold text-gray-700 hover:border-indigo-300 transition-colors"
                >
                    <i className={`fas ${provider === LLMProvider.GEMINI ? 'fa-gem' : 'fa-robot'} ${provider === LLMProvider.GEMINI ? 'text-indigo-600' : 'text-orange-500'}`}></i>
                    {provider === LLMProvider.GEMINI ? 'Gemini' : 'Mistral'}
                </button>

                {/* RAG Toggle */}
                {!file && (
                    <button 
                        onClick={() => setUseRAG(!useRAG)}
                        className={`w-8 h-5 rounded-full relative transition-colors flex-shrink-0 ${useRAG ? 'bg-green-500' : 'bg-gray-300'}`}
                        title="Toggle Knowledge Base RAG"
                    >
                        <div className={`w-3 h-3 bg-white rounded-full absolute top-1 transition-all ${useRAG ? 'left-4' : 'left-1'}`}></div>
                    </button>
                )}
            </div>
        </div>

        {/* Chat Messages Area (Flex Grow) */}
        <div className="flex-1 overflow-y-auto px-1 py-2 space-y-4 md:bg-white/40 md:rounded-3xl scroll-smooth">
            {messages.map((msg) => (
                <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                    <div className={`max-w-[85%] rounded-2xl p-4 shadow-sm ${
                        msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-white text-gray-800 border border-gray-100'
                    }`}>
                        <div className="whitespace-pre-wrap text-sm leading-relaxed">{msg.content}</div>
                        {msg.sources && (
                            <div className="mt-2 pt-2 border-t border-black/5 flex flex-wrap gap-2">
                                {msg.sources.map((src, i) => (
