// --- Live API (Real-time Audio) ---
export const startLiveSession = async (
    onAudioData: (base64Audio: string) => void,
    onTranscription: (text: string, isUser: boolean) => void,
    onError: (err: any) => void
) => {
    const inputAudioContext = new (window.AudioContext || window.webkitSpeechRecognition)({sampleRate: 16000});
    let stream: MediaStream;
    try {
        stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    } catch (e) {
        onError("Microphone permission denied");
        return null;
    }

    const sessionPromise = ai.live.connect({
        model: LIVE_MODEL,
        callbacks: {
            onopen: () => {
                console.log("Live Session Connected");
                const source = inputAudioContext.createMediaStreamSource(stream);
                const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);

                scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
                    const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);
                    // Convert Float32 to Int16 PCM
                    const l = inputData.length;
                    const int16 = new Int16Array(l);
                    for (let i = 0; i < l; i++) {
                        int16[i] = inputData[i] * 32768;
                    }
                    const base64Data = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));

                    sessionPromise.then((session) => {
                        session.sendRealtimeInput({
                            media: { mimeType: 'audio/pcm;rate=16000', data: base64Data }
                        });
                    });
                };
                source.connect(scriptProcessor);
                scriptProcessor.connect(inputAudioContext.destination);
            },
            onmessage: (message: LiveServerMessage) => {
                // Audio Output
                const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                if (audioData) {
                    onAudioData(audioData);
                }
                // Transcriptions
                if (message.serverContent?.outputTranscription?.text) {
                    onTranscription(message.serverContent.outputTranscription.text, false);
                }
                if (message.serverContent?.inputTranscription?.text) {
                    onTranscription(message.serverContent.inputTranscription.text, true);
                }
            },
            onerror: (e) => {
                console.error("Live API Error", e);
                onError(e);
            },
            onclose: () => {
                console.log("Live Session Closed");
            }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } }
            },
            inputAudioTranscription: { model: "google-provided-model" } // Enable user transcription
        }
    });

    return {
        disconnect: async () => {
            if (stream) stream.getTracks().forEach(t => t.stop());
            if (inputAudioContext) await inputAudioContext.close();
            // session.close() is handled by the promise resolution logic in a real sdk, 
            // but for this snippet we assume breaking the stream and context stops input.
        }
    };
};

