export const fetchKnowledgeFromWeb = async (topic: string): Promise<string> => {
    // 1. Try Python Scraper (Localhost)
    try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 3000); 

        const response = await fetch('http://localhost:5000/scrape', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ url: topic, query: topic }), 
            signal: controller.signal
        });
        clearTimeout(timeoutId);

        if (response.ok) {
            const data = await response.json();
            if (data.content) return data.content;
        }
    } catch (e) {
        // Fallback
    }

    // 2. Fallback to Gemini Search
    const executeFetch = async () => {
      const prompt = `Research: "${topic}". detailed summary.`;
      const response = await ai.models.generateContent({
        model: MODEL_NAME,
        contents: prompt,
        config: { tools: [{ googleSearch: {} }] }
      });
      return response.text || "";
    };

    try {
        return await withRetry(executeFetch, 3, 2000);
    } catch (error) {
        return "";
    }
};

// --- Translation ---

export const translateText = async (text: string, sourceLang: string, targetLang: string, mode: TranslationMode): Promise<string> => {
  if (!text.trim()) return "";
  let prompt = mode === TranslationMode.TRANSLITERATE
    ? `Transliterate from ${sourceLang} script to ${targetLang} script. Input: "${text}"`
    : `Translate from ${sourceLang} to ${targetLang}. Input: "${text}"`;
  try {
    const response = await ai.models.generateContent({ model: MODEL_NAME, contents: prompt });
    return response.text || "Translation failed.";
  } catch (error) { return "Error."; }
};

export const translateDocument = async (
  file: { data: string; mimeType: string; isBinary: boolean },
  sourceLang: string,
  targetLang: string,
  mode: TranslationMode
): Promise<string> => {
  const prompt = `Translate from ${sourceLang} to ${targetLang}. Preserve formatting.`;
  try {
    const parts: Part[] = [];
    if (file.isBinary) {
        parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        parts.push({ text: prompt });
    } else {
        parts.push({ text: `${prompt}\n\n${file.data}` });
    }
    const response = await ai.models.generateContent({ model: MODEL_NAME, contents: [{ role: 'user', parts }] });
    return response.text || "Failed.";
  } catch (error) { return "Error."; }
};

