// --- Live API (Real-time Audio) ---
export const startLiveSession = async (
    onAudioData: (base64Audio: string) => void,
    onTranscription: (text: string, isUser: boolean) => void,
    onError: (err: any) => void
) => {
    // Fixed AudioContext fallback
    const inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 16000});
    let stream: MediaStream;
    try {
        stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    } catch (e) {
        onError("Microphone permission denied");
        return null;
    }

    const sessionPromise = ai.live.connect({
        model: LIVE_MODEL,
        callbacks: {
            onopen: () => {
                console.log("Live Session Connected");
                const source = inputAudioContext.createMediaStreamSource(stream);
                const scriptProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);

                scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
                    const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);
                    // Convert Float32 to Int16 PCM
                    const l = inputData.length;
                    const int16 = new Int16Array(l);
                    for (let i = 0; i < l; i++) {
                        int16[i] = inputData[i] * 32768;
                    }
                    const base64Data = btoa(String.fromCharCode(...new Uint8Array(int16.buffer)));

                    sessionPromise.then((session) => {
                        session.sendRealtimeInput({
                            media: { mimeType: 'audio/pcm;rate=16000', data: base64Data }
                        });
                    });
                };
                source.connect(scriptProcessor);
                scriptProcessor.connect(inputAudioContext.destination);
            },
            onmessage: (message: LiveServerMessage) => {
                // Audio Output
                const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                if (audioData) {
                    onAudioData(audioData);
                }
                // Transcriptions
                if (message.serverContent?.outputTranscription?.text) {
                    onTranscription(message.serverContent.outputTranscription.text, false);
                }
                if (message.serverContent?.inputTranscription?.text) {
                    onTranscription(message.serverContent.inputTranscription.text, true);
                }
            },
            onerror: (e) => {
                console.error("Live API Error", e);
                onError(e);
            },
            onclose: () => {
                console.log("Live Session Closed");
            }
        },
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
                voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } }
            },
            inputAudioTranscription: { model: "google-provided-model" } // Enable user transcription
        }
    });

    return {
        disconnect: async () => {
            if (stream) stream.getTracks().forEach(t => t.stop());
            if (inputAudioContext) await inputAudioContext.close();
            // session.close() is handled by the promise resolution logic in a real sdk, 
            // but for this snippet we assume breaking the stream and context stops input.
        }
    };
};

// --- Vectorization & Embeddings ---

export const getEmbedding = async (text: string): Promise<number[]> => {
  try {
    return await withRetry(async () => {
        const response = await ai.models.embedContent({
        model: EMBEDDING_MODEL,
        contents: { parts: [{ text }] }
        });
        return response.embeddings?.[0]?.values || [];
    });
  } catch (error) {
    console.error("Embedding Error:", error);
    return [];
  }
};

// --- Knowledge Fetching ---

export const fetchKnowledgeFromWeb = async (topic: string): Promise<string> => {
    // 1. Try Python Scraper (Localhost)
    try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 3000); 

        const response = await fetch('http://localhost:5000/scrape', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ url: topic, query: topic }), 
            signal: controller.signal
        });
        clearTimeout(timeoutId);

        if (response.ok) {
            const data = await response.json();
            if (data.content) return data.content;
        }
    } catch (e) {
        // Fallback
    }

    // 2. Fallback to Gemini Search
    const executeFetch = async () => {
      const prompt = `Research: "${topic}". detailed summary.`;
      const response = await ai.models.generateContent({
        model: MODEL_NAME,
        contents: prompt,
        config: { tools: [{ googleSearch: {} }] }
      });
      return response.text || "";
    };

    try {
        return await withRetry(executeFetch, 3, 2000);
    } catch (error) {
        return "";
    }
};

// --- Translation ---

export const translateText = async (text: string, sourceLang: string, targetLang: string, mode: TranslationMode): Promise<string> => {
  if (!text.trim()) return "";
  let prompt = mode === TranslationMode.TRANSLITERATE
    ? `Transliterate from ${sourceLang} script to ${targetLang} script. Input: "${text}"`
    : `Translate from ${sourceLang} to ${targetLang}. Input: "${text}"`;
  try {
    const response = await ai.models.generateContent({ model: MODEL_NAME, contents: prompt });
    return response.text || "Translation failed.";
  } catch (error) { return "Error."; }
};

export const translateDocument = async (
  file: { data: string; mimeType: string; isBinary: boolean },
  sourceLang: string,
  targetLang: string,
  mode: TranslationMode
): Promise<string> => {
  const prompt = `Translate from ${sourceLang} to ${targetLang}. Preserve formatting.`;
  try {
    const parts: Part[] = [];
    if (file.isBinary) {
        parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });
        parts.push({ text: prompt });
    } else {
        parts.push({ text: `${prompt}\n\n${file.data}` });
    }
    const response = await ai.models.generateContent({ model: MODEL_NAME, contents: [{ role: 'user', parts }] });
    return response.text || "Failed.";
  } catch (error) { return "Error."; }
};

