                 setMessages(prev => [...prev, {
                    id: Date.now().toString(),
                    role: 'model',
                    content: `✅ Attached **${uploadedFile.name}**.`,
                    timestamp: Date.now()
                }]);
            }
        };
        if (isPdf || isImage) reader.readAsDataURL(uploadedFile);
        else reader.readAsText(uploadedFile);
