// Decode Audio for Live API
function decodeAudio(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

const IntelligentChat: React.FC = () => {
  const { tierConfig, currentTier } = useTier();

  // State
  const [messages, setMessages] = useState<ChatMessage[]>([
      {
          id: 'intro',
          role: 'model',
          content: "Hello! Select a persona to begin. Use 'Visual Tool User' for Veo animations, or 'Custom Identity' to create your own.",
          timestamp: Date.now(),
          provider: 'System'
      }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [file, setFile] = useState<UploadedFile | null>(null);
  const [persona, setPersona] = useState<ChatPersona>(ChatPersona.GENERAL);
  const [provider, setProvider] = useState<LLMProvider>(LLMProvider.GEMINI);
  const [useRAG, setUseRAG] = useState(true);

  // Custom Persona State
  const [customPersonaInput, setCustomPersonaInput] = useState('');
  const [customPersonaInstruction, setCustomPersonaInstruction] = useState('');
  const [isGeneratingPersona, setIsGeneratingPersona] = useState(false);

  // Voice Input (Dictation) State
  const [isDictating, setIsDictating] = useState(false);
  const [speechError, setSpeechError] = useState<string | null>(null);
  const recognitionRef = useRef<any>(null);

  // Live API State
  const [isLiveMode, setIsLiveMode] = useState(false);
  const [liveTranscript, setLiveTranscript] = useState('');
  const liveSessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);

  // Link State
  const [links, setLinks] = useState<string[]>([]);
  const [isLinkInputOpen, setIsLinkInputOpen] = useState(false);
  const [linkInput, setLinkInput] = useState('');
  const [indexingLinks, setIndexingLinks] = useState<Record<number, boolean>>({});

  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isProcessing, liveTranscript]);

  // --- Dictation Setup ---
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            const recognition = new SpeechRecognition();
            recognitionRef.current = recognition;
            recognition.continuous = false;
            recognition.interimResults = true;
            recognition.lang = 'en-US';

            recognition.onresult = (event: any) => {
                const transcript = Array.from(event.results)
                    .map((result: any) => result[0].transcript)
                    .join('');
                if (event.results[0].isFinal) {
                    setInputValue(prev => prev ? prev + ' ' + transcript : transcript);
                    setIsDictating(false);
                }
            };

            recognition.onerror = (event: any) => {
                console.error("Dictation Error:", event.error);
                setIsDictating(false);

                let errorMessage = "Voice input failed.";
                if (event.error === 'network') {
                    errorMessage = "Network error. Please check your connection.";
                } else if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
                    errorMessage = "Microphone access denied.";
                } else if (event.error === 'no-speech') {
                    return; // Ignore
                }

                setSpeechError(errorMessage);
                setTimeout(() => setSpeechError(null), 3000);
            };

            recognition.onend = () => {
                setIsDictating(false);
            };
        } catch (e) {
            console.error("Speech Recognition setup failed:", e);
        }
    }

    return () => {
        if (recognitionRef.current) {
            recognitionRef.current.abort();
        }
    };
  }, []);

  const toggleDictation = () => {
      if (isDictating) {
          recognitionRef.current?.stop();
          setIsDictating(false);
      } else {
          try {
              setSpeechError(null);
              recognitionRef.current?.start();
              setIsDictating(true);
          } catch(e) {
              console.error(e);
              setSpeechError("Could not start voice input.");
              setTimeout(() => setSpeechError(null), 3000);
          }
      }
  };

  // --- Live API Handlers ---
  const toggleLiveMode = async () => {
      if (isLiveMode) {
          // Stop
          if (liveSessionRef.current) liveSessionRef.current.disconnect();
          if (audioContextRef.current) audioContextRef.current.close();
          setIsLiveMode(false);
          setLiveTranscript('');
      } else {
          // Start
          setIsLiveMode(true);
          // Fix: Webkit fallback cast to any
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});
          nextStartTimeRef.current = 0;

          const session = await startLiveSession(
              async (base64Audio) => {
                  // Play Audio
                  if (!audioContextRef.current) return;
                  const audioCtx = audioContextRef.current;
                  const audioData = decodeAudio(base64Audio);

                  // Simple Decode
                  const buffer = audioCtx.createBuffer(1, audioData.length / 2, 24000);
                  const channel = buffer.getChannelData(0);
                  const int16 = new Int16Array(audioData.buffer);
                  for (let i = 0; i < int16.length; i++) {
                      channel[i] = int16[i] / 32768.0;
                  }

                  const source = audioCtx.createBufferSource();
                  source.buffer = buffer;
                  source.connect(audioCtx.destination);

                  const now = audioCtx.currentTime;
                  // Schedule ensuring no overlap but continuous play
                  const start = Math.max(now, nextStartTimeRef.current);
                  source.start(start);
                  nextStartTimeRef.current = start + buffer.duration;
              },
              (text, isUser) => {
                  setLiveTranscript(prev => `${isUser ? '\nUser: ' : '\nAI: '}${text}`);
              },
              (err) => {
                  alert("Live Session Error: " + err);
                  setIsLiveMode(false);
              }
          );
          liveSessionRef.current = session;
      }
  };

  // --- Custom Persona Handler ---
  const handleGeneratePersona = async () => {
      if (!customPersonaInput.trim()) return;
      setIsGeneratingPersona(true);
      const instruction = await createPersonaDescription(customPersonaInput);
      setCustomPersonaInstruction(instruction);
      setIsGeneratingPersona(false);
      setMessages(prev => [...prev, {
          id: Date.now().toString(),
          role: 'model',
          content: `Persona configured! I am now acting as: "${customPersonaInput}".`,
          timestamp: Date.now(),
          provider: 'System'
      }]);
  };

  // --- File Handling ---
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const uploadedFile = event.target.files?.[0];
    if (uploadedFile) {
        const isPdf = uploadedFile.type === 'application/pdf' || uploadedFile.name.toLowerCase().endsWith('.pdf');
        const isImage = uploadedFile.type.startsWith('image/');

        const reader = new FileReader();
        reader.onload = async (e) => {
            let content = e.target?.result as string;
            if (isPdf || isImage) content = content.split(',')[1];

            setFile({
                name: uploadedFile.name,
                mimeType: uploadedFile.type || 'text/plain',
                isBinary: isPdf || isImage,
                size: uploadedFile.size,
                content: content
            });

            // If Visual Persona and Image, prompt for Veo
            if (persona === ChatPersona.VISUAL_CREATOR && isImage) {
                 setMessages(prev => [...prev, {
                    id: Date.now().toString(),
                    role: 'model',
                    content: `📸 **Image Uploaded**. To animate this with **Veo**, reply with a prompt (e.g., "A neon hologram of a cat driving").`,
                    timestamp: Date.now()
                }]);
            } else {
                 setMessages(prev => [...prev, {
                    id: Date.now().toString(),
                    role: 'model',
                    content: `✅ Attached **${uploadedFile.name}**.`,
                    timestamp: Date.now()
                }]);
            }
        };
        if (isPdf || isImage) reader.readAsDataURL(uploadedFile);
        else reader.readAsText(uploadedFile);
    }
  };

  // --- Chat Logic ---
  const handleSendMessage = async () => {
    if (!inputValue.trim()) return;

    const userMsg: ChatMessage = {
        id: Date.now().toString(),
        role: 'user',
        content: inputValue,
        timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsProcessing(true);

    try {
        // Special Case: Veo Animation Request
        if (persona === ChatPersona.VISUAL_CREATOR && file && file.mimeType.startsWith('image/')) {
            const videoUri = await generateVeoVideo(file.content, userMsg.content, file.mimeType);
            if (videoUri) {
                setMessages(prev => [...prev, {
                    id: Date.now().toString(),
                    role: 'model',
                    content: "Here is your Veo generation:",
                    timestamp: Date.now(),
                    generatedVideo: videoUri,
                    provider: 'Veo'
                }]);
                setIsProcessing(false);
                return;
            }
        }

        const history = messages.map(m => ({
            role: m.role,
            parts: [{ text: m.content }]
        }));

        // 1. Retrieval (RAG)
        let ragContext = "";
        if (useRAG && !file) {
            const docs = await vectorStore.similaritySearch(userMsg.content);
            if (docs.length > 0) {
                ragContext = docs.map(d => `Source: ${d.source}\n${d.text}`).join('\n\n');
            }
        }

        // 2. Generation
        let responseText = "";
        let sources = undefined;
        let generatedImage = undefined;

        if (provider === LLMProvider.GEMINI) {
            const result = await chatHybrid(
                userMsg.content, 
                history, 
                file || undefined, 
                links, 
                persona,
                ragContext,
                persona === ChatPersona.CUSTOM ? customPersonaInstruction : undefined
            );
            responseText = result.text;
            sources = result.sources;
            generatedImage = result.generatedImage;
        } else {
            responseText = await chatWithHuggingFace(userMsg.content, history, `You are a ${persona}.`, ragContext);
        }

        const botMsg: ChatMessage = {
            id: (Date.now() + 1).toString(),
            role: 'model',
            content: responseText,
            timestamp: Date.now(),
            sources: sources,
            generatedImage: generatedImage,
            provider: provider
        };

        setMessages(prev => [...prev, botMsg]);
    } catch (e) {
        setMessages(prev => [...prev, {
            id: (Date.now() + 1).toString(),
            role: 'model',
            content: "Error processing request. " + e,
            timestamp: Date.now()
        }]);
    } finally {
        setIsProcessing(false);
    }
  };

  return (
    <div className="flex flex-col h-full overflow-hidden relative">

        {/* Live Mode Overlay */}
        {isLiveMode && (
            <div className="absolute inset-0 z-50 bg-indigo-900/95 backdrop-blur-md flex flex-col items-center justify-center text-white animate-fade-in">
                <div className="w-32 h-32 rounded-full bg-indigo-500 animate-pulse flex items-center justify-center shadow-[0_0_50px_rgba(99,102,241,0.5)]">
                    <i className="fas fa-microphone text-4xl"></i>
                </div>
                <h2 className="mt-8 text-2xl font-bold">Gemini Live</h2>
                <p className="text-indigo-300">Listening & Speaking...</p>
                <div className="mt-8 max-w-md w-full h-40 overflow-y-auto bg-black/20 rounded-xl p-4 text-sm font-mono whitespace-pre-wrap">
                    {liveTranscript || "Say something..."}
                </div>
                <button onClick={toggleLiveMode} className="mt-8 px-8 py-3 bg-red-500 rounded-full font-bold hover:bg-red-600 transition-colors">
                    End Session
                </button>
            </div>
        )}

        {/* Controls Bar */}
        <div className="flex-shrink-0 flex flex-col gap-3 p-2 bg-gray-50/80 md:bg-white/50 rounded-2xl border border-gray-200/60 mb-2">
            <div className="flex-1 overflow-x-auto flex gap-1 no-scrollbar">
                {Object.values(ChatPersona).map((p) => (
                    <button
                        key={p}
                        onClick={() => setPersona(p)}
                        className={`px-3 py-1.5 rounded-lg text-xs font-semibold whitespace-nowrap transition-all ${
                            persona === p 
                                ? p === ChatPersona.VISUAL_CREATOR 
                                    ? 'bg-gradient-to-r from-pink-500 to-purple-600 text-white shadow-lg' 
                                    : p === ChatPersona.CUSTOM
                                        ? 'bg-gradient-to-r from-emerald-500 to-teal-600 text-white shadow-lg'
                                        : 'bg-indigo-600 text-white shadow' 
                                : 'bg-white text-gray-600 hover:bg-indigo-50 border border-gray-100'
                        }`}
                    >
                        {p === ChatPersona.VISUAL_CREATOR && <i className="fas fa-magic mr-1"></i>}
                        {p === ChatPersona.CUSTOM && <i className="fas fa-user-edit mr-1"></i>}
                        {p}
                    </button>
                ))}
            </div>

            {/* Custom Persona Configuration Panel */}
            {persona === ChatPersona.CUSTOM && (
                <div className="bg-emerald-50 border border-emerald-100 rounded-xl p-3 animate-fade-in">
                    <h4 className="text-xs font-bold text-emerald-800 mb-2 flex items-center gap-2">
                        <i className="fas fa-robot"></i> Configure Identity
                        {customPersonaInstruction && <span className="text-[10px] bg-emerald-200 text-emerald-800 px-2 py-0.5 rounded-full">Active</span>}
                    </h4>
                    <div className="flex gap-2">
                        <input 
                            type="text" 
                            value={customPersonaInput}
                            onChange={(e) => setCustomPersonaInput(e.target.value)}
                            placeholder="Describe persona (e.g. 'A sarcastic pirate who loves coding')"
                            className="flex-1 text-sm p-2 rounded-lg border border-emerald-200 focus:outline-none focus:ring-2 focus:ring-emerald-500"
                        />
                        <button 
                            onClick={handleGeneratePersona}
                            disabled={isGeneratingPersona || !customPersonaInput}
                            className="bg-emerald-600 text-white px-4 py-2 rounded-lg text-xs font-bold hover:bg-emerald-700 disabled:opacity-50"
                        >
                            {isGeneratingPersona ? <i className="fas fa-spinner fa-spin"></i> : 'Create'}
                        </button>
                    </div>
                </div>
            )}

            <div className="flex items-center gap-2 border-t border-gray-200 pt-2">
                <button 
                    onClick={() => setProvider(provider === LLMProvider.GEMINI ? LLMProvider.HUGGING_FACE : LLMProvider.GEMINI)}
                    className="flex-1 md:flex-none flex items-center justify-center gap-2 px-3 py-1.5 bg-white border border-gray-200 rounded-lg text-xs font-bold text-gray-700 hover:border-indigo-300 transition-colors"
                >
                    <i className={`fas ${provider === LLMProvider.GEMINI ? 'fa-gem' : 'fa-robot'} ${provider === LLMProvider.GEMINI ? 'text-indigo-600' : 'text-orange-500'}`}></i>
                    {provider === LLMProvider.GEMINI ? 'Gemini' : 'Mistral'}
                </button>

                 {/* RAG Toggle */}
                {!file && (
                    <button 
                        onClick={() => setUseRAG(!useRAG)}
                        className={`w-12 h-6 rounded-full relative transition-colors flex items-center px-1 flex-shrink-0 ${useRAG ? 'bg-emerald-500' : 'bg-gray-300'}`}
                        title={`Knowledge Base RAG: ${useRAG ? 'ON' : 'OFF'}`}
                    >
                        <div className={`w-4 h-4 bg-white rounded-full shadow-sm transform transition-transform ${useRAG ? 'translate-x-6' : 'translate-x-0'}`}></div>
                        <span className={`absolute text-[9px] font-bold text-white ${useRAG ? 'left-1.5' : 'right-1.5'}`}>{useRAG ? 'KB' : 'OFF'}</span>
                    </button>
                )}
            </div>
        </div>

        {/* Chat Messages Area */}
        <div className={`flex-1 overflow-y-auto px-1 py-2 space-y-4 md:bg-white/40 md:rounded-3xl scroll-smooth ${persona === ChatPersona.VISUAL_CREATOR ? 'border-2 border-pink-100' : ''}`}>
            {messages.map((msg) => (
                <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                    <div className={`max-w-[85%] rounded-2xl p-4 shadow-sm ${
                        msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-white text-gray-800 border border-gray-100'
                    }`}>
                        <div className="whitespace-pre-wrap text-sm leading-relaxed">{msg.content}</div>

                        {/* Render Images */}
                        {msg.generatedImage && (
                            <div className="mt-3 rounded-xl overflow-hidden shadow-lg border border-gray-200">
                                <img src={`data:image/png;base64,${msg.generatedImage}`} alt="Generated" className="w-full h-auto" />
                            </div>
                        )}

                        {/* Render Videos */}
                        {msg.generatedVideo && (
                            <div className="mt-3 rounded-xl overflow-hidden shadow-lg border border-gray-200">
                                <video controls src={msg.generatedVideo} className="w-full h-auto bg-black" />
                            </div>
                        )}

                        {/* Render Sources */}
                        {msg.sources && msg.sources.length > 0 && (
                            <div className="mt-2 pt-2 border-t border-black/5 flex flex-wrap gap-2">
                                {msg.sources.map((src, i) => (
                                    <a key={i} href={src.uri} target="_blank" className="text-[10px] bg-black/5 px-2 py-1 rounded truncate max-w-[150px] hover:bg-black/10 transition-colors flex items-center gap-1">
                                        <i className={`fas ${src.uri.includes('maps') || src.title.includes('Map') ? 'fa-map-marker-alt text-red-500' : 'fa-external-link-alt text-blue-500'}`}></i> 
                                        {src.title}
                                    </a>
                                ))}
                            </div>
                        )}
                    </div>

                    <div className="flex items-center gap-2 mt-1 px-1">
                        <span className="text-[10px] text-gray-400">{msg.role === 'user' ? 'You' : `${persona} • ${msg.provider || provider}`}</span>
                        {msg.role === 'model' && (
                            <button onClick={() => speakText(msg.content)} className="text-gray-400 hover:text-indigo-600">
                                <i className="fas fa-volume-up text-xs"></i>
                            </button>
                        )}
                    </div>
                </div>
            ))}
            <div ref={chatEndRef} />
        </div>

        {/* Input Bar */}
        <div className="flex-shrink-0 py-2 bg-white md:bg-transparent border-t border-gray-100 md:border-none z-10">
            <div className="flex items-center gap-2 bg-white border border-gray-200 p-1.5 rounded-full shadow-lg relative">

                {/* Visual Tool Hint */}
                {persona === ChatPersona.VISUAL_CREATOR && (
                    <div className="absolute -top-8 left-0 right-0 text-center">
                        <span className="bg-pink-100 text-pink-700 text-[10px] font-bold px-3 py-1 rounded-full border border-pink-200 animate-bounce">
                            Visual Mode Active: Upload image to animate with Veo
                        </span>
                    </div>
                )}

                <label className="w-10 h-10 flex items-center justify-center text-gray-400 hover:text-indigo-600 cursor-pointer rounded-full hover:bg-gray-50 transition-colors">
                    <input type="file" className="hidden" accept=".pdf,.doc,.docx,.txt,image/*" onChange={handleFileUpload} />
                    <i className={`fas ${file ? 'fa-check text-green-500' : 'fa-paperclip'}`}></i>
                </label>

                <div className="relative">
                    <button onClick={() => setIsLinkInputOpen(!isLinkInputOpen)} className="w-10 h-10 flex items-center justify-center text-gray-400 hover:text-blue-500 rounded-full hover:bg-gray-50">
                        <i className="fas fa-link"></i>
                    </button>
                    {isLinkInputOpen && (
                        <div className="absolute bottom-12 left-0 z-50 bg-white p-2 rounded-xl shadow-xl border border-gray-200 w-64 animate-fade-in">
                            <input 
                                type="text" 
                                value={linkInput}
                                onChange={(e) => setLinkInput(e.target.value)}
                                onKeyDown={(e) => e.key === 'Enter' && (setLinks(prev => [...prev, linkInput]), setLinkInput(''), setIsLinkInputOpen(false))}
                                placeholder="Paste URL..."
                                className="w-full text-xs border border-gray-200 rounded p-2 mb-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                                autoFocus
                            />
                        </div>
                    )}
                </div>

                <input
                    type="text"
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                    disabled={isProcessing}
                    placeholder={persona === ChatPersona.VISUAL_CREATOR ? "Describe image or video..." : "Message..."}
                    className="flex-1 bg-transparent border-none focus:ring-0 text-sm py-2 px-1 text-gray-800"
                />

                {/* Dictation Button with Error Tooltip */}
                <div className="relative">
                    {speechError && (
                        <div className="absolute bottom-full mb-2 left-1/2 -translate-x-1/2 whitespace-nowrap bg-red-500 text-white text-[10px] px-2 py-1 rounded shadow-lg animate-fade-in z-50">
                            {speechError}
                            <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-red-500"></div>
                        </div>
                    )}
                    <button 
                        onClick={toggleDictation}
                        className={`w-10 h-10 rounded-full flex-shrink-0 transition-colors ${isDictating ? 'text-red-500 animate-pulse' : 'text-gray-400 hover:text-indigo-600'}`}
                        title="Voice Typing"
                    >
                         <i className={`fas ${isDictating ? 'fa-microphone-slash' : 'fa-microphone'}`}></i>
                    </button>
                </div>

                {/* Live Button */}
                <button onClick={toggleLiveMode} className="w-10 h-10 rounded-full flex-shrink-0 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 transition-colors" title="Start Live Conversation">
                     <i className="fas fa-headset"></i>
                </button>

                <button onClick={handleSendMessage} disabled={!inputValue.trim()} className={`w-10 h-10 text-white rounded-full shadow-md flex items-center justify-center flex-shrink-0 disabled:bg-gray-300 transition-colors ${persona === ChatPersona.VISUAL_CREATOR ? 'bg-pink-600 hover:bg-pink-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                    {isProcessing ? <i className="fas fa-spinner fa-spin text-xs"></i> : <i className="fas fa-arrow-up text-sm"></i>}
                </button>
            </div>
        </div>
    </div>
  );
};

export default IntelligentChat;

import React, { useState, useEffect, useRef } from 'react';
import { TranslationMode, SUPPORTED_LANGUAGES, Tier } from '../types';
import { translateText, translateDocument, speakText } from '../services/geminiService';
import { useTier } from '../contexts/TierContext';
import { createWorker } from 'tesseract.js';

// Polyfill type for SpeechRecognition
declare global {
    interface Window {
        webkitSpeechRecognition: any;
        SpeechRecognition: any;
    }
}

interface AttachedFile {
    name: string;
    mimeType: string;
    data: string; // Base64 (for binary) OR Raw Text (for text files)
    isBinary: boolean;
}

interface TranslatorProps {
    onSendToChat: (text: string, isRAG: boolean) => void;
}

const getTesseractLang = (code: string) => {
    // Extended language support
    const map: Record<string, string> = {
        'en': 'eng', 'es': 'spa', 'fr': 'fra', 'de': 'deu',
        'it': 'ita', 'pt': 'por', 'ru': 'rus', 'zh': 'chi_sim',
        'ja': 'jpn', 'ko': 'kor', 'hi': 'hin', 'bn': 'ben',
        'ar': 'ara', 'tr': 'tur', 'pl': 'pol', 'nl': 'nld'
    };
    return map[code] || 'eng';
};

// Simple stop-word based language detection
const STOP_WORDS: Record<string, string[]> = {
    'en': ['the', 'and', 'is', 'in', 'to', 'of', 'it', 'you', 'that', 'for'],
    'es': ['el', 'la', 'de', 'que', 'en', 'y', 'a', 'los', 'del', 'las', 'por', 'un'],
    'fr': ['le', 'la', 'les', 'de', 'et', 'est', 'un', 'une', 'du', 'en', 'qui'],
    'de': ['der', 'die', 'das', 'und', 'ist', 'in', 'zu', 'den', 'von', 'mit'],
    'it': ['il', 'la', 'che', 'di', 'e', 'in', 'un', 'per', 'sono', 'mi'],
    'pt': ['o', 'a', 'de', 'que', 'e', 'do', 'da', 'em', 'um', 'para']
};

const detectLanguage = (text: string): string | null => {
    const lowerText = text.toLowerCase();
    const tokens = lowerText.split(/[\s,.;!?]+/);

    let bestLang = null;
    let maxMatches = 0;

    for (const [lang, words] of Object.entries(STOP_WORDS)) {
        const matches = tokens.filter(t => words.includes(t)).length;
        if (matches > maxMatches) {
            maxMatches = matches;
            bestLang = lang;
        }
    }
    // Require at least 2 stop word matches to be confident enough to switch
    return maxMatches >= 2 ? bestLang : null;
};

const Translator: React.FC<TranslatorProps> = ({ onSendToChat }) => {
  const { tierConfig, currentTier } = useTier();

  const [sourceText, setSourceText] = useState('');
  const [targetText, setTargetText] = useState('');
  const [sourceLang, setSourceLang] = useState('auto');
  const [targetLang, setTargetLang] = useState('es');
  const [mode, setMode] = useState<TranslationMode>(TranslationMode.TRANSLATE);
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [attachedFile, setAttachedFile] = useState<AttachedFile | null>(null);

  // Camera State
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [ocrText, setOcrText] = useState('');
  const [isOcrInitializing, setIsOcrInitializing] = useState(false);
  const [ocrConfidence, setOcrConfidence] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null); // For capturing frame
  const overlayRef = useRef<HTMLCanvasElement>(null); // For drawing boxes
  const recognitionRef = useRef<any>(null);
  const workerRef = useRef<any>(null);
  const ocrIntervalRef = useRef<any>(null);

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        try {
            recognitionRef.current = new SpeechRecognition();
            recognitionRef.current.continuous = false;
            recognitionRef.current.interimResults = false;

            recognitionRef.current.onresult = (event: any) => {
                const transcript = event.results[0][0].transcript;
                setSourceText(transcript);
                setIsListening(false);
            };

            recognitionRef.current.onerror = (event: any) => {
                console.error("Speech Recognition Error:", event.error);
                setIsListening(false);
            };

            recognitionRef.current.onend = () => {
                setIsListening(false);
            };
        } catch (e) {
            console.error("Speech Recognition setup failed:", e);
        }
    }
  }, []);

  // Debounce translation trigger for text
  useEffect(() => {
    const timer = setTimeout(() => {
      if (sourceText.length > 1 && !attachedFile) { 
        handleProcess();
      }
    }, 1000);
    return () => clearTimeout(timer);
  }, [sourceText, sourceLang, targetLang, mode]);

  // Handle Camera Stream & OCR
  useEffect(() => {
    let stream: MediaStream | null = null;

    const startCameraAndOCR = async () => {
        try {
            stream = await navigator.mediaDevices.getUserMedia({ 
                video: { facingMode: 'environment' } 
            });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }

            // Init OCR Worker
            setIsOcrInitializing(true);

            // If auto, try to load a multi-lang model for detection purposes
            // This allows us to recognize common words in EN, ES, FR, DE to switch mode
            const tLang = sourceLang === 'auto' 
                ? 'eng+spa+fra+deu' 
                : getTesseractLang(sourceLang);

            // Re-create worker if language changes
            if (workerRef.current) {
                await workerRef.current.terminate();
            }

            const worker = await createWorker(tLang);
            workerRef.current = worker;
            setIsOcrInitializing(false);

            // Start OCR Loop
            ocrIntervalRef.current = setInterval(async () => {
                if (videoRef.current && canvasRef.current && workerRef.current) {
                    const video = videoRef.current;
                    const canvas = canvasRef.current;
                    const overlay = overlayRef.current;

                    if (video.readyState === video.HAVE_ENOUGH_DATA) {
                        // Capture Frame
                        canvas.width = video.videoWidth;
                        canvas.height = video.videoHeight;
                        const ctx = canvas.getContext('2d');
                        if (!ctx) return;

                        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
                        const dataUrl = canvas.toDataURL('image/jpeg', 0.5);

                        try {
                            const { data } = await workerRef.current.recognize(dataUrl);

                            // Auto-detect Language logic
                            if (sourceLang === 'auto' && data.text.trim().length > 15) {
                                const detected = detectLanguage(data.text);
                                if (detected) {
                                    console.log("Auto-detected language:", detected);
                                    setSourceLang(detected); // This will trigger cleanup and restart with specific lang
                                    return;
                                }
                            }

                            if (data.text.trim().length > 1) {
                                setOcrText(data.text.trim());
                                setOcrConfidence(data.confidence);
                            }

                            // Draw Bounding Boxes on Overlay
                            if (overlay) {
                                overlay.width = video.clientWidth;
                                overlay.height = video.clientHeight;
                                const oCtx = overlay.getContext('2d');
                                if (oCtx) {
                                    oCtx.clearRect(0, 0, overlay.width, overlay.height);

                                    const scaleX = overlay.width / video.videoWidth;
                                    const scaleY = overlay.height / video.videoHeight;

                                    data.words.forEach((word: any) => {
                                        if (word.confidence > 50) {
                                            const { x0, y0, x1, y1 } = word.bbox;
                                            const w = (x1 - x0) * scaleX;
                                            const h = (y1 - y0) * scaleY;
                                            const x = x0 * scaleX;
                                            const y = y0 * scaleY;

                                            // Enhanced Visuals
                                            oCtx.beginPath();
                                            // Fallback for roundRect in older browsers
                                            if (oCtx.roundRect) {
                                                oCtx.roundRect(x, y, w, h, 4);
                                            } else {
                                                oCtx.rect(x, y, w, h);
                                            }

                                            // Cyan Accent Color with Opacity based on confidence
                                            oCtx.strokeStyle = `rgba(6, 182, 212, ${word.confidence / 100})`; 
                                            oCtx.lineWidth = 2;
                                            oCtx.shadowColor = "#06B6D4";
                                            oCtx.shadowBlur = 8;
                                            oCtx.stroke();
                                            oCtx.shadowBlur = 0; // Reset shadow for text

                                            // Text Label for high confidence words
                                            if (word.confidence > 75) {
                                                const fontSize = 10;
                                                oCtx.font = `bold ${fontSize}px sans-serif`;
                                                const textWidth = oCtx.measureText(word.text).width;

                                                // Label Background
                                                oCtx.fillStyle = "rgba(6, 182, 212, 0.9)";
                                                oCtx.fillRect(x, y - fontSize - 6, textWidth + 8, fontSize + 4);

                                                // Text
                                                oCtx.fillStyle = "#FFFFFF";
                                                oCtx.fillText(word.text, x + 4, y - 6);
                                            }
                                        }
                                    });
                                }
                            }

                        } catch (e) {
                            // console.debug("OCR Frame Error", e);
                        }
                    }
                }
            }, 1000); // 1s interval

        } catch (err) {
            console.error("Error accessing camera or OCR:", err);
            alert("Could not access camera or initialize OCR.");
            setIsCameraOpen(false);
        }
    };

    if (isCameraOpen) {
        startCameraAndOCR();
    } else {
        if (ocrIntervalRef.current) clearInterval(ocrIntervalRef.current);
        if (workerRef.current) {
            workerRef.current.terminate();
            workerRef.current = null;
        }
        setOcrText('');
    }

    return () => {
        if (stream) {
            stream.getTracks().forEach(track => track.stop());
        }
        if (ocrIntervalRef.current) clearInterval(ocrIntervalRef.current);
        if (workerRef.current) workerRef.current.terminate();
    };
  }, [isCameraOpen, sourceLang]);

  const capturePhoto = () => {
      if (videoRef.current && canvasRef.current) {
          const video = videoRef.current;
          const canvas = canvasRef.current;

          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          const ctx = canvas.getContext('2d');
          if (ctx) {
              ctx.drawImage(video, 0, 0);
              const dataUrl = canvas.toDataURL('image/jpeg');
              const base64Data = dataUrl.split(',')[1];

              setAttachedFile({
                  name: `capture_${Date.now()}.jpg`,
                  mimeType: 'image/jpeg',
                  data: base64Data,
                  isBinary: true
              });
              setIsCameraOpen(false);
              setTargetText('');
          }
      }
  };

  const useScannedText = () => {
      if (ocrText) {
          setSourceText(ocrText);
          setIsCameraOpen(false);
      }
  };

  const handleProcess = async () => {
    if (!sourceText.trim() && !attachedFile) return;
    setIsLoading(true);
    let result = "";

    try {
        if (attachedFile) {
            result = await translateDocument(
                { data: attachedFile.data, mimeType: attachedFile.mimeType, isBinary: attachedFile.isBinary },
                sourceLang, targetLang, mode
            );
        } else {
            result = await translateText(sourceText, sourceLang, targetLang, mode);
        }
        setTargetText(result);
    } catch (e) {
        setTargetText("Error processing request. Please try again.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
      const file = event.target.files?.[0];
      if (file) {
          if (file.size > tierConfig.maxFileSizeMB * 1024 * 1024) {
              alert(`File too large for ${currentTier} tier.`);
              return;
          }
          const reader = new FileReader();
          reader.onload = (e) => {
              const content = e.target?.result as string;
              setAttachedFile({
                  name: file.name,
                  mimeType: file.type || 'text/plain',
                  data: file.type.startsWith('image/') || file.type.includes('pdf') ? content.split(',')[1] : content,
                  isBinary: file.type.startsWith('image/') || file.type.includes('pdf')
              });
              setTargetText('');
          };
          if (file.type.startsWith('image/') || file.type.includes('pdf')) reader.readAsDataURL(file);
          else reader.readAsText(file);
      }
  };

  const handleRemoveFile = () => { setAttachedFile(null); setTargetText(''); };
  const handleDownload = () => {
      if (!targetText) return;
      const element = document.createElement("a");
      const file = new Blob([targetText], {type: 'text/plain'});
      element.href = URL.createObjectURL(file);
      element.download = "translation.txt";
      document.body.appendChild(element); element.click(); document.body.removeChild(element);
  };
  const toggleListening = () => {
    if (isListening) { recognitionRef.current?.stop(); setIsListening(false); }
    else { recognitionRef.current?.start(); setIsListening(true); }
  };
  const handleSpeak = async () => {
      if (!targetText) return;
      setIsPlaying(true);
      await speakText(targetText);
      setIsPlaying(false);
  };
  const handleSwap = () => {
    if (sourceLang === 'auto') return;
    const oldSource = sourceLang; setSourceLang(targetLang); setTargetLang(oldSource);
    if (!attachedFile) { setSourceText(targetText); setTargetText(sourceText); }
  };
  const getButtonLabel = () => {
      if (attachedFile?.mimeType.startsWith('image/')) return 'Analyze Image';
      return mode === TranslationMode.TRANSLITERATE ? 'Transliterate Doc' : 'Translate Doc';
  };

  return (
    <div className="space-y-6">
      {/* Control Panel */}
      <div className="bg-gray-50 p-6 rounded-xl border border-gray-200 grid grid-cols-1 md:grid-cols-3 gap-6 shadow-sm">
        <div className="flex flex-col gap-2">
          <label className="text-sm font-semibold text-gray-900">Source Language (OCR)</label>
          <select 
            value={sourceLang}
            onChange={(e) => setSourceLang(e.target.value)}
            className="p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white text-gray-900"
          >
            {SUPPORTED_LANGUAGES.map(l => (
              <option key={`src-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>

        <div className="flex flex-col gap-2 justify-center items-center">
            <button onClick={handleSwap} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors">
                <i className="fas fa-exchange-alt"></i>
            </button>
        </div>

        <div className="flex flex-col gap-2">
          <label className="text-sm font-semibold text-gray-900">Target Language</label>
          <select 
            value={targetLang}
            onChange={(e) => setTargetLang(e.target.value)}
            className="p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-white text-gray-900"
          >
            {SUPPORTED_LANGUAGES.filter(l => l.code !== 'auto').map(l => (
              <option key={`tgt-${l.code}`} value={l.code}>{l.name}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Mode Toggle */}
      <div className="flex justify-center">
        <div className="bg-gray-200 p-1 rounded-full flex gap-1 relative">
             <button onClick={() => setMode(TranslationMode.TRANSLATE)} className={`px-6 py-2 rounded-full text-sm font-bold transition-all ${mode === TranslationMode.TRANSLATE ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600'}`}>Translate</button>
             <button onClick={() => setMode(TranslationMode.TRANSLITERATE)} className={`px-6 py-2 rounded-full text-sm font-bold transition-all ${mode === TranslationMode.TRANSLITERATE ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-600'}`}>Transliterate</button>
        </div>
      </div>

      {/* Text Areas */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative">

        {/* Camera Modal Overlay */}
        {isCameraOpen && (
            <div className="absolute inset-0 z-50 bg-black/95 rounded-2xl flex flex-col items-center justify-center p-4 animate-fade-in">
                <div className="relative w-full max-w-md aspect-[3/4] bg-black rounded-xl overflow-hidden border border-gray-700 shadow-2xl">
                    <video 
                        ref={videoRef} 
                        autoPlay 
                        playsInline 
                        muted
                        className="w-full h-full object-fill" 
                    />
                    <canvas ref={canvasRef} className="hidden" /> {/* Hidden canvas for extraction */}
                    <canvas ref={overlayRef} className="absolute inset-0 w-full h-full pointer-events-none" /> {/* Visible overlay for boxes */}

                    {/* OCR Text Preview Overlay */}
                    <div className="absolute bottom-4 left-4 right-4 bg-gray-900/80 backdrop-blur-md p-4 rounded-xl border border-gray-700">
                        {isOcrInitializing ? (
                            <div className="flex items-center gap-2 text-indigo-400">
                                <i className="fas fa-circle-notch fa-spin"></i>
                                <span className="text-sm font-medium">Initializing Neural OCR ({sourceLang})...</span>
                            </div>
                        ) : (
                            <div className="space-y-2">
                                <div className="flex justify-between items-center text-xs text-gray-400 uppercase tracking-wider font-bold">
                                    <span>Detected Text</span>
                                    {ocrConfidence > 0 && <span>Conf: {ocrConfidence.toFixed(0)}%</span>}
                                </div>
                                <p className="text-white text-sm font-mono min-h-[40px] max-h-[100px] overflow-y-auto">
                                    {ocrText || <span className="text-gray-600 italic">Scanning...</span>}
                                </p>
                                {ocrText && (
                                    <button 
                                        onClick={useScannedText}
                                        className="w-full bg-indigo-600 text-white py-2 rounded-lg text-sm font-bold hover:bg-indigo-500 transition-colors flex items-center justify-center gap-2"
                                    >
                                        <i className="fas fa-check"></i> Use This Text
                                    </button>
                                )}
                            </div>
                        )}
                    </div>
                </div>

                <div className="flex gap-4 mt-6">
                    <button 
                        onClick={() => setIsCameraOpen(false)}
                        className="px-6 py-3 rounded-full bg-gray-800 text-white font-bold hover:bg-gray-700 transition-colors border border-gray-700"
                    >
                        Cancel
                    </button>
                    <button 
                        onClick={capturePhoto}
                        className="px-6 py-3 rounded-full bg-white text-black font-bold hover:bg-gray-200 transition-colors flex items-center gap-2 shadow-lg shadow-white/20"
                    >
                        <i className="fas fa-camera"></i> Capture & Translate
                    </button>
                </div>
                <p className="text-gray-500 text-[10px] mt-4">
                    Multilingual Real-time OCR • Point camera at text
                </p>
            </div>
        )}

        {/* SOURCE AREA */}
        <div className="relative group h-full">
            <div className="flex justify-between mb-2">
                <span className="text-sm font-semibold text-gray-600">Source</span>
                <div className="flex gap-2">
                     <button onClick={() => setIsCameraOpen(true)} disabled={!!attachedFile} className={`text-xs flex items-center gap-1 font-bold transition-colors ${attachedFile ? 'opacity-30' : 'text-gray-500 hover:text-indigo-600'}`}>
                        <i className="fas fa-camera"></i> Camera
                    </button>
                     <label className={`cursor-pointer text-xs flex items-center gap-1 font-bold transition-colors ${attachedFile ? 'text-indigo-600' : 'text-gray-500 hover:text-indigo-600'}`}>
                        <input type="file" className="hidden" accept={tierConfig.allowedMimeTypes.join(',')} onChange={handleFileUpload} />
                        <i className="fas fa-paperclip"></i> {attachedFile ? ' Change' : ' Attach'}
                    </label>
                    <button onClick={toggleListening} disabled={!!attachedFile} className={`text-xs flex items-center gap-1 font-bold transition-colors ${isListening ? 'text-red-600 animate-pulse' : 'text-gray-500 hover:text-indigo-600'}`}>
                        <i className={`fas fa-microphone${isListening ? '' : '-slash'}`}></i> Voice
                    </button>
                </div>
            </div>

            <div className="relative w-full h-80">
                {attachedFile ? (
                    <div className="absolute inset-0 z-10 bg-indigo-50 border-2 border-indigo-200 border-dashed rounded-2xl flex flex-col items-center justify-center p-6 text-center animate-fade-in">
                        <div className="bg-white p-4 rounded-full shadow-sm mb-3 text-indigo-600 text-2xl"><i className={`fas ${attachedFile.mimeType.startsWith('image/') ? 'fa-image' : 'fa-file-alt'}`}></i></div>
                        <h4 className="font-bold text-gray-900 break-all max-w-full mb-1">{attachedFile.name}</h4>
                        {attachedFile.mimeType.startsWith('image/') && (
                             <div className="w-20 h-20 mb-4 rounded-lg overflow-hidden border border-gray-300 shadow-sm">
                                 <img src={`data:${attachedFile.mimeType};base64,${attachedFile.data}`} alt="Preview" className="w-full h-full object-cover" />
                             </div>
                        )}
                        <div className="flex gap-2">
                             <button onClick={handleProcess} disabled={isLoading} className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-indigo-700 shadow-sm">{isLoading ? <i className="fas fa-spinner fa-spin"></i> : getButtonLabel()}</button>
                             <button onClick={handleRemoveFile} className="bg-white text-red-500 border border-red-200 px-4 py-2 rounded-lg text-sm font-bold hover:bg-red-50">Remove</button>
                        </div>
                    </div>
                ) : (
                    <textarea value={sourceText} onChange={(e) => setSourceText(e.target.value)} placeholder="Enter text or use camera..." className="w-full h-full p-5 rounded-2xl border border-gray-300 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 outline-none resize-none shadow-inner text-lg bg-white text-gray-900"></textarea>
                )}
            </div>
        </div>

        {/* TARGET AREA */}
        <div className="relative group h-full">
            <div className="flex justify-between mb-2">
                <span className="text-sm font-semibold text-gray-600">Result</span>
                <div className="flex gap-3">
                     <button onClick={handleDownload} disabled={!targetText} className={`text-xs font-bold flex items-center gap-1 ${targetText ? 'text-indigo-600' : 'text-gray-300'}`}><i className="fas fa-download"></i> Download</button>
                     <button onClick={handleSpeak} disabled={!targetText} className={`text-xs font-bold flex items-center gap-1 ${isPlaying ? 'text-green-600' : 'text-gray-500 hover:text-indigo-600'}`}><i className={`fas fa-volume-${isPlaying ? 'up' : 'off'}`}></i> Listen</button>
                     <button onClick={() => navigator.clipboard.writeText(targetText)} className="text-xs text-indigo-600 hover:text-indigo-800 font-medium"><i className="fas fa-copy mr-1"></i> Copy</button>
                </div>
            </div>

            {/* Action Buttons for Chat Integration */}
            {targetText && (
                <div className="absolute bottom-5 right-5 z-20 flex gap-2">
                     <button 
                        onClick={() => onSendToChat(targetText, false)}
                        className="bg-white text-gray-700 border border-gray-300 shadow-lg px-3 py-1.5 rounded-lg text-xs font-bold hover:bg-gray-50 transition-all flex items-center gap-1"
                        title="Paste to Chat Input"
                    >
                        <i className="fas fa-comment-alt"></i> Edit in Chat
                    </button>
                    <button 
                        onClick={() => onSendToChat(targetText, true)}
                        className="bg-gradient-to-r from-indigo-500 to-purple-600 text-white shadow-lg px-3 py-1.5 rounded-lg text-xs font-bold hover:from-indigo-600 hover:to-purple-700 transition-all flex items-center gap-1"
                        title="Analyze using RAG"
                    >
                        <i className="fas fa-brain"></i> Analyze (RAG)
                    </button>
                </div>
            )}

            <textarea readOnly value={targetText} placeholder="Translation will appear here..." className="w-full h-80 p-5 rounded-2xl border border-gray-300 bg-white text-gray-900 resize-none shadow-sm focus:outline-none text-lg pb-14"></textarea>
        </div>
      </div>
    </div>
  );
};

