export const getEmbedding = async (text: string): Promise<number[]> => {
  // Use Direct REST API to avoid SDK "requests[]" error (which implies incorrect batch endpoint usage)
  try {
    return await withRetry(async () => {
        const url = `https://generativelanguage.googleapis.com/v1beta/models/${EMBEDDING_MODEL}:embedContent?key=${process.env.API_KEY}`;
        const response = await fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                model: `models/${EMBEDDING_MODEL}`,
                content: { parts: [{ text }] }
            })
        });

        if (!response.ok) {
             throw new Error(`Embedding failed: ${response.status}`);
        }

        const data = await response.json();
        return data.embedding?.values || [];
    });
  } catch (error) {
    console.error("Embedding Error:", error);
    return [];
  }
};

